async fn bind_chat_task_cancellation_sender(
    state: &AppState,
    task_id: &str,
    sender: tokio::sync::watch::Sender<bool>,
) {
    state
        .chat_task_cancellations
        .write()
        .await
        .insert(task_id.to_string(), sender);
}

async fn signal_chat_task_cancellation(state: &AppState, task_id: &str) {
    let sender = {
        state
            .chat_task_cancellations
            .read()
            .await
            .get(task_id)
            .cloned()
    };
    if let Some(sender) = sender {
        let _ = sender.send(true);
    }
}

async fn unregister_chat_task_cancellation(state: &AppState, task_id: &str) {
    state.chat_task_cancellations.write().await.remove(task_id);
}

/// Request a device code from OpenAI and start background polling for authorization.
async fn spawn_codex_oauth_probe() -> std::result::Result<(), String> {
    let runtime = codex_oauth_runtime();
    {
        let state = runtime.read().await;
        if state.active {
            return Ok(());
        }
    }

    // Step 1: Request user code from OpenAI
    let client = reqwest::Client::new();
    let resp = client
        .post(OPENAI_DEVICE_USERCODE_URL)
        .json(&serde_json::json!({ "client_id": OPENAI_DEVICE_AUTH_CLIENT_ID }))
        .send()
        .await
        .map_err(|e| format!("Failed to request device code: {}", e))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(format!(
            "OpenAI device code request failed ({}): {}",
            status, body
        ));
    }

    let body: serde_json::Value = resp
        .json()
        .await
        .map_err(|e| format!("Failed to parse device code response: {}", e))?;

    let device_auth_id = body
        .get("device_auth_id")
        .and_then(|v| v.as_str())
        .unwrap_or("")
        .to_string();
    let user_code = body
        .get("user_code")
        .or_else(|| body.get("usercode"))
        .and_then(|v| v.as_str())
        .unwrap_or("")
        .to_string();
    let interval: u64 = body
        .get("interval")
        .and_then(|v| {
            v.as_str()
                .and_then(|s| s.parse().ok())
                .or_else(|| v.as_u64())
        })
        .unwrap_or(5);

    if device_auth_id.is_empty() || user_code.is_empty() {
        return Err(format!(
            "OpenAI returned incomplete device code response: {}",
            body
        ));
    }

    {
        let mut state = runtime.write().await;
        state.active = true;
        state.auth_url = Some(OPENAI_DEVICE_VERIFY_URL.to_string());
        state.device_code = Some(user_code.clone());
        state.device_auth_id = Some(device_auth_id.clone());
        state.user_code = Some(user_code.clone());
        state.poll_interval_secs = interval;
        state.last_output = format!(
            "Open {} and enter code: {}",
            OPENAI_DEVICE_VERIFY_URL, user_code
        );
        state.last_error = None;
    }

    // Step 2: Background task polls for authorization completion
    let runtime_bg = runtime.clone();
    tokio::spawn(async move {
        let client = reqwest::Client::new();
        let max_attempts = (15 * 60) / interval.max(1); // 15 min timeout

        for _ in 0..max_attempts {
            tokio::time::sleep(std::time::Duration::from_secs(interval)).await;

            let poll_resp = client
                .post(OPENAI_DEVICE_TOKEN_URL)
                .json(&serde_json::json!({
                    "device_auth_id": device_auth_id,
                    "user_code": user_code,
                }))
                .send()
                .await;

            match poll_resp {
                Ok(resp) if resp.status().is_success() => {
                    // User authorized - extract auth code and exchange for tokens
                    if let Ok(poll_body) = resp.json::<serde_json::Value>().await {
                        let auth_code = poll_body
                            .get("authorization_code")
                            .and_then(|v| v.as_str())
                            .unwrap_or("");
                        let code_verifier = poll_body
                            .get("code_verifier")
                            .and_then(|v| v.as_str())
                            .unwrap_or("");

                        if !auth_code.is_empty() {
                            // Step 3: Exchange authorization code for tokens
                            let token_resp = client
                                .post(OPENAI_OAUTH_TOKEN_URL)
                                .form(&[
                                    ("grant_type", "authorization_code"),
                                    ("client_id", OPENAI_DEVICE_AUTH_CLIENT_ID),
                                    ("code", auth_code),
                                    ("code_verifier", code_verifier),
                                    ("redirect_uri", OPENAI_DEVICE_REDIRECT_URI),
                                ])
                                .send()
                                .await;

                            match token_resp {
                                Ok(tr) if tr.status().is_success() => {
                                    if let Ok(tokens) = tr.json::<serde_json::Value>().await {
                                        let access = tokens
                                            .get("access_token")
                                            .and_then(|v| v.as_str())
                                            .unwrap_or("");
                                        let refresh = tokens
                                            .get("refresh_token")
                                            .and_then(|v| v.as_str())
                                            .unwrap_or("");
                                        let expires_in = tokens
                                            .get("expires_in")
                                            .and_then(|v| v.as_u64())
                                            .unwrap_or(3600);
                                        let expires_ms = std::time::SystemTime::now()
                                            .duration_since(std::time::UNIX_EPOCH)
                                            .unwrap_or_default()
                                            .as_millis()
                                            as u64
                                            + (expires_in * 1000);

                                        if let Err(error) = persist_codex_cli_oauth_tokens(
                                            access, refresh, expires_ms,
                                        ) {
                                            let mut state = runtime_bg.write().await;
                                            state.active = false;
                                            state.last_error = Some(format!(
                                                "Failed to save OpenAI OAuth tokens: {}",
                                                error
                                            ));
                                            return;
                                        }

                                        let mut state = runtime_bg.write().await;
                                        state.active = false;
                                        state.last_output =
                                            "OpenAI OAuth connected successfully.".to_string();
                                        state.last_error = None;
                                        return;
                                    }
                                }
                                Ok(tr) => {
                                    let body = tr.text().await.unwrap_or_default();
                                    let mut state = runtime_bg.write().await;
                                    state.active = false;
                                    state.last_error =
                                        Some(format!("Token exchange failed: {}", body));
                                    return;
                                }
                                Err(e) => {
                                    let mut state = runtime_bg.write().await;
                                    state.active = false;
                                    state.last_error = Some(format!("Token exchange error: {}", e));
                                    return;
                                }
                            }
                        }
                    }
                }
                Ok(resp)
                    if resp.status() == reqwest::StatusCode::FORBIDDEN
                        || resp.status() == reqwest::StatusCode::NOT_FOUND =>
                {
                    // Still pending - continue polling
                    continue;
                }
                Ok(resp) => {
                    let status = resp.status();
                    let body = resp.text().await.unwrap_or_default();
                    let mut state = runtime_bg.write().await;
                    state.active = false;
                    state.last_error = Some(format!("Poll failed ({}): {}", status, body));
                    return;
                }
                Err(e) => {
                    let mut state = runtime_bg.write().await;
                    state.active = false;
                    state.last_error = Some(format!("Poll request error: {}", e));
                    return;
                }
            }
        }

        // Timeout
        let mut state = runtime_bg.write().await;
        state.active = false;
        state.last_error = Some("Device code expired (15 min timeout). Try again.".to_string());
    });

    Ok(())
}

async fn open_url_in_default_browser(url: &str) -> std::result::Result<(), String> {
    let status = if cfg!(target_os = "windows") {
        tokio::process::Command::new("cmd")
            .arg("/C")
            .arg("start")
            .arg("")
            .arg(url)
            .status()
            .await
            .map_err(|e| format!("Failed to launch browser: {}", e))?
    } else if cfg!(target_os = "macos") {
        tokio::process::Command::new("open")
            .arg(url)
            .status()
            .await
            .map_err(|e| format!("Failed to launch browser: {}", e))?
    } else {
        tokio::process::Command::new("xdg-open")
            .arg(url)
            .status()
            .await
            .map_err(|e| format!("Failed to launch browser: {}", e))?
    };

    if status.success() {
        Ok(())
    } else {
        Err(format!("Browser launcher exited with status {}", status))
    }
}

fn normalize_model_credential_base_url(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.trim_end_matches('/').to_string())
}

fn model_slot_credential_scope(slot: &ModelSlot) -> (String, Option<String>) {
    match &slot.provider {
        LlmProvider::Anthropic { .. } => ("anthropic".to_string(), None),
        LlmProvider::Ollama { base_url, .. } => (
            "ollama".to_string(),
            normalize_model_credential_base_url(Some(base_url.as_str())),
        ),
        LlmProvider::OpenAI { base_url, .. } => (
            openai_provider_label(base_url.as_deref()).to_string(),
            normalize_model_credential_base_url(
                display_openai_base_url(base_url.as_ref()).as_deref(),
            ),
        ),
    }
}

fn model_slot_request_credential_scope(
    request: &ModelSlotRequest,
) -> std::result::Result<(String, Option<String>), String> {
    if request.provider.trim().is_empty() {
        return Err("Provider is required".to_string());
    }
    let Some(provider_id) = canonical_provider_id(request.provider.as_str()) else {
        return Err(format!("Unknown provider: {}", request.provider));
    };
    let base_url = request.base_url.as_deref().and_then(|value| {
        let trimmed = value.trim();
        if trimmed.is_empty() {
            None
        } else {
            Some(trimmed.to_string())
        }
    });

    match provider_id {
        "anthropic" => Ok(("anthropic".to_string(), None)),
        "ollama" => {
            if base_url.is_none() {
                return Err("Ollama base URL is required".to_string());
            }
            Ok((
                "ollama".to_string(),
                normalize_model_credential_base_url(base_url.as_deref()),
            ))
        }
        "openai" | "openai-compatible" | "openrouter" | "openai-subscription" => {
            let compat_base_url = normalize_openai_base_url(provider_id, base_url)?;
            Ok((
                openai_provider_label(compat_base_url.as_deref()).to_string(),
                normalize_model_credential_base_url(
                    display_openai_base_url(compat_base_url.as_ref()).as_deref(),
                ),
            ))
        }
        _ => Ok((
            provider_id.to_string(),
            normalize_model_credential_base_url(base_url.as_deref()),
        )),
    }
}

fn can_reuse_model_slot_api_key(
    slot: &ModelSlot,
    request: &ModelSlotRequest,
) -> std::result::Result<bool, String> {
    if request.clear_api_key.unwrap_or(false) {
        return Ok(false);
    }
    Ok(model_slot_credential_scope(slot) == model_slot_request_credential_scope(request)?)
}

fn llm_provider_requires_api_key(provider_id: &str) -> bool {
    matches!(
        provider_id,
        "anthropic" | "openai" | "openrouter" | "openai-subscription"
    )
}

async fn provider_from_model_slot_request(
    request: &ModelSlotRequest,
    existing_api_key: Option<String>,
) -> std::result::Result<LlmProvider, String> {
    if request.provider.trim().is_empty() {
        return Err("Provider is required".to_string());
    }
    let Some(provider_id) = canonical_provider_id(request.provider.as_str()) else {
        return Err(format!("Unknown provider: {}", request.provider));
    };
    let base_url = request.base_url.clone().and_then(|u| {
        let trimmed = u.trim();
        if trimmed.is_empty() {
            None
        } else {
            Some(trimmed.to_string())
        }
    });
    let compat_base_url = normalize_openai_base_url(provider_id, base_url.clone())?;
    let mut api_key = request
        .api_key
        .clone()
        .filter(|k| !k.is_empty() && k != "[ENCRYPTED]")
        .or(existing_api_key.filter(|k| !k.is_empty() && k != "[ENCRYPTED]"))
        .unwrap_or_default();
    if provider_id == "openai-subscription" && api_key.is_empty() {
        let client = reqwest::Client::builder()
            .timeout(std::time::Duration::from_secs(10))
            .build()
            .map_err(|e| format!("Failed to build HTTP client: {}", e))?;
        api_key = resolve_codex_cli_api_key(&client, false)
            .await
            .map_err(|e| e.to_string())?
            .unwrap_or_default();
    }
    if provider_id == "ollama" && base_url.is_none() {
        return Err("Ollama base URL is required".to_string());
    }
    if provider_id == "openai-compatible" && compat_base_url.is_none() {
        return Err("Base URL is required for OpenAI-Compatible providers".to_string());
    }
    if llm_provider_requires_api_key(provider_id) && api_key.trim().is_empty() {
        return Err("API key is required for the selected provider".to_string());
    }

    let provider = match provider_id {
        "ollama" => LlmProvider::Ollama {
            base_url: base_url.unwrap_or_default(),
            model: request.model.clone(),
        },
        "anthropic" => LlmProvider::Anthropic {
            api_key: api_key.clone(),
            model: request.model.clone(),
        },
        "openai" => LlmProvider::OpenAI {
            api_key: api_key.clone(),
            model: request.model.clone(),
            base_url: None,
        },
        "openai-compatible" | "openrouter" => LlmProvider::OpenAI {
            api_key: api_key.clone(),
            model: request.model.clone(),
            base_url: compat_base_url,
        },
        "openai-subscription" => {
            if api_key.trim().is_empty() {
                return Err(
                    "OpenAI Subscription is not connected yet. Click 'Connect via Browser' and complete OAuth first.".to_string(),
                );
            }
            LlmProvider::OpenAI {
                api_key: api_key.clone(),
                model: request.model.clone(),
                base_url: compat_base_url,
            }
        }
        _ => {
            return Err(format!("Unknown provider: {}", provider_id));
        }
    };

    Ok(provider)
}

fn is_env_var_style_key(key: &str) -> bool {
    // Conservative: env vars are typically uppercase, digits, and underscores.
    !key.is_empty()
        && key.len() <= 128
        && key
            .chars()
            .all(|c| c.is_ascii_uppercase() || c.is_ascii_digit() || c == '_')
}

fn parse_set_secret_command(message: &str) -> Option<(String, String)> {
    crate::core::secrets::parse_set_secret_command(message)
}

fn normalize_origin(value: &str) -> Option<String> {
    let trimmed = value.trim().trim_end_matches('/');
    if trimmed.is_empty() {
        return None;
    }
    let uri: Uri = trimmed.parse().ok()?;
    let scheme = uri.scheme_str()?.to_ascii_lowercase();
    let authority = uri.authority()?.as_str().to_ascii_lowercase();
    Some(format!("{}://{}", scheme, authority))
}

fn is_local_origin(value: &str) -> bool {
    let normalized = match normalize_origin(value) {
        Some(v) => v,
        None => return false,
    };
    normalized.starts_with("http://localhost")
        || normalized.starts_with("https://localhost")
        || normalized.starts_with("http://127.0.0.1")
        || normalized.starts_with("https://127.0.0.1")
        || normalized.starts_with("http://[::1]")
        || normalized.starts_with("https://[::1]")
}

fn generate_ephemeral_token() -> String {
    use rand::RngCore;
    let mut bytes = [0u8; 32];
    rand::rngs::OsRng.fill_bytes(&mut bytes);
    base64::engine::Engine::encode(&base64::engine::general_purpose::URL_SAFE_NO_PAD, bytes)
}

fn parse_env_truthy(key: &str) -> Option<bool> {
    std::env::var(key).ok().and_then(|raw| {
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            None
        } else if trimmed.eq_ignore_ascii_case("true") || trimmed == "1" {
            Some(true)
        } else if trimmed.eq_ignore_ascii_case("false") || trimmed == "0" {
            Some(false)
        } else {
            None
        }
    })
}

fn normalize_optional_url(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.trim_end_matches('/').to_string())
}

fn deployment_mode_from_config(config: &crate::core::config::AgentConfig) -> DeploymentMode {
    if let Some(force_mode) = std::env::var("AGENTARK_DEPLOYMENT_MODE")
        .ok()
        .map(|value| value.trim().to_ascii_lowercase())
    {
        if force_mode == "internet_facing" || force_mode == "internet-facing" {
            return DeploymentMode::InternetFacing;
        }
        if force_mode == "trusted_local" || force_mode == "trusted-local" {
            return DeploymentMode::TrustedLocal;
        }
    }
    config.deployment_mode
}

fn public_app_bind_addr_from_config(
    config: &crate::core::config::AgentConfig,
    deployment_mode: DeploymentMode,
) -> Option<String> {
    normalize_optional_url(std::env::var("AGENTARK_PUBLIC_APP_BIND").ok().as_deref())
        .or_else(|| {
            config
                .public_apps
                .bind_addr
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(ToString::to_string)
        })
        .or_else(|| {
            if deployment_mode == DeploymentMode::InternetFacing {
                Some("127.0.0.1:8992".to_string())
            } else {
                None
            }
        })
}

fn public_app_base_url_from_config(config: &crate::core::config::AgentConfig) -> Option<String> {
    normalize_optional_url(
        std::env::var("AGENTARK_PUBLIC_APP_BASE_URL")
            .ok()
            .as_deref(),
    )
    .or_else(|| normalize_optional_url(config.public_apps.base_url.as_deref()))
}

fn default_base_url_for_bind_addr(bind_addr: &str) -> Option<String> {
    let trimmed = bind_addr.trim();
    if trimmed.is_empty() {
        return None;
    }
    let normalized = if trimmed.starts_with("0.0.0.0:") {
        format!("localhost:{}", trimmed.trim_start_matches("0.0.0.0:"))
    } else if trimmed == "0.0.0.0" {
        "localhost".to_string()
    } else if trimmed.starts_with("[::]:") {
        format!("localhost:{}", trimmed.trim_start_matches("[::]:"))
    } else if trimmed == "[::]" || trimmed == "::" {
        "localhost".to_string()
    } else if trimmed.starts_with("127.0.0.1:") || trimmed == "127.0.0.1" {
        trimmed.replacen("127.0.0.1", "localhost", 1)
    } else {
        trimmed.to_string()
    };
    Some(format!("http://{}", normalized.trim_end_matches('/')))
}

fn bind_addr_host(bind_addr: &str) -> Option<String> {
    let trimmed = bind_addr.trim();
    if trimmed.is_empty() {
        return None;
    }
    let candidate = if trimmed.contains("://") {
        trimmed.to_string()
    } else {
        format!("http://{}", trimmed)
    };
    reqwest::Url::parse(&candidate)
        .ok()?
        .host_str()
        .map(|value| value.trim().to_ascii_lowercase())
}

fn bind_addr_is_loopback(bind_addr: &str) -> bool {
    bind_addr_host(bind_addr)
        .as_deref()
        .is_some_and(|host| matches!(host, "localhost" | "127.0.0.1" | "::1"))
}

fn should_warn_for_direct_control_plane_exposure(
    deployment_mode: DeploymentMode,
    bind_addr: &str,
) -> bool {
    deployment_mode == DeploymentMode::InternetFacing && !bind_addr_is_loopback(bind_addr)
}

fn validate_public_app_listener_posture(
    deployment_mode: DeploymentMode,
    public_app_bind_addr: Option<&str>,
    configured_public_app_base_url: Option<&str>,
    direct_tls_enabled: bool,
) -> Result<()> {
    if !internet_facing_apps_should_be_isolated(deployment_mode, public_app_bind_addr) {
        return Ok(());
    }

    let bind_addr = public_app_bind_addr
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| anyhow::anyhow!("Internet-facing public apps require a bind address"))?;
    let base_url = configured_public_app_base_url
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            anyhow::anyhow!(
                "Internet-facing public apps require AGENTARK_PUBLIC_APP_BASE_URL or [public_apps].base_url to be set to the external HTTPS origin"
            )
        })?;
    let parsed_base_url = reqwest::Url::parse(base_url).map_err(|error| {
        anyhow::anyhow!("Public app base URL '{}' is invalid: {}", base_url, error)
    })?;
    if !parsed_base_url.scheme().eq_ignore_ascii_case("https") {
        anyhow::bail!("Internet-facing public app base URL must use HTTPS");
    }

    if !bind_addr_is_loopback(bind_addr) {
        if !direct_tls_enabled {
            anyhow::bail!(
                "Internet-facing public app listener '{}' is non-loopback but TLS is not configured. Either bind public apps to loopback behind an HTTPS reverse proxy, or configure tls_cert_path/tls_key_path for direct HTTPS.",
                bind_addr
            );
        }
        bind_addr.parse::<SocketAddr>().map_err(|error| {
            anyhow::anyhow!(
                "Direct HTTPS public app listener '{}' must be a concrete socket address: {}",
                bind_addr,
                error
            )
        })?;
    }

    Ok(())
}

fn internet_facing_apps_should_be_isolated(
    deployment_mode: DeploymentMode,
    public_app_bind_addr: Option<&str>,
) -> bool {
    deployment_mode == DeploymentMode::InternetFacing
        && public_app_bind_addr
            .map(|value| !value.trim().is_empty())
            .unwrap_or(false)
}

fn escape_html(text: &str) -> String {
    text.replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&#x27;")
}

fn parse_autonomy_quick_command(message: &str) -> Option<AutonomyQuickCommand> {
    let trimmed = message.trim();
    let command = trimmed.strip_prefix('/')?;
    let normalized = command.to_ascii_lowercase().replace(['_', '-'], " ");
    let normalized = normalized.split_whitespace().collect::<Vec<_>>().join(" ");
    if normalized == "triage" {
        return Some(AutonomyQuickCommand::TriageInbox);
    }
    if let Some(task) = command.strip_prefix("delegate ") {
        let task = task.trim();
        if task.is_empty() {
            return None;
        }
        return Some(AutonomyQuickCommand::Delegate {
            task: task.to_string(),
            require_approval: false,
        });
    }
    if let Some(rest) = command.strip_prefix("rollback ") {
        let rest = rest.trim();
        if rest.is_empty() {
            return None;
        }
        let mut parts = rest.split_whitespace();
        let event_id = parts.next().unwrap_or("").trim();
        if event_id.is_empty() {
            return None;
        }
        let operation = if let Some(raw) = parts.next() {
            let op = raw.trim().to_ascii_lowercase();
            if op == "mark" {
                parts.next().map(|next| {
                    let next = next.trim().to_ascii_lowercase();
                    match next.as_str() {
                        "read" => "mark_read".to_string(),
                        "unread" => "mark_unread".to_string(),
                        other => format!("mark {}", other),
                    }
                })
            } else {
                Some(match op.as_str() {
                    "read" => "mark_read".to_string(),
                    "unread" => "mark_unread".to_string(),
                    _ => op,
                })
            }
        } else {
            None
        };
        return Some(AutonomyQuickCommand::Rollback {
            event_id: event_id.to_string(),
            operation,
        });
    }
    None
}

fn parse_notification_control_command(message: &str) -> Option<NotificationControlCommand> {
    let command = message.trim().strip_prefix('/')?;
    match command
        .to_ascii_lowercase()
        .replace(['_', '-'], " ")
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .as_str()
    {
        "notifications pause" => Some(NotificationControlCommand::Pause24h),
        "notifications resume" => Some(NotificationControlCommand::Resume),
        "notifications status" => Some(NotificationControlCommand::Status),
        _ => None,
    }
}

async fn handle_notification_control_command(
    state: &AppState,
    cmd: NotificationControlCommand,
) -> std::result::Result<String, String> {
    let agent = state.agent.read().await;
    match cmd {
        NotificationControlCommand::Pause24h => {
            let until_ts = agent
                .pause_push_notifications_for_hours(24)
                .await
                .map_err(|e| format!("Failed to pause notifications: {}", e))?;
            let until = chrono::DateTime::<chrono::Utc>::from_timestamp(until_ts, 0)
                .unwrap_or_else(chrono::Utc::now);
            Ok(format!(
                "Push notifications paused until {}. Use `/notifications resume` anytime to re-enable.",
                until.format("%Y-%m-%d %H:%M:%S UTC")
            ))
        }
        NotificationControlCommand::Resume => {
            agent
                .resume_push_notifications()
                .await
                .map_err(|e| format!("Failed to resume notifications: {}", e))?;
            Ok("Push notifications resumed.".to_string())
        }
        NotificationControlCommand::Status => {
            if let Some(until_ts) = agent.push_notifications_muted_until_ts().await {
                let until = chrono::DateTime::<chrono::Utc>::from_timestamp(until_ts, 0)
                    .unwrap_or_else(chrono::Utc::now);
                Ok(format!(
                    "Push notifications are currently paused until {}.",
                    until.format("%Y-%m-%d %H:%M:%S UTC")
                ))
            } else {
                Ok("Push notifications are active.".to_string())
            }
        }
    }
}

async fn server_load_reasons(state: &AppState) -> Vec<String> {
    let now = chrono::Utc::now();
    let mut reasons = {
        let tasks = state.tasks.read().await;
        tasks
            .all()
            .iter()
            .filter(|task| matches!(task.status, TaskStatus::InProgress))
            .filter_map(|task| {
                let age_secs = (now - task.created_at).num_seconds().max(0);
                if age_secs > SERVER_BUSY_TASK_WINDOW_SECS {
                    None
                } else {
                    Some(format!(
                        "task '{}' in progress ({}s)",
                        task.action, age_secs
                    ))
                }
            })
            .take(3)
            .collect::<Vec<_>>()
    };

    let active_trace_reason = {
        let last_trace = state.last_trace.read().await;
        last_trace
            .started_at
            .filter(|_| last_trace.completed_at.is_none())
            .and_then(|started_at| {
                let age_secs = (now - started_at).num_seconds().max(0);
                if age_secs > SERVER_BUSY_TRACE_WINDOW_SECS {
                    None
                } else {
                    Some(format!("active trace ({}s)", age_secs))
                }
            })
    };
    if let Some(reason) = active_trace_reason {
        reasons.push(reason);
    }

    reasons
}

async fn server_under_load(state: &AppState) -> bool {
    !server_load_reasons(state).await.is_empty()
}

async fn handle_autonomy_quick_command(
    state: &AppState,
    cmd: AutonomyQuickCommand,
) -> std::result::Result<String, String> {
    match cmd {
        AutonomyQuickCommand::TriageInbox => {
            let labels = vec![
                "Act now".to_string(),
                "Delegate".to_string(),
                "Ignore".to_string(),
            ];
            let agent = state.agent.read().await;
            let fallback = agent
                .storage
                .list_notifications(30, 0, true)
                .await
                .unwrap_or_default();
            let messages: Vec<serde_json::Value> = fallback
                .into_iter()
                .map(|n| {
                    serde_json::json!({
                        "id": n.id,
                        "from": n.source,
                        "subject": n.title,
                        "snippet": n.body,
                    })
                })
                .collect();
            if messages.is_empty() {
                return Ok(
                    "No inbox items found to triage. Unread notifications are already clear."
                        .to_string(),
                );
            }

            let payload = serde_json::json!({ "messages": messages, "labels": labels });
            let llm_response = agent
                .llm
                .chat(
                    "You are an executive inbox triage assistant. Return strict JSON {\"triage\":[{\"message_id\":\"...\",\"label\":\"...\",\"reason\":\"...\",\"draft_reply\":\"...\"}]}.",
                    &payload.to_string(),
                    &[],
                    &[],
                )
                .await
                .ok();
            if let Some(ref r) = llm_response {
                agent.record_llm_usage("web", "inbox_triage", r).await;
            }

            let parsed = llm_response
                .as_ref()
                .and_then(|r| extract_json(&r.content))
                .unwrap_or_else(|| {
                    let triage: Vec<serde_json::Value> = payload
                        .get("messages")
                        .and_then(|v| v.as_array())
                        .cloned()
                        .unwrap_or_default()
                        .iter()
                        .map(|m| {
                            let label = "Review";
                            serde_json::json!({
                                "message_id": m.get("id").cloned().unwrap_or(serde_json::json!("")),
                                "label": label,
                                "reason": "LLM triage unavailable; conservative fallback",
                                "draft_reply": "",
                            })
                        })
                        .collect();
                    serde_json::json!({ "triage": triage })
                });

            let rows = parsed
                .get("triage")
                .and_then(|v| v.as_array())
                .cloned()
                .unwrap_or_default();
            if rows.is_empty() {
                return Ok("Inbox triage complete. No items were classified.".to_string());
            }
            let mut out = format!("Inbox triage complete: {} item(s).\n", rows.len());
            for row in rows.iter().take(10) {
                let id = row
                    .get("message_id")
                    .and_then(|v| v.as_str())
                    .map(|s| s.to_string())
                    .unwrap_or_else(|| {
                        row.get("message_id")
                            .map(|v| v.to_string())
                            .unwrap_or("-".to_string())
                    });
                let label = row.get("label").and_then(|v| v.as_str()).unwrap_or("-");
                let reason = row.get("reason").and_then(|v| v.as_str()).unwrap_or("-");
                out.push_str(&format!("- [{}] {}: {}\n", label, id, reason));
            }
            if rows.len() > 10 {
                out.push_str(&format!("... and {} more.\n", rows.len() - 10));
            }
            out.push_str("Tip: use /delegate <task> for anything labeled Delegate.");
            Ok(out)
        }
        AutonomyQuickCommand::Delegate {
            task,
            require_approval,
        } => {
            if task.trim().is_empty() {
                return Err("Task is required. Usage: /delegate <task description>".to_string());
            }
            let agent = state.agent.read().await;
            let settings = load_autonomy_settings(&agent).await;
            let trust = score_action_risk(
                "delegate",
                &serde_json::json!({"task": task}),
                &settings.trust_policy,
            );

            if trust.requires_approval || require_approval {
                let mut approval_task = Task::new(
                    format!("Delegation approval: {}", task),
                    "delegate".to_string(),
                    serde_json::json!({
                        "task": task,
                        "context": "",
                        "_approval": {
                            "title": format!("Delegate: {}", task),
                            "summary": "This delegation will spawn specialist/background work on your behalf.",
                            "reason": trust.reasons.join("; "),
                            "rule_name": "elevated_action_requires_explicit_approval",
                            "risk_level": risk_level_label(&trust.level),
                            "risk_score": trust.score,
                            "source": "autonomy_quick_command"
                        }
                    }),
                );
                approval_task.status = TaskStatus::AwaitingApproval;
                approval_task.approval = TaskApproval::RequireApproval;
                let queued = agent
                    .add_or_update_similar_task(approval_task, false, None)
                    .await;
                if let Err(e) = queued {
                    return Err(format!("Failed to queue delegation approval: {}", e));
                }
                return Ok(format!(
                    "Delegation queued for approval (risk: {} / score {}).",
                    risk_level_label(&trust.level),
                    trust.score
                ));
            }

            let actions = agent.runtime.list_actions().await.unwrap_or_default();
            let active_prompt_bundle = agent.active_prompt_bundle_for_message(&task).await;
            let active_specialist_prompt_bundle = agent
                .active_specialist_prompt_bundle_for_message(&task)
                .await;
            let mut decision = agent
                .route_query(&task, &actions, &active_prompt_bundle)
                .await;
            decision.needs_delegation = true;
            if decision.sub_agents.len() < 2 {
                decision.sub_agents = agent.forced_swarm_specs(&task, &actions);
            }
            decision.confidence = decision.confidence.max(0.96);
            decision.reasoning = format!(
                "{} | Explicit /delegate command forced multi-agent execution.",
                decision.reasoning
            );
            let system_prompt = match agent
                .build_system_prompt(&[], Some(&active_prompt_bundle))
                .await
            {
                Ok(prompt) => prompt,
                Err(error) => {
                    return Err(format!("Failed to build delegation prompt: {}", error));
                }
            };
            let delegation_id = uuid::Uuid::new_v4().to_string();
            let empty_memories: Vec<crate::memory::MemoryEntry> = Vec::new();
            let specialists = agent
                .swarm
                .as_ref()
                .map(|manager| manager.specialists.clone());
            let action_scope_hints = agent
                .runtime
                .list_action_scope_hints()
                .await
                .unwrap_or_default();
            let trace = Arc::new(RwLock::new(crate::core::ExecutionTrace {
                id: uuid::Uuid::new_v4().to_string(),
                message: task.clone(),
                channel: "http".to_string(),
                started_at: Some(chrono::Utc::now()),
                ..Default::default()
            }));
            match agent
                .task_router
                .execute(
                    &decision,
                    crate::core::task_router::TaskRouterExecuteContext {
                        delegation_id: &delegation_id,
                        conversation_id: None,
                        channel: Some("http"),
                        message: &task,
                        system_prompt: &system_prompt,
                        prompt_bundle: &active_prompt_bundle,
                        specialist_prompt_bundle: &active_specialist_prompt_bundle,
                        model_pool: &agent.model_pool,
                        primary_llm: &agent.llm,
                        specialists: &specialists,
                        memories: &empty_memories,
                        actions: &actions,
                        action_scope_hints: &action_scope_hints,
                        trace: &trace,
                        token_tx: None,
                        swarm_activity: Some(&agent.swarm_activity),
                        storage: Some(&agent.storage),
                    },
                )
                .await
            {
                Ok(crate::core::task_router::TaskRouterResult::Delegated(result)) => {
                    let final_result = crate::security::redact_pii(&result.final_response.content);
                    Ok(format!(
                        "Delegation complete.\nAgents used: {}\nStatus: {}\nResult:\n{}",
                        if result.agent_results.is_empty() {
                            "-".to_string()
                        } else {
                            result
                                .agent_results
                                .iter()
                                .map(|item| {
                                    item.agent_name
                                        .clone()
                                        .unwrap_or_else(|| item.agent_type.clone())
                                })
                                .collect::<Vec<_>>()
                                .join(", ")
                        },
                        result.delegation_status.as_str(),
                        final_result
                    ))
                }
                Ok(crate::core::task_router::TaskRouterResult::Direct) => {
                    Err("Delegation unexpectedly routed to a direct path.".to_string())
                }
                Err(e) => Err(format!("Delegation failed: {}", e)),
            }
        }
        AutonomyQuickCommand::Rollback {
            event_id,
            operation,
        } => {
            let agent = state.agent.read().await;
            let event_id_trimmed = event_id.trim();
            let operation = operation.unwrap_or_default();

            if let Some(task_id) = event_id_trimmed.strip_prefix("task:") {
                let uuid = uuid::Uuid::parse_str(task_id)
                    .map_err(|_| "Invalid task id. Expected format: task:<uuid>".to_string())?;
                let mut tasks = agent.tasks.write().await;
                let Some(task) = tasks.get_mut(uuid) else {
                    return Err("Task not found.".to_string());
                };
                if !matches!(
                    task.status,
                    TaskStatus::Pending | TaskStatus::AwaitingApproval | TaskStatus::InProgress
                ) {
                    return Err("Task cannot be cancelled from its current state.".to_string());
                }
                task.status = TaskStatus::Cancelled;
                let status_json =
                    serde_json::to_string(&task.status).unwrap_or("\"Cancelled\"".to_string());
                let _ = agent
                    .storage
                    .update_task_status(task_id, &status_json)
                    .await;
                return Ok("Rollback applied: task cancelled.".to_string());
            }

            if let Some(watcher_id) = event_id_trimmed.strip_prefix("watcher:") {
                let uuid = uuid::Uuid::parse_str(watcher_id).map_err(|_| {
                    "Invalid watcher id. Expected format: watcher:<uuid>".to_string()
                })?;
                if agent.watcher_manager.cancel(uuid).await {
                    if let Some(watcher) = agent.watcher_manager.get(uuid).await {
                        agent
                            .sync_watcher_supervisor_state(&watcher, Some("cancelled"), None)
                            .await;
                    }
                    return Ok("Rollback applied: watcher cancelled.".to_string());
                }
                return Err("Watcher not found or not cancellable.".to_string());
            }

            if let Some(notification_id) = event_id_trimmed.strip_prefix("notification:") {
                let read = operation != "mark_unread";
                agent
                    .storage
                    .set_notification_read(notification_id, read)
                    .await
                    .map_err(|e| format!("Failed to update notification: {}", e))?;
                return Ok(if read {
                    "Rollback applied: notification marked as read.".to_string()
                } else {
                    "Rollback applied: notification marked as unread.".to_string()
                });
            }

            Err("Unsupported rollback target. Use task:<uuid>, watcher:<uuid>, or notification:<id>.".to_string())
        }
    }
}

