/// Serve output files from code execution (images, CSVs, code files, etc.)
async fn serve_output_file(
    State(state): State<AppState>,
    Path((exec_id, filename)): Path<(String, String)>,
) -> Response {
    // Validate exec_id is a UUID to prevent path traversal
    if uuid::Uuid::parse_str(&exec_id).is_err() {
        return StatusCode::BAD_REQUEST.into_response();
    }
    // Validate filename has no path separators
    if filename.contains('/') || filename.contains('\\') || filename.contains("..") {
        return StatusCode::BAD_REQUEST.into_response();
    }

    // Resolve data directory from agent config
    let data_dir = {
        let agent = state.agent.read().await;
        agent.data_dir().to_path_buf()
    };
    let file_path = data_dir.join("outputs").join(&exec_id).join(&filename);
    let bytes = match tokio::fs::read(&file_path).await {
        Ok(bytes) => Some(bytes),
        Err(_) => {
            if let Some(workspace) = state.workspace_client.as_ref() {
                workspace
                    .get_blob(&format!("outputs/{}/{}", exec_id, filename))
                    .await
                    .ok()
            } else {
                None
            }
        }
    };

    match bytes {
        Some(bytes) => {
            let content_type = guess_content_type(&filename);
            let safe_filename = sanitize_content_disposition_filename(&filename);
            (
                [
                    (header::CONTENT_TYPE, content_type.as_str()),
                    (
                        header::CONTENT_DISPOSITION,
                        &format!("inline; filename=\"{}\"", safe_filename),
                    ),
                    (header::CACHE_CONTROL, "public, max-age=86400"),
                ],
                bytes,
            )
                .into_response()
        }
        None => StatusCode::NOT_FOUND.into_response(),
    }
}

/// Serve output file as a download (Content-Disposition: attachment)
async fn download_output_file(
    State(state): State<AppState>,
    Path((exec_id, filename)): Path<(String, String)>,
) -> Response {
    if uuid::Uuid::parse_str(&exec_id).is_err() {
        return StatusCode::BAD_REQUEST.into_response();
    }
    if filename.contains('/') || filename.contains('\\') || filename.contains("..") {
        return StatusCode::BAD_REQUEST.into_response();
    }

    let data_dir = {
        let agent = state.agent.read().await;
        agent.data_dir().to_path_buf()
    };
    let file_path = data_dir.join("outputs").join(&exec_id).join(&filename);
    let bytes = match tokio::fs::read(&file_path).await {
        Ok(bytes) => Some(bytes),
        Err(_) => {
            if let Some(workspace) = state.workspace_client.as_ref() {
                workspace
                    .get_blob(&format!("outputs/{}/{}", exec_id, filename))
                    .await
                    .ok()
            } else {
                None
            }
        }
    };

    match bytes {
        Some(bytes) => {
            let content_type = guess_content_type(&filename);
            let safe_filename = sanitize_content_disposition_filename(&filename);
            (
                [
                    (header::CONTENT_TYPE, content_type.as_str()),
                    (
                        header::CONTENT_DISPOSITION,
                        &format!("attachment; filename=\"{}\"", safe_filename),
                    ),
                    (header::CACHE_CONTROL, "public, max-age=86400"),
                ],
                bytes,
            )
                .into_response()
        }
        None => StatusCode::NOT_FOUND.into_response(),
    }
}

/// Guess MIME content type from filename extension.
/// Falls back to octet-stream for unknown types.
fn guess_content_type(filename: &str) -> String {
    let ext = filename.rsplit('.').next().unwrap_or("").to_lowercase();
    match ext.as_str() {
        // Images
        "png" => "image/png",
        "jpg" | "jpeg" => "image/jpeg",
        "gif" => "image/gif",
        "svg" => "image/svg+xml",
        "webp" => "image/webp",
        "bmp" => "image/bmp",
        "ico" => "image/x-icon",
        // Documents
        "pdf" => "application/pdf",
        "html" | "htm" => "text/html",
        "xml" => "application/xml",
        // Data
        "json" | "ipynb" => "application/json",
        "csv" => "text/csv",
        "tsv" => "text/tab-separated-values",
        "yaml" | "yml" => "text/yaml",
        "toml" => "text/toml",
        // Code (all served as plain text for viewing)
        "txt" | "log" | "md" | "rst" => "text/plain",
        "py" | "js" | "ts" | "java" | "c" | "cpp" | "h" | "hpp" | "rs" | "go" | "rb" | "php"
        | "pl" | "lua" | "r" | "sh" | "bash" | "zsh" | "fish" | "kt" | "swift" | "sql" | "css"
        | "scss" | "less" => "text/plain; charset=utf-8",
        // Archives
        "zip" => "application/zip",
        "gz" | "tgz" => "application/gzip",
        "tar" => "application/x-tar",
        // Audio/Video
        "mp3" => "audio/mpeg",
        "wav" => "audio/wav",
        "mp4" => "video/mp4",
        "webm" => "video/webm",
        // Office
        "xlsx" | "xls" => "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        "docx" | "doc" => "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        "pptx" | "ppt" => {
            "application/vnd.openxmlformats-officedocument.presentationml.presentation"
        }
        // Fallback
        _ => "application/octet-stream",
    }
    .to_string()
}

// ==================== Deployed Apps ====================

fn merge_executor_status_fields(
    row: &mut serde_json::Map<String, serde_json::Value>,
    status: &crate::clients::AppStatusResponse,
) {
    row.insert("running".to_string(), serde_json::json!(status.running));
    row.insert(
        "runtime_mode".to_string(),
        serde_json::Value::String(
            status
                .runtime_mode
                .clone()
                .unwrap_or_else(|| "stopped".to_string()),
        ),
    );
    row.insert(
        "is_isolated_runtime".to_string(),
        serde_json::json!(status.is_isolated_runtime),
    );
    row.insert(
        "port".to_string(),
        status
            .port
            .map(serde_json::Value::from)
            .unwrap_or(serde_json::Value::Null),
    );
}

fn executor_websocket_base_url(base_url: &str) -> String {
    if let Some(stripped) = base_url.strip_prefix("https://") {
        format!("wss://{}", stripped.trim_end_matches('/'))
    } else if let Some(stripped) = base_url.strip_prefix("http://") {
        format!("ws://{}", stripped.trim_end_matches('/'))
    } else {
        format!("ws://{}", base_url.trim_end_matches('/'))
    }
}

/// List all deployed apps
async fn list_apps(State(state): State<AppState>) -> Json<serde_json::Value> {
    let mut apps = Vec::new();
    for mut row in state.app_registry.list().await {
        let Some(obj) = row.as_object_mut() else {
            apps.push(row);
            continue;
        };
        let Some(app_id) = obj
            .get("id")
            .and_then(|value| value.as_str())
            .map(|s| s.to_string())
        else {
            apps.push(row);
            continue;
        };
        let access_guard_enabled = obj
            .get("access_guard_enabled")
            .and_then(|value| value.as_bool())
            .unwrap_or(false);
        obj.insert(
            "url".to_string(),
            serde_json::Value::String(app_root_url_for_state(&state, &app_id)),
        );
        obj.insert(
            "access_url".to_string(),
            serde_json::Value::String(
                app_access_url_for_state(&state, &app_id, access_guard_enabled).await,
            ),
        );
        if !obj
            .get("is_static")
            .and_then(|value| value.as_bool())
            .unwrap_or(true)
        {
            if let Some(executor) = state.executor_client.as_ref() {
                if let Ok(status) = executor.app_status(&app_id).await {
                    merge_executor_status_fields(obj, &status);
                }
            }
        }
        apps.push(row);
    }
    let restore = state.app_registry.restore_snapshot().await;
    Json(serde_json::json!({ "apps": apps, "restore": restore }))
}

fn is_valid_app_id(app_id: &str) -> bool {
    !app_id.is_empty()
        && app_id.len() <= 64
        && app_id
            .chars()
            .all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_')
}

fn is_secure_origin_request(headers: &axum::http::HeaderMap) -> bool {
    if headers
        .get("x-forwarded-proto")
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.eq_ignore_ascii_case("https"))
    {
        return true;
    }
    let host = headers
        .get(header::HOST)
        .and_then(|v| v.to_str().ok())
        .unwrap_or("")
        .to_ascii_lowercase();
    host.ends_with(".trycloudflare.com") || host.ends_with(".cfargotunnel.com")
}

fn should_upgrade_insecure_links(content_type: &str) -> bool {
    let ct = content_type.to_ascii_lowercase();
    ct.starts_with("text/html")
        || ct.starts_with("application/javascript")
        || ct.starts_with("text/javascript")
        || ct.starts_with("text/css")
}

fn rewrite_external_proxy_urls_for_public_apps(content: &str) -> String {
    const ARXIV_EXPORT_PLACEHOLDER: &str = "__AGENTARK_ARXIV_EXPORT_API__";
    const ARXIV_ROOT_PLACEHOLDER: &str = "__AGENTARK_ARXIV_ROOT_API__";

    let mut rewritten = content
        // Redirect direct ArXiv API calls through our same-origin public proxy
        // to avoid browser CORS failures on tunneled/public app URLs.
        .replace(
            "http://export.arxiv.org/api/query",
            ARXIV_EXPORT_PLACEHOLDER,
        )
        .replace(
            "https://export.arxiv.org/api/query",
            ARXIV_EXPORT_PLACEHOLDER,
        )
        .replace("http://arxiv.org/api/query", ARXIV_ROOT_PLACEHOLDER)
        .replace("https://arxiv.org/api/query", ARXIV_ROOT_PLACEHOLDER)
        .replace(
            "https://api.allorigins.win/raw?url=",
            "/public/proxy/raw?url=",
        )
        .replace("https://corsproxy.io/?", "/public/proxy/raw?url=")
        .replace(
            "https://api.codetabs.com/v1/proxy/?quest=",
            "/public/proxy/raw?url=",
        )
        .replace(
            ARXIV_EXPORT_PLACEHOLDER,
            "/public/proxy/raw?url=https://export.arxiv.org/api/query",
        )
        .replace(
            ARXIV_ROOT_PLACEHOLDER,
            "/public/proxy/raw?url=https://arxiv.org/api/query",
        );

    while rewritten.contains("/public/proxy/raw?url=/public/proxy/raw?url=") {
        rewritten = rewritten.replace(
            "/public/proxy/raw?url=/public/proxy/raw?url=",
            "/public/proxy/raw?url=",
        );
    }

    rewritten
}

fn inject_app_runtime_fetch_shims(content: &str, app_id: &str) -> String {
    if content.contains("__agentarkLlmProxyShimApplied") {
        return content.to_string();
    }
    let shim = format!(
        r#"<script>
(function() {{
  if (window.__agentarkLlmProxyShimApplied) return;
  window.__agentarkLlmProxyShimApplied = true;
  const APP_ID = "{app_id}";
  const PROXY_PATH = "/apps/" + encodeURIComponent(APP_ID) + "/__agentark/llm/chat";
  const ARXIV_PROXY_PATH = "/apps/" + encodeURIComponent(APP_ID) + "/__agentark/arxiv/search";

  const nativeFetch = window.fetch ? window.fetch.bind(window) : null;
  if (nativeFetch) {{
    const extractUrl = (input) => {{
      try {{
        if (typeof input === "string") return input;
        if (input && typeof input.url === "string") return input.url;
        if (input instanceof URL) return input.toString();
      }} catch (_) {{}}
      return "";
    }};
    const shouldProxy = (url) => {{
      const lower = String(url || "").toLowerCase();
      return (
        lower.includes("openrouter.ai/api/v1/chat/completions") ||
        lower.includes("openrouter.ai/api/v1/responses") ||
        lower.includes("openrouter.ai/api/v1/completions") ||
        lower.includes("api.openai.com/v1/chat/completions") ||
        lower.includes("api.openai.com/v1/responses") ||
        lower.includes("api.openai.com/v1/completions") ||
        lower.endsWith("/v1/chat/completions") ||
        lower.endsWith("/v1/responses") ||
        lower.endsWith("/v1/completions")
      );
    }};
    const shouldProxyArxiv = (url) => {{
      const lower = String(url || "").toLowerCase();
      return (
        !lower.includes("/__agentark/arxiv/search") &&
        (
          lower.includes("export.arxiv.org/api/query") ||
          lower.includes("arxiv.org/api/query") ||
          lower.includes("/public/proxy/raw?url=https://export.arxiv.org/api/query") ||
          lower.includes("/public/proxy/raw?url=http://export.arxiv.org/api/query") ||
          lower.includes("/public/proxy/raw?url=https://arxiv.org/api/query") ||
          lower.includes("/public/proxy/raw?url=http://arxiv.org/api/query") ||
          lower.includes("/public/proxy/raw?url=/public/proxy/raw?url=https://export.arxiv.org/api/query") ||
          lower.includes("/public/proxy/raw?url=/public/proxy/raw?url=https://arxiv.org/api/query")
        )
      );
    }};
    window.fetch = function(input, init) {{
      const targetUrl = extractUrl(input);
      const baseInit = Object.assign({{}}, init || {{}});
      const inferredMethod = (
        baseInit.method ||
        (input && input.method) ||
        "GET"
      )
        .toString()
        .toUpperCase();
      if (shouldProxyArxiv(targetUrl) && inferredMethod === "GET") {{
        const arxivHeaders = new Headers();
        arxivHeaders.set("x-agentark-app-proxy", "arxiv");
        return nativeFetch(
          ARXIV_PROXY_PATH + "?source_url=" + encodeURIComponent(targetUrl),
          {{
            method: "GET",
            headers: arxivHeaders,
            credentials: "same-origin"
          }}
        );
      }}
      if (!shouldProxy(targetUrl)) {{
        return nativeFetch(input, init);
      }}
      const proxyInit = baseInit;
      proxyInit.method = inferredMethod;
      if (inferredMethod !== "POST") {{
        return nativeFetch(input, init);
      }}
      const headers = new Headers(proxyInit.headers || (input && input.headers) || {{}});
      headers.delete("authorization");
      headers.delete("x-api-key");
      headers.set("content-type", "application/json");
      headers.set("x-agentark-app-proxy", "llm");
      proxyInit.headers = headers;
      return nativeFetch(PROXY_PATH, proxyInit);
    }};
  }}

  const nativePrompt = window.prompt ? window.prompt.bind(window) : null;
  if (nativePrompt) {{
    window.prompt = function(message, defaultValue) {{
      const text = String(message || "").toLowerCase();
      if (
        text.includes("api key") ||
        text.includes("openai") ||
        text.includes("openrouter") ||
        text.includes("anthropic")
      ) {{
        return "agentark-managed";
      }}
      return nativePrompt(message, defaultValue);
    }};
  }}
}})();
</script>"#
    );

    if content.contains("</head>") {
        return content.replacen("</head>", &format!("{}\n</head>", shim), 1);
    }
    if content.contains("</body>") {
        return content.replacen("</body>", &format!("{}\n</body>", shim), 1);
    }
    format!("{}\n{}", content, shim)
}

fn extract_openai_message_text(value: &serde_json::Value) -> Option<String> {
    if let Some(s) = value.as_str() {
        let trimmed = s.trim();
        if !trimmed.is_empty() {
            return Some(trimmed.to_string());
        }
    }
    if let Some(obj) = value.as_object() {
        if let Some(s) = obj.get("text").and_then(|v| v.as_str()) {
            let trimmed = s.trim();
            if !trimmed.is_empty() {
                return Some(trimmed.to_string());
            }
        }
        if let Some(s) = obj.get("content").and_then(|v| v.as_str()) {
            let trimmed = s.trim();
            if !trimmed.is_empty() {
                return Some(trimmed.to_string());
            }
        }
    }
    if let Some(arr) = value.as_array() {
        let mut chunks = Vec::new();
        for item in arr {
            if let Some(obj) = item.as_object() {
                let item_type = obj
                    .get("type")
                    .and_then(|v| v.as_str())
                    .unwrap_or("text")
                    .to_ascii_lowercase();
                if item_type != "text" && item_type != "input_text" && item_type != "output_text" {
                    continue;
                }
                if let Some(text) = obj.get("text").and_then(|v| v.as_str()) {
                    if !text.trim().is_empty() {
                        chunks.push(text.trim().to_string());
                    }
                }
            } else if let Some(s) = item.as_str() {
                if !s.trim().is_empty() {
                    chunks.push(s.trim().to_string());
                }
            }
        }
        if !chunks.is_empty() {
            return Some(chunks.join("\n"));
        }
    }
    None
}

#[derive(Debug, Clone, Serialize, Default)]
struct AppArxivPaper {
    id: String,
    paper_url: String,
    pdf_url: String,
    title: String,
    summary: String,
    published: String,
    updated: String,
    authors: Vec<String>,
    primary_category: String,
    categories: Vec<String>,
}

#[derive(Debug, Clone, Default)]
struct AppArxivSearchRequest {
    source_url: String,
    search_query: String,
    start: usize,
    max_results: usize,
    sort_by: String,
    sort_order: String,
    categories: Vec<String>,
    keywords: Vec<String>,
}

fn app_origin_request_allowed(
    headers: &axum::http::HeaderMap,
    app_id: &str,
    proxy_tag: &str,
) -> bool {
    let has_proxy_header = headers
        .get("x-agentark-app-proxy")
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.eq_ignore_ascii_case(proxy_tag));
    let referer_ok = headers
        .get(header::REFERER)
        .and_then(|v| v.to_str().ok())
        .and_then(|v| reqwest::Url::parse(v).ok())
        .map(|url| {
            let path_prefix = format!("/apps/{}/", app_id);
            url.path().starts_with(&path_prefix) || url.path() == format!("/apps/{}", app_id)
        })
        .unwrap_or(false);
    has_proxy_header || referer_ok
}

fn collapse_inline_whitespace(value: &str) -> String {
    value.split_whitespace().collect::<Vec<_>>().join(" ")
}

fn split_app_query_csv(value: Option<&String>) -> Vec<String> {
    value
        .map(|raw| {
            raw.split([',', '|', '\n'])
                .map(str::trim)
                .filter(|item| !item.is_empty())
                .map(|item| item.to_string())
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn push_unique_ci(items: &mut Vec<String>, seen: &mut HashSet<String>, value: &str) {
    let normalized = collapse_inline_whitespace(value.trim().trim_matches('"').trim_matches('\''));
    if normalized.is_empty() {
        return;
    }
    let key = normalized.to_ascii_lowercase();
    if seen.insert(key) {
        items.push(normalized);
    }
}

fn normalize_arxiv_field_aliases(raw: &str) -> String {
    static ARXIV_FIELD_ALIAS_RE: OnceLock<Regex> = OnceLock::new();
    let re = ARXIV_FIELD_ALIAS_RE.get_or_init(|| {
        Regex::new(r"(?i)\b(title|abstract)\s*[:=]").expect("valid arxiv alias regex")
    });
    re.replace_all(raw, |caps: &regex::Captures| {
        let field = caps.get(1).map(|m| m.as_str()).unwrap_or_default();
        if field.eq_ignore_ascii_case("title") {
            "ti:"
        } else {
            "abs:"
        }
    })
    .into_owned()
}

fn extract_arxiv_categories_and_keywords(search_query: &str) -> (Vec<String>, Vec<String>) {
    static BOOLEAN_SPLIT_RE: OnceLock<Regex> = OnceLock::new();
    static CATEGORY_VALUE_RE: OnceLock<Regex> = OnceLock::new();
    let split_re = BOOLEAN_SPLIT_RE.get_or_init(|| {
        Regex::new(r"(?i)\bANDNOT\b|\bAND\b|\bOR\b").expect("valid boolean split regex")
    });
    let category_re = CATEGORY_VALUE_RE
        .get_or_init(|| Regex::new(r"^[A-Za-z0-9][A-Za-z0-9.\-]+$").expect("valid category regex"));

    let decoded = urlencoding::decode(search_query)
        .map(|value| value.into_owned())
        .unwrap_or_else(|_| search_query.to_string());
    let normalized = normalize_arxiv_field_aliases(&decoded);
    let mut categories = Vec::new();
    let mut keywords = Vec::new();
    let mut seen_categories = HashSet::new();
    let mut seen_keywords = HashSet::new();

    for token in split_re.split(&normalized) {
        let cleaned = collapse_inline_whitespace(
            token
                .trim()
                .trim_matches('(')
                .trim_matches(')')
                .trim_matches('"')
                .trim(),
        );
        if cleaned.is_empty() {
            continue;
        }
        let lower = cleaned.to_ascii_lowercase();
        if lower.starts_with("submitteddate:") {
            continue;
        }
        if lower.starts_with("cat:") {
            let category = cleaned[4..].trim().trim_matches('"');
            if category_re.is_match(category) {
                push_unique_ci(&mut categories, &mut seen_categories, category);
            }
            continue;
        }
        if lower.starts_with("ti:") || lower.starts_with("abs:") {
            let value = cleaned
                .split_once(':')
                .map(|(_, value)| value)
                .unwrap_or_default();
            push_unique_ci(&mut keywords, &mut seen_keywords, value);
            continue;
        }
        if !cleaned.contains(':') {
            push_unique_ci(&mut keywords, &mut seen_keywords, &cleaned);
        }
    }

    (categories, keywords)
}

fn build_canonical_arxiv_search_query(
    categories: &[String],
    keywords: &[String],
    raw_fallback: Option<&str>,
) -> String {
    let mut groups = Vec::new();

    if !categories.is_empty() {
        let category_group = categories
            .iter()
            .map(|category| format!("cat:{}", category))
            .collect::<Vec<_>>()
            .join(" OR ");
        groups.push(if categories.len() > 1 {
            format!("({})", category_group)
        } else {
            category_group
        });
    }

    if !keywords.is_empty() {
        let keyword_group = keywords
            .iter()
            .flat_map(|keyword| {
                let value = if keyword.contains(' ') {
                    format!("\"{}\"", keyword)
                } else {
                    keyword.to_string()
                };
                [format!("ti:{}", value), format!("abs:{}", value)]
            })
            .collect::<Vec<_>>()
            .join(" OR ");
        groups.push(if keywords.len() > 1 {
            format!("({})", keyword_group)
        } else {
            keyword_group
        });
    }

    if !groups.is_empty() {
        return groups.join(" AND ");
    }

    raw_fallback
        .map(normalize_arxiv_field_aliases)
        .map(|value| collapse_inline_whitespace(&value))
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "all:electron".to_string())
}

fn arxiv_sort_by_param(raw: Option<&str>) -> String {
    match raw.unwrap_or_default().trim().to_ascii_lowercase().as_str() {
        "relevance" => "relevance".to_string(),
        "lastupdateddate" | "last_updated_date" | "updated" => "lastUpdatedDate".to_string(),
        _ => "submittedDate".to_string(),
    }
}

fn arxiv_sort_order_param(raw: Option<&str>) -> String {
    match raw.unwrap_or_default().trim().to_ascii_lowercase().as_str() {
        "ascending" | "asc" => "ascending".to_string(),
        _ => "descending".to_string(),
    }
}

fn unwrap_nested_public_proxy_url(raw: &str) -> String {
    let mut current = raw.trim().to_string();
    for _ in 0..5 {
        let decoded = urlencoding::decode(&current)
            .map(|value| value.into_owned())
            .unwrap_or_else(|_| current.clone());
        let trimmed = decoded.trim().to_string();
        if trimmed.starts_with("/public/proxy/raw?url=") {
            current = trimmed
                .trim_start_matches("/public/proxy/raw?url=")
                .trim()
                .to_string();
            continue;
        }
        if let Ok(parsed) = reqwest::Url::parse(&trimmed) {
            if parsed.path() == "/public/proxy/raw" {
                if let Some(raw_query) = parsed.query() {
                    if raw_query.starts_with("url=http://") || raw_query.starts_with("url=https://")
                    {
                        current = raw_query.trim_start_matches("url=").trim().to_string();
                        continue;
                    }
                    if let Some(url_value) = url::form_urlencoded::parse(raw_query.as_bytes())
                        .find_map(|(key, value)| (key == "url").then(|| value.into_owned()))
                    {
                        current = url_value;
                        continue;
                    }
                }
            }
        }
        return trimmed;
    }
    current
}

fn build_arxiv_search_request_from_source_url(
    raw_source_url: &str,
) -> Option<AppArxivSearchRequest> {
    let source_url = unwrap_nested_public_proxy_url(raw_source_url);
    let without_fragment = source_url.split('#').next()?.trim();
    let (base, raw_query) = without_fragment.split_once('?')?;
    let mut base_url = reqwest::Url::parse(base).ok()?;
    if !is_allowed_public_proxy_host(base_url.host_str().unwrap_or_default()) {
        return None;
    }
    if base_url.path() != "/api/query" {
        return None;
    }
    if base_url.scheme() == "http" {
        let _ = base_url.set_scheme("https");
    }

    let params: HashMap<String, String> = url::form_urlencoded::parse(raw_query.as_bytes())
        .into_owned()
        .collect();
    let raw_search_query = params.get("search_query").cloned().unwrap_or_default();
    let (categories, keywords) = extract_arxiv_categories_and_keywords(&raw_search_query);
    Some(AppArxivSearchRequest {
        source_url,
        search_query: build_canonical_arxiv_search_query(
            &categories,
            &keywords,
            Some(&raw_search_query),
        ),
        start: params
            .get("start")
            .and_then(|value| value.parse::<usize>().ok())
            .unwrap_or(0),
        max_results: params
            .get("max_results")
            .and_then(|value| value.parse::<usize>().ok())
            .map(|value| value.clamp(1, 50))
            .unwrap_or(25),
        sort_by: arxiv_sort_by_param(params.get("sortBy").map(String::as_str)),
        sort_order: arxiv_sort_order_param(params.get("sortOrder").map(String::as_str)),
        categories,
        keywords,
    })
}

fn build_arxiv_search_request_from_query(raw_query: Option<&str>) -> Option<AppArxivSearchRequest> {
    let params: HashMap<String, String> = raw_query
        .map(|query| {
            url::form_urlencoded::parse(query.as_bytes())
                .into_owned()
                .collect::<HashMap<_, _>>()
        })
        .unwrap_or_default();

    if let Some(source_url) = params
        .get("source_url")
        .filter(|value| !value.trim().is_empty())
    {
        return build_arxiv_search_request_from_source_url(source_url);
    }

    let mut categories = split_app_query_csv(
        params
            .get("categories")
            .or_else(|| params.get("subjects"))
            .or_else(|| params.get("category")),
    );
    let mut keywords = split_app_query_csv(
        params
            .get("keywords")
            .or_else(|| params.get("terms"))
            .or_else(|| params.get("q")),
    );
    let raw_search_query = params.get("search_query").cloned().unwrap_or_default();
    if (categories.is_empty() && keywords.is_empty()) && !raw_search_query.trim().is_empty() {
        let extracted = extract_arxiv_categories_and_keywords(&raw_search_query);
        categories = extracted.0;
        keywords = extracted.1;
    }

    if categories.is_empty() && keywords.is_empty() && raw_search_query.trim().is_empty() {
        return None;
    }

    Some(AppArxivSearchRequest {
        source_url: String::new(),
        search_query: build_canonical_arxiv_search_query(
            &categories,
            &keywords,
            (!raw_search_query.trim().is_empty()).then_some(raw_search_query.as_str()),
        ),
        start: params
            .get("start")
            .and_then(|value| value.parse::<usize>().ok())
            .unwrap_or(0),
        max_results: params
            .get("max_results")
            .and_then(|value| value.parse::<usize>().ok())
            .map(|value| value.clamp(1, 50))
            .unwrap_or(25),
        sort_by: arxiv_sort_by_param(
            params
                .get("sortBy")
                .or_else(|| params.get("sort_by"))
                .map(String::as_str),
        ),
        sort_order: arxiv_sort_order_param(
            params
                .get("sortOrder")
                .or_else(|| params.get("sort_order"))
                .map(String::as_str),
        ),
        categories,
        keywords,
    })
}

fn arxiv_upstream_url(request: &AppArxivSearchRequest) -> reqwest::Url {
    let mut url =
        reqwest::Url::parse("https://export.arxiv.org/api/query").expect("valid arxiv url");
    url.query_pairs_mut()
        .append_pair("search_query", &request.search_query)
        .append_pair("start", &request.start.to_string())
        .append_pair("max_results", &request.max_results.to_string())
        .append_pair("sortBy", &request.sort_by)
        .append_pair("sortOrder", &request.sort_order);
    url
}

fn canonical_arxiv_id(raw: &str) -> String {
    let trimmed = raw.trim();
    if let Ok(parsed) = reqwest::Url::parse(trimmed) {
        let path = parsed.path().trim_start_matches('/');
        return path
            .strip_prefix("abs/")
            .or_else(|| path.strip_prefix("pdf/"))
            .unwrap_or(path)
            .trim_end_matches(".pdf")
            .to_string();
    }
    trimmed.to_string()
}

fn decode_arxiv_xml_entities(raw: &str) -> String {
    raw.replace("&lt;", "<")
        .replace("&gt;", ">")
        .replace("&amp;", "&")
        .replace("&quot;", "\"")
        .replace("&apos;", "'")
}

fn first_xml_tag_text(block: &str, tag: &str) -> String {
    let pattern = format!(
        r"(?is)<(?:[A-Za-z0-9_]+:)?{tag}\b[^>]*>(.*?)</(?:[A-Za-z0-9_]+:)?{tag}>",
        tag = regex::escape(tag)
    );
    Regex::new(&pattern)
        .ok()
        .and_then(|re| re.captures(block))
        .and_then(|caps| caps.get(1).map(|m| m.as_str().to_string()))
        .map(|value| collapse_inline_whitespace(&decode_arxiv_xml_entities(&value)))
        .unwrap_or_default()
}

fn all_xml_tag_text(block: &str, tag: &str) -> Vec<String> {
    let pattern = format!(
        r"(?is)<(?:[A-Za-z0-9_]+:)?{tag}\b[^>]*>(.*?)</(?:[A-Za-z0-9_]+:)?{tag}>",
        tag = regex::escape(tag)
    );
    Regex::new(&pattern)
        .ok()
        .map(|re| {
            re.captures_iter(block)
                .filter_map(|caps| caps.get(1).map(|m| m.as_str()))
                .map(decode_arxiv_xml_entities)
                .map(|value| collapse_inline_whitespace(&value))
                .filter(|value| !value.is_empty())
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn xml_attr_value(attrs: &str, key: &str) -> String {
    let pattern = format!(r#"(?is)\b{}\s*=\s*"([^"]*)""#, regex::escape(key));
    Regex::new(&pattern)
        .ok()
        .and_then(|re| re.captures(attrs))
        .and_then(|caps| caps.get(1).map(|m| m.as_str().to_string()))
        .map(|value| decode_arxiv_xml_entities(&value))
        .unwrap_or_default()
}

fn parse_arxiv_atom_feed(xml: &str) -> anyhow::Result<serde_json::Value> {
    static ENTRY_RE: OnceLock<Regex> = OnceLock::new();
    static LINK_RE: OnceLock<Regex> = OnceLock::new();
    static CATEGORY_RE: OnceLock<Regex> = OnceLock::new();
    static PRIMARY_CATEGORY_RE: OnceLock<Regex> = OnceLock::new();
    let entry_re = ENTRY_RE.get_or_init(|| {
        Regex::new(r"(?is)<entry\b[^>]*>(.*?)</entry>").expect("valid arxiv entry regex")
    });
    let link_re = LINK_RE.get_or_init(|| {
        Regex::new(r"(?is)<(?:[A-Za-z0-9_]+:)?link\b([^>]*)/?>").expect("valid arxiv link regex")
    });
    let category_re = CATEGORY_RE.get_or_init(|| {
        Regex::new(r"(?is)<(?:[A-Za-z0-9_]+:)?category\b([^>]*)/?>")
            .expect("valid arxiv category regex")
    });
    let primary_category_re = PRIMARY_CATEGORY_RE.get_or_init(|| {
        Regex::new(r"(?is)<(?:[A-Za-z0-9_]+:)?primary_category\b([^>]*)/?>")
            .expect("valid arxiv primary category regex")
    });

    let total_results = first_xml_tag_text(xml, "totalResults")
        .parse::<usize>()
        .unwrap_or(0);
    let start_index = first_xml_tag_text(xml, "startIndex")
        .parse::<usize>()
        .unwrap_or(0);
    let items_per_page = first_xml_tag_text(xml, "itemsPerPage")
        .parse::<usize>()
        .unwrap_or(0);
    let mut papers = Vec::new();

    for entry_caps in entry_re.captures_iter(xml) {
        let Some(entry_block) = entry_caps.get(1).map(|m| m.as_str()) else {
            continue;
        };

        let mut paper_url = String::new();
        let mut pdf_url = String::new();
        for link_caps in link_re.captures_iter(entry_block) {
            let attrs = link_caps.get(1).map(|m| m.as_str()).unwrap_or_default();
            let href = xml_attr_value(attrs, "href");
            let rel = xml_attr_value(attrs, "rel");
            let title = xml_attr_value(attrs, "title");
            let content_type = xml_attr_value(attrs, "type");
            if rel == "alternate" && paper_url.is_empty() {
                paper_url = href.clone();
            }
            if title.eq_ignore_ascii_case("pdf")
                || (rel == "related" && content_type.contains("pdf"))
            {
                pdf_url = href;
            }
        }

        let mut categories = Vec::new();
        for category_caps in category_re.captures_iter(entry_block) {
            let attrs = category_caps.get(1).map(|m| m.as_str()).unwrap_or_default();
            let value = xml_attr_value(attrs, "term");
            if !value.is_empty() && !categories.iter().any(|item| item == &value) {
                categories.push(value);
            }
        }
        let primary_category = primary_category_re
            .captures(entry_block)
            .and_then(|caps| caps.get(1).map(|m| m.as_str().to_string()))
            .map(|attrs| xml_attr_value(&attrs, "term"))
            .filter(|value| !value.is_empty())
            .or_else(|| categories.first().cloned())
            .unwrap_or_default();
        let id = canonical_arxiv_id(&first_xml_tag_text(entry_block, "id"));

        papers.push(AppArxivPaper {
            id,
            paper_url,
            pdf_url,
            title: first_xml_tag_text(entry_block, "title"),
            summary: first_xml_tag_text(entry_block, "summary"),
            published: first_xml_tag_text(entry_block, "published"),
            updated: first_xml_tag_text(entry_block, "updated"),
            authors: all_xml_tag_text(entry_block, "name"),
            primary_category,
            categories,
        });
    }

    Ok(serde_json::json!({
        "total_results": total_results,
        "start_index": start_index,
        "items_per_page": items_per_page,
        "papers": papers,
    }))
}

async fn app_scoped_arxiv_search_proxy(
    _state: &AppState,
    app_id: &str,
    headers: &axum::http::HeaderMap,
    raw_query: Option<&str>,
) -> Response {
    if !app_origin_request_allowed(headers, app_id, "arxiv") {
        return (
            StatusCode::FORBIDDEN,
            Json(serde_json::json!({
                "error": "forbidden",
                "message": "app-scoped arXiv helper requires app-origin request context"
            })),
        )
            .into_response();
    }

    let Some(request) = build_arxiv_search_request_from_query(raw_query) else {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({
                "error": "missing_query",
                "message": "Provide source_url, search_query, categories, keywords, or q."
            })),
        )
            .into_response();
    };

    let upstream_url = arxiv_upstream_url(&request);
    let client = match reqwest::Client::builder()
        .timeout(Duration::from_secs(12))
        .redirect(reqwest::redirect::Policy::limited(3))
        .user_agent(crate::branding::user_agent_with_suffix("arXiv app helper"))
        .build()
    {
        Ok(client) => client,
        Err(_) => return StatusCode::INTERNAL_SERVER_ERROR.into_response(),
    };

    let response = match client.get(upstream_url.clone()).send().await {
        Ok(response) => response,
        Err(error) => {
            return (
                StatusCode::BAD_GATEWAY,
                Json(serde_json::json!({
                    "error": "arxiv_fetch_failed",
                    "message": error.to_string(),
                    "query": request.search_query,
                })),
            )
                .into_response();
        }
    };

    if !response.status().is_success() {
        return (
            StatusCode::BAD_GATEWAY,
            Json(serde_json::json!({
                "error": "arxiv_upstream_error",
                "status": response.status().as_u16(),
                "query": request.search_query,
                "upstream_url": upstream_url.to_string(),
            })),
        )
            .into_response();
    }

    let xml = match response.text().await {
        Ok(xml) => xml,
        Err(error) => {
            return (
                StatusCode::BAD_GATEWAY,
                Json(serde_json::json!({
                    "error": "arxiv_read_failed",
                    "message": error.to_string(),
                })),
            )
                .into_response();
        }
    };

    let parsed = match parse_arxiv_atom_feed(&xml) {
        Ok(parsed) => parsed,
        Err(error) => {
            return (
                StatusCode::BAD_GATEWAY,
                Json(serde_json::json!({
                    "error": "arxiv_parse_failed",
                    "message": error.to_string(),
                    "query": request.search_query,
                })),
            )
                .into_response();
        }
    };

    let mut payload = parsed.as_object().cloned().unwrap_or_default();
    payload.insert(
        "query".to_string(),
        serde_json::json!({
            "search_query": request.search_query,
            "start": request.start,
            "max_results": request.max_results,
            "sortBy": request.sort_by,
            "sortOrder": request.sort_order,
            "categories": request.categories,
            "keywords": request.keywords,
            "source_url": request.source_url,
            "upstream_url": upstream_url.to_string(),
        }),
    );

    (
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, "application/json".to_string()),
            (header::CACHE_CONTROL, "no-store".to_string()),
        ],
        serde_json::Value::Object(payload).to_string(),
    )
        .into_response()
}

async fn app_scoped_llm_chat_proxy(
    state: &AppState,
    app_id: &str,
    headers: &axum::http::HeaderMap,
    body: axum::body::Body,
) -> Response {
    let has_proxy_header = headers
        .get("x-agentark-app-proxy")
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.eq_ignore_ascii_case("llm"));
    let referer_ok = headers
        .get(header::REFERER)
        .and_then(|v| v.to_str().ok())
        .and_then(|v| reqwest::Url::parse(v).ok())
        .map(|url| {
            let path_prefix = format!("/apps/{}/", app_id);
            url.path().starts_with(&path_prefix) || url.path() == format!("/apps/{}", app_id)
        })
        .unwrap_or(false);
    if !has_proxy_header && !referer_ok {
        return (
            StatusCode::FORBIDDEN,
            Json(serde_json::json!({
                "error": "forbidden",
                "message": "app-scoped LLM proxy requires app-origin request context"
            })),
        )
            .into_response();
    }

    let body_bytes = match axum::body::to_bytes(body, 1024 * 1024).await {
        Ok(bytes) => bytes,
        Err(_) => {
            return (
                StatusCode::PAYLOAD_TOO_LARGE,
                Json(serde_json::json!({ "error": "request body too large" })),
            )
                .into_response()
        }
    };
    let payload: serde_json::Value = match serde_json::from_slice(&body_bytes) {
        Ok(v) => v,
        Err(_) => {
            return (
                StatusCode::BAD_REQUEST,
                Json(serde_json::json!({ "error": "invalid JSON payload" })),
            )
                .into_response()
        }
    };

    let stream_requested = payload
        .get("stream")
        .and_then(|v| v.as_bool())
        .unwrap_or(false);
    if stream_requested {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({
                "error": "streaming_not_supported",
                "message": "Use non-streaming chat completion for app proxy requests."
            })),
        )
            .into_response();
    }

    let mut system_lines: Vec<String> = Vec::new();
    let mut convo: Vec<(String, String)> = Vec::new();
    let requested_model_hint = payload
        .get("model")
        .and_then(|v| v.as_str())
        .map(str::trim)
        .filter(|s| !s.is_empty())
        .map(|s| s.to_string());
    if let Some(messages) = payload.get("messages").and_then(|v| v.as_array()) {
        for msg in messages {
            let Some(obj) = msg.as_object() else {
                continue;
            };
            let role = obj
                .get("role")
                .and_then(|v| v.as_str())
                .unwrap_or("user")
                .to_ascii_lowercase();
            let Some(content_val) = obj.get("content") else {
                continue;
            };
            let Some(text) = extract_openai_message_text(content_val) else {
                continue;
            };
            if role == "system" {
                system_lines.push(text);
            } else {
                convo.push((role, text));
            }
        }
    }

    if convo.is_empty() {
        if let Some(input) = payload.get("input") {
            if let Some(text) = extract_openai_message_text(input) {
                convo.push(("user".to_string(), text));
            } else if let Some(arr) = input.as_array() {
                for item in arr {
                    let Some(obj) = item.as_object() else {
                        continue;
                    };
                    let role = obj
                        .get("role")
                        .and_then(|v| v.as_str())
                        .unwrap_or("user")
                        .to_ascii_lowercase();
                    let content_val = obj.get("content").or_else(|| obj.get("text"));
                    let Some(content_val) = content_val else {
                        continue;
                    };
                    let Some(text) = extract_openai_message_text(content_val) else {
                        continue;
                    };
                    if role == "system" {
                        system_lines.push(text);
                    } else {
                        convo.push((role, text));
                    }
                }
            }
        }
    }

    if convo.is_empty() {
        if let Some(prompt) = payload.get("prompt").and_then(|v| v.as_str()) {
            let trimmed = prompt.trim();
            if !trimmed.is_empty() {
                convo.push(("user".to_string(), trimmed.to_string()));
            }
        }
    }

    if convo.is_empty() {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({
                "error": "missing_messages",
                "message": "Provide messages[], input, or prompt."
            })),
        )
            .into_response();
    }

    let system_prompt = if system_lines.is_empty() {
        "You are a concise assistant helping summarize and explain app content for the end user."
            .to_string()
    } else {
        system_lines.join("\n")
    };

    let (last_role, last_text) = convo.pop().unwrap_or(("user".to_string(), String::new()));
    let user_message = if last_text.trim().is_empty() {
        "Please help with this request.".to_string()
    } else if last_role == "assistant" {
        format!(
            "Continue from the previous assistant context:\n{}",
            last_text
        )
    } else {
        last_text
    };

    let history: Vec<crate::core::ConversationMessage> = convo
        .into_iter()
        .map(|(role, content)| crate::core::ConversationMessage {
            role: if role == "assistant" {
                "assistant".to_string()
            } else {
                "user".to_string()
            },
            content,
            _timestamp: chrono::Utc::now(),
        })
        .collect();

    let (selected_llm, model_name, selection_note) = {
        let agent = state.agent.read().await;
        let (llm, _slot_label, note) =
            agent.select_llm_for_app_proxy(requested_model_hint.as_deref());
        let name = llm.model_name().to_string();
        (llm, name, note)
    };

    let no_actions: Vec<crate::actions::ActionDef> = Vec::new();
    let response = match selected_llm
        .chat_with_history(&system_prompt, &user_message, &history, &[], &no_actions)
        .await
    {
        Ok(r) => r,
        Err(e) => {
            return (
                StatusCode::BAD_GATEWAY,
                Json(serde_json::json!({
                    "error": "llm_proxy_failed",
                    "message": format!("LLM request failed: {}", e)
                })),
            )
                .into_response()
        }
    };
    let assistant_content = response.content;

    let openai_like = serde_json::json!({
        "id": format!("chatcmpl-{}", uuid::Uuid::new_v4()),
        "object": "chat.completion",
        "created": chrono::Utc::now().timestamp(),
        "model": model_name,
        "selection_note": selection_note,
        "choices": [{
            "index": 0,
            "message": {
                "role": "assistant",
                "content": &assistant_content,
            },
            "text": &assistant_content,
            "finish_reason": "stop"
        }],
        "output_text": &assistant_content,
        "output": [{
            "type": "message",
            "role": "assistant",
            "content": [{
                "type": "output_text",
                "text": &assistant_content
            }]
        }],
        "status": "completed",
        "usage": response.usage.as_ref().map(|u| serde_json::json!({
            "prompt_tokens": u.prompt_tokens,
            "completion_tokens": u.completion_tokens,
            "total_tokens": u.total_tokens
        }))
    });

    (
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, "application/json".to_string()),
            (header::CACHE_CONTROL, "no-store".to_string()),
        ],
        openai_like.to_string(),
    )
        .into_response()
}

fn is_local_or_private_host_for_upgrade(host: &str) -> bool {
    let h = host
        .trim()
        .trim_matches('[')
        .trim_matches(']')
        .to_ascii_lowercase();
    if h.is_empty()
        || h == "localhost"
        || h.ends_with(".localhost")
        || h == "0.0.0.0"
        || h.ends_with(".local")
        || h.ends_with(".internal")
    {
        return true;
    }
    if let Ok(ip) = h.parse::<std::net::IpAddr>() {
        return match ip {
            std::net::IpAddr::V4(v4) => {
                v4.is_loopback() || v4.is_private() || v4.is_link_local() || v4.is_unspecified()
            }
            std::net::IpAddr::V6(v6) => {
                v6.is_loopback()
                    || v6.is_unspecified()
                    || v6.is_unique_local()
                    || v6.is_unicast_link_local()
            }
        };
    }
    false
}

fn upgrade_http_links_for_secure_origin(content: &str) -> String {
    static HTTP_URL_RE: OnceLock<Regex> = OnceLock::new();
    let re = HTTP_URL_RE.get_or_init(|| {
        Regex::new(r#"http://[A-Za-z0-9\.\-]+(?::\d+)?[^\s"'<>)]*"#)
            .expect("valid insecure URL regex")
    });
    re.replace_all(content, |caps: &regex::Captures| {
        let raw = caps.get(0).map(|m| m.as_str()).unwrap_or_default();
        let Some(parsed) = reqwest::Url::parse(raw).ok() else {
            return raw.to_string();
        };
        let host = parsed.host_str().unwrap_or_default();
        if is_local_or_private_host_for_upgrade(host) {
            return raw.to_string();
        }
        raw.replacen("http://", "https://", 1)
    })
    .into_owned()
}

fn is_allowed_public_proxy_host(host: &str) -> bool {
    let h = host.trim().to_ascii_lowercase();
    h == "export.arxiv.org" || h == "arxiv.org" || h.ends_with(".arxiv.org")
}

/// Public proxy for static tunneled apps.
/// Strict allowlist prevents open-proxy abuse.
async fn public_proxy_raw(uri: Uri, Query(params): Query<HashMap<String, String>>) -> Response {
    // Accept both properly encoded URLs and pragmatic unencoded forms such as:
    // /public/proxy/raw?url=https://export.arxiv.org/api/query?search_query=...&start=0
    // The latter appears in generated JS that appends query params dynamically.
    let mut raw_url = params
        .get("url")
        .map(|s| s.trim().to_string())
        .unwrap_or_default();
    if let Some(raw_query) = uri.query().map(str::trim) {
        if raw_query.starts_with("url=http://") || raw_query.starts_with("url=https://") {
            raw_url = raw_query.trim_start_matches("url=").trim().to_string();
        }
    }
    let raw_url = raw_url.trim();
    if raw_url.is_empty() {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({ "error": "missing query param: url" })),
        )
            .into_response();
    }

    let mut parsed = match reqwest::Url::parse(raw_url) {
        Ok(url) => url,
        Err(_) => {
            return (
                StatusCode::BAD_REQUEST,
                Json(serde_json::json!({ "error": "invalid url" })),
            )
                .into_response()
        }
    };

    let host = parsed.host_str().unwrap_or("");
    if !is_allowed_public_proxy_host(host) {
        return (
            StatusCode::FORBIDDEN,
            Json(serde_json::json!({ "error": "host not allowed" })),
        )
            .into_response();
    }

    if parsed.scheme() == "http" {
        let _ = parsed.set_scheme("https");
    }
    if parsed.scheme() != "https" {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({ "error": "only https urls are allowed" })),
        )
            .into_response();
    }

    let client = match reqwest::Client::builder()
        .timeout(Duration::from_secs(12))
        .redirect(reqwest::redirect::Policy::limited(3))
        .build()
    {
        Ok(c) => c,
        Err(_) => return StatusCode::INTERNAL_SERVER_ERROR.into_response(),
    };

    match client.get(parsed).send().await {
        Ok(resp) => {
            if !resp.status().is_success() {
                return (
                    StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({
                        "error": format!("upstream returned {}", resp.status())
                    })),
                )
                    .into_response();
            }
            let content_type = resp
                .headers()
                .get(header::CONTENT_TYPE)
                .and_then(|v| v.to_str().ok())
                .unwrap_or("application/octet-stream")
                .to_string();
            match resp.bytes().await {
                Ok(bytes) => (
                    StatusCode::OK,
                    [
                        (header::CONTENT_TYPE, content_type),
                        (header::CACHE_CONTROL, "no-store".to_string()),
                        (header::ACCESS_CONTROL_ALLOW_ORIGIN, "*".to_string()),
                    ],
                    bytes,
                )
                    .into_response(),
                Err(_) => StatusCode::BAD_GATEWAY.into_response(),
            }
        }
        Err(_) => StatusCode::BAD_GATEWAY.into_response(),
    }
}

fn extract_query_param(query: Option<&str>, key: &str) -> Option<String> {
    query.and_then(|q| {
        url::form_urlencoded::parse(q.as_bytes()).find_map(|(k, v)| {
            if k == key {
                Some(v.into_owned())
            } else {
                None
            }
        })
    })
}

fn strip_query_param(query: Option<&str>, key: &str) -> Option<String> {
    let query = query?;
    let mut serializer = url::form_urlencoded::Serializer::new(String::new());
    let mut has_pairs = false;
    for (k, v) in url::form_urlencoded::parse(query.as_bytes()) {
        if k == key {
            continue;
        }
        serializer.append_pair(&k, &v);
        has_pairs = true;
    }
    if has_pairs {
        Some(serializer.finish())
    } else {
        None
    }
}

fn extract_cookie(headers: &axum::http::HeaderMap, cookie_name: &str) -> Option<String> {
    headers
        .get(header::COOKIE)
        .and_then(|v| v.to_str().ok())
        .and_then(|cookies| {
            cookies.split(';').map(|c| c.trim()).find_map(|c| {
                c.strip_prefix(&format!("{}=", cookie_name))
                    .map(|v| v.to_string())
            })
        })
}

fn filter_proxy_cookie(cookie_header: &str, app_id: &str) -> Option<String> {
    let app_cookie = format!("ark_app_{}=", app_id);
    let filtered: Vec<&str> = cookie_header
        .split(';')
        .map(|c| c.trim())
        .filter(|c| !c.is_empty())
        .filter(|c| !c.starts_with(&format!("{}=", crate::branding::SESSION_COOKIE_NAME)))
        .filter(|c| !c.starts_with(&app_cookie))
        .collect();
    if filtered.is_empty() {
        None
    } else {
        Some(filtered.join("; "))
    }
}

fn build_app_url(app_id: &str, path: &str, query: Option<&str>) -> String {
    let mut url = if path.is_empty() {
        format!("/apps/{}/", app_id)
    } else {
        format!("/apps/{}/{}", app_id, path.trim_start_matches('/'))
    };
    if let Some(q) = query.filter(|q| !q.is_empty()) {
        url.push('?');
        url.push_str(q);
    }
    url
}

fn build_absolute_app_url(
    base_url: Option<&str>,
    app_id: &str,
    path: &str,
    query: Option<&str>,
) -> String {
    let relative = build_app_url(app_id, path, query);
    match base_url {
        Some(base) if !base.trim().is_empty() => {
            format!("{}{}", base.trim_end_matches('/'), relative)
        }
        _ => relative,
    }
}

fn app_root_url_for_state(state: &AppState, app_id: &str) -> String {
    build_absolute_app_url(state.public_app_base_url.as_deref(), app_id, "", None)
}

async fn app_access_url_for_state(
    state: &AppState,
    app_id: &str,
    access_guard_enabled: bool,
) -> String {
    let relative = if access_guard_enabled {
        state
            .app_registry
            .issue_access_url(app_id)
            .await
            .unwrap_or_else(|| build_app_url(app_id, "", None))
    } else {
        build_app_url(app_id, "", None)
    };
    match state.public_app_base_url.as_deref() {
        Some(base) if !base.trim().is_empty() => {
            format!("{}{}", base.trim_end_matches('/'), relative)
        }
        _ => relative,
    }
}

fn is_hop_by_hop_header(header_name: &str) -> bool {
    matches!(
        header_name,
        "connection"
            | "keep-alive"
            | "proxy-authenticate"
            | "proxy-authorization"
            | "te"
            | "trailer"
            | "transfer-encoding"
            | "upgrade"
    )
}

fn is_websocket_upgrade(headers: &axum::http::HeaderMap) -> bool {
    let has_upgrade_token = headers
        .get(header::CONNECTION)
        .and_then(|v| v.to_str().ok())
        .map(|v| {
            v.split(',')
                .any(|part| part.trim().eq_ignore_ascii_case("upgrade"))
        })
        .unwrap_or(false);
    let websocket_upgrade = headers
        .get(header::UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);
    has_upgrade_token && websocket_upgrade
}

fn axum_to_tungstenite_message(msg: AxumWsMessage) -> Option<TungsteniteMessage> {
    match msg {
        AxumWsMessage::Text(text) => Some(TungsteniteMessage::Text(text.to_string())),
        AxumWsMessage::Binary(data) => Some(TungsteniteMessage::Binary(data.to_vec())),
        AxumWsMessage::Ping(data) => Some(TungsteniteMessage::Ping(data.to_vec())),
        AxumWsMessage::Pong(data) => Some(TungsteniteMessage::Pong(data.to_vec())),
        AxumWsMessage::Close(_) => Some(TungsteniteMessage::Close(None)),
    }
}

fn tungstenite_to_axum_message(msg: TungsteniteMessage) -> Option<AxumWsMessage> {
    match msg {
        TungsteniteMessage::Text(text) => Some(AxumWsMessage::Text(text.to_string().into())),
        TungsteniteMessage::Binary(data) => Some(AxumWsMessage::Binary(data.into())),
        TungsteniteMessage::Ping(data) => Some(AxumWsMessage::Ping(data.into())),
        TungsteniteMessage::Pong(data) => Some(AxumWsMessage::Pong(data.into())),
        TungsteniteMessage::Close(_) => Some(AxumWsMessage::Close(None)),
        TungsteniteMessage::Frame(_) => None,
    }
}

async fn proxy_websocket_connection(
    client_socket: WebSocket,
    upstream_url: String,
    requested_protocols: Vec<String>,
    forward_headers: Vec<(String, String)>,
) {
    let mut upstream_request = match upstream_url.into_client_request() {
        Ok(request) => request,
        Err(error) => {
            tracing::warn!("Failed to build upstream WS request: {}", error);
            return;
        }
    };
    if !requested_protocols.is_empty() {
        let protocols = requested_protocols.join(", ");
        if let Ok(value) = axum::http::HeaderValue::from_str(&protocols) {
            upstream_request
                .headers_mut()
                .insert("Sec-WebSocket-Protocol", value);
        }
    }
    for (name, value) in forward_headers {
        if let (Ok(header_name), Ok(header_value)) = (
            axum::http::HeaderName::from_bytes(name.as_bytes()),
            axum::http::HeaderValue::from_str(&value),
        ) {
            upstream_request
                .headers_mut()
                .insert(header_name, header_value);
        }
    }

    let (upstream_socket, _) = match tokio_tungstenite::connect_async(upstream_request).await {
        Ok(pair) => pair,
        Err(error) => {
            tracing::warn!("Failed to connect to upstream WS app: {}", error);
            return;
        }
    };

    let (mut client_sender, mut client_receiver) = client_socket.split();
    let (mut upstream_sender, mut upstream_receiver) = upstream_socket.split();

    let client_to_upstream = async {
        while let Some(result) = client_receiver.next().await {
            match result {
                Ok(message) => {
                    let Some(upstream_message) = axum_to_tungstenite_message(message) else {
                        continue;
                    };
                    if upstream_sender.send(upstream_message).await.is_err() {
                        break;
                    }
                }
                Err(error) => {
                    tracing::debug!("Client WS receive error: {}", error);
                    break;
                }
            }
        }
        let _ = upstream_sender.close().await;
    };

    let upstream_to_client = async {
        while let Some(result) = upstream_receiver.next().await {
            match result {
                Ok(message) => {
                    let Some(client_message) = tungstenite_to_axum_message(message) else {
                        continue;
                    };
                    if client_sender.send(client_message).await.is_err() {
                        break;
                    }
                }
                Err(error) => {
                    tracing::debug!("Upstream WS receive error: {}", error);
                    break;
                }
            }
        }
        let _ = client_sender.send(AxumWsMessage::Close(None)).await;
    };

    tokio::select! {
        _ = client_to_upstream => {}
        _ = upstream_to_client => {}
    }
}

/// Serve app root - static files or reverse proxy
async fn serve_app_root(
    State(state): State<AppState>,
    Path(app_id): Path<String>,
    request: Request,
) -> Response {
    let (mut parts, body) = request.into_parts();
    let ws = if is_websocket_upgrade(&parts.headers) {
        WebSocketUpgrade::from_request_parts(&mut parts, &())
            .await
            .ok()
    } else {
        None
    };

    let method = parts.method.clone();
    let uri = parts.uri.clone();
    let headers = parts.headers.clone();

    serve_app_file_inner(
        &state,
        &app_id,
        "",
        AppServeRequestContext {
            method,
            uri,
            headers,
            ws,
            body,
        },
    )
    .await
}

/// Serve app file by path - static files or reverse proxy
async fn serve_app_path(
    State(state): State<AppState>,
    Path((app_id, path)): Path<(String, String)>,
    request: Request,
) -> Response {
    let (mut parts, body) = request.into_parts();
    let ws = if is_websocket_upgrade(&parts.headers) {
        WebSocketUpgrade::from_request_parts(&mut parts, &())
            .await
            .ok()
    } else {
        None
    };

    let method = parts.method.clone();
    let uri = parts.uri.clone();
    let headers = parts.headers.clone();

    serve_app_file_inner(
        &state,
        &app_id,
        &path,
        AppServeRequestContext {
            method,
            uri,
            headers,
            ws,
            body,
        },
    )
    .await
}

struct AppServeRequestContext {
    method: Method,
    uri: Uri,
    headers: axum::http::HeaderMap,
    ws: Option<WebSocketUpgrade>,
    body: axum::body::Body,
}

fn should_proxy_app_request_to_executor(is_static: bool, executor_configured: bool) -> bool {
    executor_configured && !is_static
}

/// Inner handler: serve static file or reverse proxy to dynamic app
async fn serve_app_file_inner(
    state: &AppState,
    app_id: &str,
    path: &str,
    request_ctx: AppServeRequestContext,
) -> Response {
    let method = request_ctx.method;
    let uri = request_ctx.uri;
    let headers = request_ctx.headers;
    let ws = request_ctx.ws;
    let body = request_ctx.body;

    if !is_valid_app_id(app_id) {
        return StatusCode::BAD_REQUEST.into_response();
    }

    if state.server_role == HttpServerRole::ControlPlane
        && internet_facing_apps_should_be_isolated(
            state.deployment_mode,
            state.public_app_bind_addr.as_deref(),
        )
    {
        let target = build_absolute_app_url(
            state.public_app_base_url.as_deref(),
            app_id,
            path,
            uri.query(),
        );
        if target.starts_with("http://") || target.starts_with("https://") {
            return Response::builder()
                .status(StatusCode::TEMPORARY_REDIRECT)
                .header(header::LOCATION, target)
                .body(axum::body::Body::empty())
                .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR.into_response());
        }
        return (
            StatusCode::SERVICE_UNAVAILABLE,
            "Public apps are isolated onto a dedicated app origin in internet-facing mode.",
        )
            .into_response();
    }

    // Check app existence first so unknown IDs return 404 instead of auth form.
    let Some(app_dir) = state.app_registry.get_dir(app_id).await else {
        return StatusCode::NOT_FOUND.into_response();
    };
    if !state.app_registry.is_enabled(app_id).await {
        return (
            StatusCode::SERVICE_UNAVAILABLE,
            "This app is disabled. Start it again from the Apps page.",
        )
            .into_response();
    }

    let access_guard_enabled = state.app_registry.access_guard_enabled(app_id).await;
    let cookie_name = format!("ark_app_{}", app_id);
    let grant_from_query = if access_guard_enabled {
        extract_query_param(uri.query(), "grant")
    } else {
        None
    };
    let session_from_cookie = if access_guard_enabled {
        extract_cookie(&headers, &cookie_name)
    } else {
        None
    };
    let key_from_header = if access_guard_enabled {
        headers
            .get("x-agentark-app-key")
            .and_then(|value| value.to_str().ok())
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToString::to_string)
    } else {
        None
    };
    let is_ws_request = is_websocket_upgrade(&headers);

    if access_guard_enabled {
        let query_valid = match grant_from_query.as_deref() {
            Some(grant) => {
                state
                    .app_registry
                    .consume_access_bootstrap_grant(app_id, grant)
                    .await
            }
            None => false,
        };
        let cookie_valid = match session_from_cookie.as_deref() {
            Some(token) => {
                state
                    .app_registry
                    .validate_access_session(app_id, token)
                    .await
            }
            None => false,
        };
        let header_valid = match key_from_header.as_deref() {
            Some(key) => state.app_registry.verify_key(app_id, key).await,
            None => false,
        };

        if !query_valid && !cookie_valid && !header_valid {
            return app_access_denied_page(app_id);
        }

        // First successful key entry: set cookie and redirect to clean URL.
        if query_valid && !cookie_valid && !header_valid && method == Method::GET && !is_ws_request
        {
            if let Some(session_token) = state.app_registry.create_access_session(app_id).await {
                let request_proto = headers
                    .get("x-forwarded-proto")
                    .and_then(|v| v.to_str().ok())
                    .unwrap_or("http");
                let secure_attr = if request_proto.eq_ignore_ascii_case("https") {
                    "; Secure"
                } else {
                    ""
                };
                let cookie = format!(
                    "{}={}; Path=/apps/{}; HttpOnly; SameSite=Lax; Max-Age=604800{}",
                    cookie_name, session_token, app_id, secure_attr
                );
                let clean_query = strip_query_param(uri.query(), "grant");
                let clean_url = build_app_url(app_id, path, clean_query.as_deref());
                return Response::builder()
                    .status(StatusCode::FOUND)
                    .header(header::SET_COOKIE, cookie)
                    .header(header::LOCATION, clean_url)
                    .body(axum::body::Body::empty())
                    .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR.into_response());
            }
        }
    }

    let is_static = state.app_registry.is_static(app_id).await;

    state.app_registry.touch(app_id).await;
    let clean_query = if access_guard_enabled {
        strip_query_param(uri.query(), "grant")
    } else {
        uri.query().map(|q| q.to_string())
    };
    let normalized_path = path.trim_start_matches('/');
    if normalized_path.eq_ignore_ascii_case("__agentark/llm/chat") {
        if method != Method::POST {
            return StatusCode::METHOD_NOT_ALLOWED.into_response();
        }
        return app_scoped_llm_chat_proxy(state, app_id, &headers, body).await;
    }
    if normalized_path.eq_ignore_ascii_case("__agentark/arxiv/search") {
        if method != Method::GET {
            return StatusCode::METHOD_NOT_ALLOWED.into_response();
        }
        return app_scoped_arxiv_search_proxy(state, app_id, &headers, clean_query.as_deref())
            .await;
    }

    let body_bytes = if is_ws_request {
        None
    } else {
        Some(match axum::body::to_bytes(body, 64 * 1024 * 1024).await {
            Ok(bytes) => bytes,
            Err(_) => {
                return (StatusCode::PAYLOAD_TOO_LARGE, "Request body too large").into_response();
            }
        })
    };

    if should_proxy_app_request_to_executor(is_static, state.executor_client.is_some()) {
        if let Some(executor) = state.executor_client.as_ref() {
            let mut proxy_path = if normalized_path.is_empty() {
                format!("/internal/v1/apps/{}/proxy", app_id)
            } else {
                format!("/internal/v1/apps/{}/proxy/{}", app_id, normalized_path)
            };
            if let Some(q) = clean_query.as_deref().filter(|q| !q.is_empty()) {
                proxy_path.push('?');
                proxy_path.push_str(q);
            }
            if is_ws_request {
                if method != Method::GET {
                    return StatusCode::METHOD_NOT_ALLOWED.into_response();
                }

                let Some(ws_upgrade) = ws else {
                    return (StatusCode::BAD_REQUEST, "Invalid websocket upgrade request")
                        .into_response();
                };

                let upstream_url = format!(
                    "{}{}",
                    executor_websocket_base_url(executor.base_url()),
                    proxy_path
                );
                let requested_protocols = headers
                    .get("Sec-WebSocket-Protocol")
                    .and_then(|v| v.to_str().ok())
                    .map(|raw| {
                        raw.split(',')
                            .map(|s| s.trim())
                            .filter(|s| !s.is_empty())
                            .map(|s| s.to_string())
                            .collect::<Vec<String>>()
                    })
                    .unwrap_or_default();
                let mut ws_forward_headers: Vec<(String, String)> = Vec::new();
                if let Some(v) = headers.get(header::ORIGIN).and_then(|v| v.to_str().ok()) {
                    ws_forward_headers.push(("origin".to_string(), v.to_string()));
                }
                if let Some(v) = headers
                    .get(header::USER_AGENT)
                    .and_then(|v| v.to_str().ok())
                {
                    ws_forward_headers.push(("user-agent".to_string(), v.to_string()));
                }
                if let Some(v) = headers.get(header::HOST).and_then(|v| v.to_str().ok()) {
                    ws_forward_headers.push(("x-forwarded-host".to_string(), v.to_string()));
                }
                if let Some(token) = executor.bearer_token() {
                    ws_forward_headers
                        .push(("authorization".to_string(), format!("Bearer {}", token)));
                }
                let forwarded_proto = headers
                    .get("x-forwarded-proto")
                    .and_then(|v| v.to_str().ok())
                    .unwrap_or("http");
                ws_forward_headers
                    .push(("x-forwarded-proto".to_string(), forwarded_proto.to_string()));
                ws_forward_headers.push((
                    "x-forwarded-prefix".to_string(),
                    format!("/apps/{}", app_id),
                ));
                if let Some(raw_cookie) = headers.get(header::COOKIE).and_then(|v| v.to_str().ok())
                {
                    if let Some(filtered) = filter_proxy_cookie(raw_cookie, app_id) {
                        ws_forward_headers.push(("cookie".to_string(), filtered));
                    }
                }

                let ws_upgrade = if requested_protocols.is_empty() {
                    ws_upgrade
                } else {
                    ws_upgrade.protocols(requested_protocols.clone())
                };
                return ws_upgrade
                    .on_upgrade(move |socket| async move {
                        proxy_websocket_connection(
                            socket,
                            upstream_url,
                            requested_protocols,
                            ws_forward_headers,
                        )
                        .await;
                    })
                    .into_response();
            }

            let mut upstream = executor.request(
                reqwest::Method::from_bytes(method.as_str().as_bytes())
                    .unwrap_or(reqwest::Method::GET),
                &proxy_path,
            );
            for (name, value) in &headers {
                let lower = name.as_str().to_ascii_lowercase();
                if is_hop_by_hop_header(&lower)
                    || lower == "host"
                    || lower == "content-length"
                    || lower == "authorization"
                {
                    continue;
                }
                if lower == "cookie" {
                    if let Ok(raw_cookie) = value.to_str() {
                        if let Some(filtered) = filter_proxy_cookie(raw_cookie, app_id) {
                            upstream = upstream.header(header::COOKIE, filtered);
                        }
                    }
                    continue;
                }
                upstream = upstream.header(name, value);
            }
            if let Some(host) = headers.get(header::HOST).and_then(|v| v.to_str().ok()) {
                upstream = upstream.header("x-forwarded-host", host);
            }
            let forwarded_proto = headers
                .get("x-forwarded-proto")
                .and_then(|v| v.to_str().ok())
                .unwrap_or("http");
            upstream = upstream
                .header("x-forwarded-proto", forwarded_proto)
                .header("x-forwarded-prefix", format!("/apps/{}", app_id));
            upstream = upstream.body(body_bytes.clone().unwrap_or_default());

            match upstream.send().await {
                Ok(resp) => {
                    let status = StatusCode::from_u16(resp.status().as_u16())
                        .unwrap_or(StatusCode::BAD_GATEWAY);
                    let response_headers = resp.headers().clone();
                    match resp.bytes().await {
                        Ok(response_body) => {
                            let mut builder = Response::builder().status(status);
                            for (name, value) in &response_headers {
                                if !is_hop_by_hop_header(name.as_str()) {
                                    builder = builder.header(name, value);
                                }
                            }
                            let response_body = if method == Method::HEAD {
                                axum::body::Body::empty()
                            } else {
                                axum::body::Body::from(response_body)
                            };
                            return builder
                                .body(response_body)
                                .unwrap_or(StatusCode::BAD_GATEWAY.into_response());
                        }
                        Err(_) => return StatusCode::BAD_GATEWAY.into_response(),
                    }
                }
                Err(error) => {
                    tracing::warn!(
                        "Executor proxy failed for app {} on path '{}': {}",
                        app_id,
                        proxy_path,
                        error
                    );
                }
            }
        }
    }

    if let Some(port) = state.app_registry.get_port(app_id).await {
        if is_ws_request {
            if method != Method::GET {
                return StatusCode::METHOD_NOT_ALLOWED.into_response();
            }

            let Some(ws_upgrade) = ws else {
                return (StatusCode::BAD_REQUEST, "Invalid websocket upgrade request")
                    .into_response();
            };

            let upstream_path = path.trim_start_matches('/');
            let mut upstream_url = if upstream_path.is_empty() {
                format!("ws://127.0.0.1:{}/", port)
            } else {
                format!("ws://127.0.0.1:{}/{}", port, upstream_path)
            };
            if let Some(q) = clean_query.as_deref().filter(|q| !q.is_empty()) {
                upstream_url.push('?');
                upstream_url.push_str(q);
            }

            let requested_protocols = headers
                .get("Sec-WebSocket-Protocol")
                .and_then(|v| v.to_str().ok())
                .map(|raw| {
                    raw.split(',')
                        .map(|s| s.trim())
                        .filter(|s| !s.is_empty())
                        .map(|s| s.to_string())
                        .collect::<Vec<String>>()
                })
                .unwrap_or_default();
            let mut ws_forward_headers: Vec<(String, String)> = Vec::new();
            if let Some(v) = headers.get(header::ORIGIN).and_then(|v| v.to_str().ok()) {
                ws_forward_headers.push(("origin".to_string(), v.to_string()));
            }
            if let Some(v) = headers
                .get(header::USER_AGENT)
                .and_then(|v| v.to_str().ok())
            {
                ws_forward_headers.push(("user-agent".to_string(), v.to_string()));
            }
            if let Some(v) = headers.get(header::HOST).and_then(|v| v.to_str().ok()) {
                ws_forward_headers.push(("x-forwarded-host".to_string(), v.to_string()));
            }
            let forwarded_proto = headers
                .get("x-forwarded-proto")
                .and_then(|v| v.to_str().ok())
                .unwrap_or("http");
            ws_forward_headers.push(("x-forwarded-proto".to_string(), forwarded_proto.to_string()));
            ws_forward_headers.push((
                "x-forwarded-prefix".to_string(),
                format!("/apps/{}", app_id),
            ));
            if let Some(raw_cookie) = headers.get(header::COOKIE).and_then(|v| v.to_str().ok()) {
                if let Some(filtered) = filter_proxy_cookie(raw_cookie, app_id) {
                    ws_forward_headers.push(("cookie".to_string(), filtered));
                }
            }

            let ws_upgrade = if requested_protocols.is_empty() {
                ws_upgrade
            } else {
                ws_upgrade.protocols(requested_protocols.clone())
            };
            return ws_upgrade
                .on_upgrade(move |socket| async move {
                    proxy_websocket_connection(
                        socket,
                        upstream_url,
                        requested_protocols,
                        ws_forward_headers,
                    )
                    .await;
                })
                .into_response();
        }

        let upstream_path = path.trim_start_matches('/');
        let mut target_url = if upstream_path.is_empty() {
            format!("http://127.0.0.1:{}/", port)
        } else {
            format!("http://127.0.0.1:{}/{}", port, upstream_path)
        };
        if let Some(q) = clean_query.as_deref().filter(|q| !q.is_empty()) {
            target_url.push('?');
            target_url.push_str(q);
        }

        let client = reqwest::Client::new();
        let mut upstream = client.request(method.clone(), &target_url);
        for (name, value) in &headers {
            let lower = name.as_str().to_ascii_lowercase();
            if is_hop_by_hop_header(&lower)
                || lower == "host"
                || lower == "content-length"
                || lower == "authorization"
            {
                continue;
            }
            if lower == "cookie" {
                if let Ok(raw_cookie) = value.to_str() {
                    if let Some(filtered) = filter_proxy_cookie(raw_cookie, app_id) {
                        upstream = upstream.header(header::COOKIE, filtered);
                    }
                }
                continue;
            }
            upstream = upstream.header(name, value);
        }
        if let Some(host) = headers.get(header::HOST).and_then(|v| v.to_str().ok()) {
            upstream = upstream.header("x-forwarded-host", host);
        }
        let forwarded_proto = headers
            .get("x-forwarded-proto")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("http");
        upstream = upstream
            .header("x-forwarded-proto", forwarded_proto)
            .header("x-forwarded-prefix", format!("/apps/{}", app_id))
            .body(body_bytes.unwrap_or_default());

        match upstream.send().await {
            Ok(resp) => {
                let status =
                    StatusCode::from_u16(resp.status().as_u16()).unwrap_or(StatusCode::BAD_GATEWAY);
                let response_headers = resp.headers().clone();
                match resp.bytes().await {
                    Ok(response_body) => {
                        let mut builder = Response::builder().status(status);
                        for (name, value) in &response_headers {
                            if !is_hop_by_hop_header(name.as_str()) {
                                builder = builder.header(name, value);
                            }
                        }
                        let response_body = if method == Method::HEAD {
                            axum::body::Body::empty()
                        } else {
                            axum::body::Body::from(response_body)
                        };
                        builder
                            .body(response_body)
                            .unwrap_or(StatusCode::BAD_GATEWAY.into_response())
                    }
                    Err(_) => StatusCode::BAD_GATEWAY.into_response(),
                }
            }
            Err(_) => {
                (StatusCode::SERVICE_UNAVAILABLE, "App server not responding").into_response()
            }
        }
    } else if is_static {
        if method != Method::GET && method != Method::HEAD {
            return StatusCode::METHOD_NOT_ALLOWED.into_response();
        }

        let relative_path = path.trim_start_matches('/');
        let relative_path = if relative_path.is_empty() {
            "index.html"
        } else {
            relative_path
        };
        if relative_path.contains('\0') {
            return StatusCode::BAD_REQUEST.into_response();
        }

        let app_root = match tokio::fs::canonicalize(&app_dir).await {
            Ok(path) => path,
            Err(_) => return StatusCode::NOT_FOUND.into_response(),
        };

        let mut canonical_file = match tokio::fs::canonicalize(app_dir.join(relative_path)).await {
            Ok(path) => path,
            Err(_) => return StatusCode::NOT_FOUND.into_response(),
        };
        if !canonical_file.starts_with(&app_root) {
            return StatusCode::FORBIDDEN.into_response();
        }

        if tokio::fs::metadata(&canonical_file)
            .await
            .map(|m| m.is_dir())
            .unwrap_or(false)
        {
            let index_path = canonical_file.join("index.html");
            let index_canonical = match tokio::fs::canonicalize(index_path).await {
                Ok(path) => path,
                Err(_) => return StatusCode::NOT_FOUND.into_response(),
            };
            if !index_canonical.starts_with(&app_root) {
                return StatusCode::FORBIDDEN.into_response();
            }
            canonical_file = index_canonical;
        }

        match tokio::fs::read(&canonical_file).await {
            Ok(bytes) => {
                let filename = canonical_file
                    .file_name()
                    .and_then(|n| n.to_str())
                    .unwrap_or("index.html");
                let content_type = guess_content_type(filename);
                let mut response_bytes = bytes;
                if should_upgrade_insecure_links(&content_type) {
                    let mut rewritten = String::from_utf8_lossy(&response_bytes).into_owned();
                    rewritten = rewrite_external_proxy_urls_for_public_apps(&rewritten);
                    if content_type.to_ascii_lowercase().starts_with("text/html") {
                        rewritten = inject_app_runtime_fetch_shims(&rewritten, app_id);
                    }
                    if is_secure_origin_request(&headers) {
                        rewritten = upgrade_http_links_for_secure_origin(&rewritten);
                    }
                    response_bytes = rewritten.into_bytes();
                }
                if method == Method::HEAD {
                    (
                        StatusCode::OK,
                        [
                            (header::CONTENT_TYPE, content_type),
                            (header::CACHE_CONTROL, "no-store".to_string()),
                        ],
                        Vec::<u8>::new(),
                    )
                        .into_response()
                } else {
                    (
                        StatusCode::OK,
                        [
                            (header::CONTENT_TYPE, content_type),
                            (header::CACHE_CONTROL, "no-store".to_string()),
                        ],
                        response_bytes,
                    )
                        .into_response()
                }
            }
            Err(_) => StatusCode::NOT_FOUND.into_response(),
        }
    } else {
        StatusCode::NOT_FOUND.into_response()
    }
}

/// Access denied page for apps with invalid/missing access key
fn app_access_denied_page(app_id: &str) -> Response {
    let html = format!(
        r#"<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Access Key Required</title>
<style>
*{{margin:0;padding:0;box-sizing:border-box}}
body{{display:flex;justify-content:center;align-items:center;min-height:100vh;font-family:system-ui,-apple-system,sans-serif;background:#0f0f1a;color:#e0e0e0}}
.card{{background:#1a1a2e;border:1px solid #2a2a3e;border-radius:16px;padding:40px;max-width:400px;width:90%;text-align:center}}
h2{{margin-bottom:8px;font-size:1.4em}}
p{{color:#888;margin-bottom:24px;font-size:0.95em}}
input{{width:100%;padding:12px 16px;border-radius:8px;border:1px solid #333;background:#12121e;color:#fff;font-size:1em;outline:none;transition:border 0.2s}}
input:focus{{border-color:#7c3aed}}
button{{margin-top:16px;width:100%;padding:12px;border-radius:8px;border:none;background:#7c3aed;color:#fff;font-size:1em;cursor:pointer;transition:background 0.2s}}
button:hover{{background:#6d28d9}}
</style></head>
<body><div class="card">
<h2>Access Key Required</h2>
<p>This app is protected. Enter the access key to continue.</p>
<form method="GET" action="/apps/{app_id}/">
<input type="text" name="key" placeholder="Enter access key" autofocus required>
<button type="submit">Unlock</button>
</form>
</div></body></html>"#,
        app_id = app_id
    );
    Html(html).into_response()
}

#[derive(Debug, Deserialize)]
struct AppAccessGuardUpdateRequest {
    enabled: bool,
    #[serde(default)]
    regenerate_key: bool,
}

/// Disable an app and stop its runtime if it has one.
async fn stop_app(State(state): State<AppState>, Path(app_id): Path<String>) -> Response {
    if !is_valid_app_id(&app_id) {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({ "error": "Invalid app_id" })),
        )
            .into_response();
    }
    if state.app_registry.get_dir(&app_id).await.is_none() {
        return (
            StatusCode::NOT_FOUND,
            Json(serde_json::json!({ "error": "App not found" })),
        )
            .into_response();
    }
    let is_static = state.app_registry.is_static(&app_id).await;
    let stop_result = if is_static {
        Ok(())
    } else if let Some(executor) = state.executor_client.as_ref() {
        executor
            .request(
                reqwest::Method::POST,
                &format!("/internal/v1/apps/{}/stop", app_id),
            )
            .json(&crate::clients::AppLifecycleRequest {
                title: None,
                query: None,
            })
            .send()
            .await
            .and_then(reqwest::Response::error_for_status)
            .map(|_| ())
            .map_err(anyhow::Error::from)
    } else {
        state.app_registry.stop_runtime(&app_id).await
    };
    match stop_result {
        Ok(_) => match state.app_registry.set_enabled(&app_id, false).await {
            Ok(_) => {
                trigger_arkpulse_after_app_change(&state, "app_disable").await;
                (
                    StatusCode::OK,
                    Json(serde_json::json!({ "status": "disabled", "app_id": app_id })),
                )
                    .into_response()
            }
            Err(error) => (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(serde_json::json!({ "error": error.to_string() })),
            )
                .into_response(),
        },
        Err(e) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(serde_json::json!({ "error": e.to_string() })),
        )
            .into_response(),
    }
}

async fn update_app_access_guard(
    State(state): State<AppState>,
    Path(app_id): Path<String>,
    Json(request): Json<AppAccessGuardUpdateRequest>,
) -> Response {
    if !is_valid_app_id(&app_id) {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({ "error": "Invalid app_id" })),
        )
            .into_response();
    }

    match state
        .app_registry
        .set_access_guard(&app_id, request.enabled, request.regenerate_key)
        .await
    {
        Ok(access_key) => {
            trigger_arkpulse_after_app_change(&state, "app_access_guard_update").await;
            let access_url = app_access_url_for_state(&state, &app_id, request.enabled).await;
            (
                StatusCode::OK,
                Json(serde_json::json!({
                    "status": "ok",
                    "app_id": app_id,
                    "access_guard_enabled": request.enabled,
                    "access_key": if request.enabled { access_key } else { String::new() },
                    "access_url": access_url,
                })),
            )
                .into_response()
        }
        Err(e) => {
            let status = if e.to_string() == "App not found" {
                StatusCode::NOT_FOUND
            } else {
                StatusCode::INTERNAL_SERVER_ERROR
            };
            (status, Json(serde_json::json!({ "error": e.to_string() }))).into_response()
        }
    }
}

/// Restart an app from saved metadata
async fn restart_app(State(state): State<AppState>, Path(app_id): Path<String>) -> Response {
    if !is_valid_app_id(&app_id) {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({ "error": "Invalid app_id" })),
        )
            .into_response();
    }

    let app_dir = if let Some(path) = state.app_registry.get_dir(&app_id).await {
        path
    } else {
        let data_dir = {
            let agent = state.agent.read().await;
            agent.data_dir().to_path_buf()
        };
        let fallback = data_dir.join("apps").join(&app_id);
        if !fallback.exists() {
            return (
                StatusCode::NOT_FOUND,
                Json(serde_json::json!({ "error": "App not found" })),
            )
                .into_response();
        }
        fallback
    };

    if let Some(executor) = state.executor_client.as_ref() {
        match executor
            .request(
                reqwest::Method::POST,
                &format!("/internal/v1/apps/{}/restart", app_id),
            )
            .json(&crate::clients::AppLifecycleRequest {
                title: None,
                query: None,
            })
            .send()
            .await
        {
            Ok(response) => {
                let status = response.status();
                let payload = response
                    .json::<serde_json::Value>()
                    .await
                    .unwrap_or_else(|_| serde_json::json!({}));
                if !status.is_success() {
                    return (
                        StatusCode::from_u16(status.as_u16())
                            .unwrap_or(StatusCode::BAD_GATEWAY),
                        Json(serde_json::json!({
                            "error": payload.get("message").and_then(|value| value.as_str()).unwrap_or("Failed to restart app"),
                            "details": payload
                        })),
                    )
                        .into_response();
                }
                let _ = state.app_registry.set_enabled(&app_id, true).await;
                trigger_arkpulse_after_app_change(&state, "app_restart").await;
                let raw = payload
                    .get("raw")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!({}));
                let title = raw
                    .get("title")
                    .and_then(|value| value.as_str())
                    .unwrap_or(&app_id);
                let access_guard_enabled = raw
                    .get("access_guard_enabled")
                    .and_then(|value| value.as_bool())
                    .unwrap_or(false);
                let app_url =
                    build_absolute_app_url(state.public_app_base_url.as_deref(), &app_id, "", None);
                let app_access_url =
                    app_access_url_for_state(&state, &app_id, access_guard_enabled).await;
                return Json(serde_json::json!({
                    "status": "restarted",
                    "type": raw.get("mode").cloned().unwrap_or_else(|| serde_json::json!("dynamic")),
                    "app_id": app_id,
                    "title": title,
                    "url": app_url,
                    "access_url": app_access_url,
                    "access_guard_enabled": access_guard_enabled,
                    "port": raw.get("port").cloned().unwrap_or(serde_json::Value::Null),
                    "runtime_preference": raw.get("runtime_mode").cloned().unwrap_or_else(|| serde_json::json!("executor")),
                    "details": payload,
                }))
                .into_response();
            }
            Err(error) => {
                return (
                    StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({
                        "error": format!("Failed to restart app through executor: {}", error)
                    })),
                )
                    .into_response();
            }
        }
    }

    let meta_path = app_dir.join(".app_meta.json");
    let mut meta: serde_json::Value = match tokio::fs::read(&meta_path).await {
        Ok(bytes) => serde_json::from_slice(&bytes).unwrap_or(serde_json::json!({})),
        Err(_) => serde_json::json!({}),
    };
    if !meta.is_object() {
        meta = serde_json::json!({});
    }

    let title = meta
        .get("title")
        .and_then(|v| v.as_str())
        .unwrap_or(&app_id)
        .to_string();
    let entry_command = meta
        .get("entry_command")
        .and_then(|v| v.as_str())
        .map(|s| s.to_string());
    let install_command = meta
        .get("install_command")
        .and_then(|v| v.as_str())
        .map(|s| s.to_string());
    let runtime_image = meta
        .get("runtime_image")
        .and_then(|v| v.as_str())
        .map(|s| s.to_string());
    let runtime_preference = crate::actions::app::runtime_preference_from_opt(
        meta.get("runtime_preference").and_then(|v| v.as_str()),
    );
    let required_inputs = crate::actions::app::parse_required_inputs(&meta);
    let config_values: std::collections::HashMap<String, String> = meta
        .get("config_values")
        .and_then(|v| v.as_object())
        .map(|obj| {
            obj.iter()
                .filter_map(|(k, v)| {
                    let value = match v {
                        serde_json::Value::String(s) => s.clone(),
                        serde_json::Value::Bool(b) => b.to_string(),
                        serde_json::Value::Number(n) => n.to_string(),
                        _ => return None,
                    };
                    Some((k.clone(), value))
                })
                .collect()
        })
        .unwrap_or_default();
    let access_guard_enabled = meta
        .get("access_guard_enabled")
        .and_then(|v| v.as_bool())
        .unwrap_or(false);
    let access_key = if access_guard_enabled {
        state
            .app_registry
            .access_key(&app_id)
            .await
            .unwrap_or_else(crate::actions::app::generate_access_key)
    } else {
        String::new()
    };

    if meta.get("access_guard_enabled").is_none() || meta.get("access_key").is_some() {
        meta["access_guard_enabled"] = serde_json::Value::Bool(access_guard_enabled);
        if let Some(obj) = meta.as_object_mut() {
            obj.remove("access_key");
        }
        let _ = tokio::fs::write(
            &meta_path,
            serde_json::to_vec_pretty(&meta).unwrap_or_default(),
        )
        .await;
    }
    if meta.get("enabled").and_then(|v| v.as_bool()) != Some(true) {
        meta["enabled"] = serde_json::Value::Bool(true);
        let _ = tokio::fs::write(
            &meta_path,
            serde_json::to_vec_pretty(&meta).unwrap_or_default(),
        )
        .await;
    }
    let _ = state.app_registry.set_enabled(&app_id, true).await;

    if let Err(e) = state.app_registry.stop_runtime(&app_id).await {
        return (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(serde_json::json!({ "error": format!("Failed to stop running app before restart: {}", e) })),
        )
            .into_response();
    }

    if let Some(entry_command) = entry_command {
        let Some(port) = state.app_registry.find_available_port().await else {
            return (
                StatusCode::SERVICE_UNAVAILABLE,
                Json(serde_json::json!({ "error": "No available app port" })),
            )
                .into_response();
        };

        let (config_dir, data_dir, llm_env) = {
            let agent = state.agent.read().await;
            (
                agent.config_dir.clone(),
                agent.data_dir().to_path_buf(),
                agent.app_model_env_vars(),
            )
        };
        let (resolved_env, missing_sensitive, missing_config) =
            match crate::actions::app::resolve_required_env_values(
                &config_dir,
                &data_dir,
                &required_inputs,
                &llm_env,
                &config_values,
            )
            .await
            {
                Ok(v) => v,
                Err(e) => {
                    return (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    Json(serde_json::json!({ "error": format!("Failed to resolve app secrets: {}", e) })),
                )
                    .into_response();
                }
            };
        if !missing_sensitive.is_empty() || !missing_config.is_empty() {
            let mut missing_all = missing_sensitive.clone();
            for m in &missing_config {
                if !missing_all.iter().any(|x| x == m) {
                    missing_all.push(m.clone());
                }
            }
            let required_secret_keys: Vec<String> = required_inputs
                .iter()
                .filter(|r| r.sensitive)
                .map(|r| r.key.clone())
                .collect();
            let required_config_keys: Vec<String> = required_inputs
                .iter()
                .filter(|r| !r.sensitive)
                .map(|r| r.key.clone())
                .collect();
            return (
                StatusCode::CONFLICT,
                Json(serde_json::json!({
                    "status": "needs_secrets",
                    "app_id": app_id,
                    "missing_env": missing_sensitive,
                    "missing_config": missing_config,
                    "missing_inputs": missing_all,
                    "required_inputs": required_inputs,
                    "required_secrets": required_secret_keys.clone(),
                    "required_env": required_secret_keys,
                    "required_config": required_config_keys,
                    "message": "Missing required inputs. Use /setsecret KEY=VALUE for sensitive values; provide config for non-sensitive values."
                })),
            )
                .into_response();
        }

        match crate::actions::app::launch_dynamic_runtime(
            crate::actions::app::DynamicRuntimeLaunch {
                app_id: &app_id,
                app_dir: &app_dir,
                entry_command: &entry_command,
                install_command: install_command.as_deref(),
                port,
                extra_env: &resolved_env,
                runtime_image: runtime_image.as_deref(),
                runtime_preference,
                stream_tx: None,
            },
        )
        .await
        {
            Ok(runtime_handle) => {
                let (child, container_id) = match runtime_handle {
                    crate::actions::app::DynamicRuntimeHandle::Container(container_id) => {
                        (None, Some(container_id))
                    }
                    crate::actions::app::DynamicRuntimeHandle::Process(child) => {
                        (Some(*child), None)
                    }
                };
                let app_dir_for_diagnostics = app_dir.clone();
                state
                    .app_registry
                    .register_dynamic(
                        app_id.clone(),
                        crate::actions::app::DynamicAppRegistration {
                            title: title.clone(),
                            app_dir,
                            child,
                            container_id,
                            port,
                            access_key: access_key.clone(),
                            access_guard_enabled,
                            enabled: true,
                            last_accessed: None,
                        },
                    )
                    .await;
                tokio::time::sleep(std::time::Duration::from_secs(2)).await;
                if !state.app_registry.runtime_is_alive(&app_id).await {
                    let logs = crate::actions::app::read_local_runtime_log_tail(
                        &app_dir_for_diagnostics,
                        4096,
                    )
                    .await;
                    let detail = if logs.is_empty() {
                        "App process stopped shortly after restart.".to_string()
                    } else {
                        format!(
                            "App process stopped shortly after restart. Recent runtime logs:\n{}",
                            logs
                        )
                    };
                    return (
                        StatusCode::BAD_GATEWAY,
                        Json(serde_json::json!({ "error": detail })),
                    )
                        .into_response();
                }
                trigger_arkpulse_after_app_change(&state, "app_restart").await;
                let app_url =
                    build_absolute_app_url(state.public_app_base_url.as_deref(), &app_id, "", None);
                let app_access_url =
                    app_access_url_for_state(&state, &app_id, access_guard_enabled).await;
                Json(serde_json::json!({
                    "status": "restarted",
                    "type": "dynamic",
                    "app_id": app_id,
                    "title": title,
                    "url": app_url,
                    "access_url": app_access_url,
                    "access_guard_enabled": access_guard_enabled,
                    "port": port,
                    "runtime_preference": runtime_preference.as_str(),
                }))
                .into_response()
            }
            Err(error) => (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(serde_json::json!({ "error": format!("Failed to restart app: {}", error) })),
            )
                .into_response(),
        }
    } else {
        state
            .app_registry
            .register_stored(
                app_id.clone(),
                crate::actions::app::StoredAppRegistration {
                    title: title.clone(),
                    app_dir,
                    is_static: true,
                    access_key: access_key.clone(),
                    access_guard_enabled,
                    enabled: true,
                    last_accessed: None,
                },
            )
            .await;
        trigger_arkpulse_after_app_change(&state, "app_restart").await;
        let app_url =
            build_absolute_app_url(state.public_app_base_url.as_deref(), &app_id, "", None);
        let app_access_url = app_access_url_for_state(&state, &app_id, access_guard_enabled).await;
        Json(serde_json::json!({
            "status": "restarted",
            "type": "static",
            "app_id": app_id,
            "title": title,
            "url": app_url,
            "access_url": app_access_url,
            "access_guard_enabled": access_guard_enabled,
            "runtime_preference": runtime_preference.as_str(),
        }))
        .into_response()
    }
}

/// Stop and delete an app from disk
async fn delete_app(State(state): State<AppState>, Path(app_id): Path<String>) -> Response {
    if !is_valid_app_id(&app_id) {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({ "error": "Invalid app_id" })),
        )
            .into_response();
    }

    let app_title: Option<String> = {
        let apps = state.app_registry.list().await;
        apps.iter()
            .find(|row| row.get("id").and_then(|v| v.as_str()) == Some(app_id.as_str()))
            .and_then(|row| row.get("title").and_then(|v| v.as_str()))
            .map(|s| s.to_string())
    };

    let app_dir = if let Some(path) = state.app_registry.get_dir(&app_id).await {
        path
    } else {
        let data_dir = {
            let agent = state.agent.read().await;
            agent.data_dir().to_path_buf()
        };
        let fallback = data_dir.join("apps").join(&app_id);
        if !fallback.exists() {
            return (
                StatusCode::NOT_FOUND,
                Json(serde_json::json!({ "error": "App not found" })),
            )
                .into_response();
        }
        fallback
    };

    let mut executor_deleted_files = false;
    if let Some(executor) = state.executor_client.as_ref() {
        match executor
            .request(
                reqwest::Method::DELETE,
                &format!("/internal/v1/apps/{}", app_id),
            )
            .send()
            .await
        {
            Ok(response) if response.status().is_success() => {
                executor_deleted_files = true;
            }
            Ok(response) => {
                let status = StatusCode::from_u16(response.status().as_u16())
                    .unwrap_or(StatusCode::BAD_GATEWAY);
                let payload = response
                    .json::<serde_json::Value>()
                    .await
                    .unwrap_or_else(|_| serde_json::json!({}));
                return (
                    status,
                    Json(serde_json::json!({
                        "error": payload.get("message").and_then(|value| value.as_str()).unwrap_or("Failed to stop app before delete"),
                        "details": payload
                    })),
                )
                    .into_response();
            }
            Err(error) => {
                return (
                    StatusCode::BAD_GATEWAY,
                    Json(serde_json::json!({
                        "error": format!("Failed to contact executor before delete: {}", error)
                    })),
                )
                    .into_response();
            }
        }
    } else if let Err(e) = state.app_registry.stop(&app_id).await {
        return (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(
                serde_json::json!({ "error": format!("Failed to stop app before delete: {}", e) }),
            ),
        )
            .into_response();
    }
    match tokio::fs::remove_dir_all(&app_dir).await {
        Ok(_) => {
            let _ = state.app_registry.stop(&app_id).await;
            trigger_arkpulse_after_app_change(&state, "app_delete").await;
            let deleted_notifications = {
                let agent = state.agent.read().await;
                agent
                    .storage
                    .delete_app_notifications(&app_id, app_title.as_deref())
                    .await
                    .unwrap_or(0)
            };
            Json(serde_json::json!({
                "status": "deleted",
                "app_id": app_id,
                "deleted_notifications": deleted_notifications
            }))
            .into_response()
        }
        Err(error) if executor_deleted_files && error.kind() == std::io::ErrorKind::NotFound => {
            let _ = state.app_registry.stop(&app_id).await;
            trigger_arkpulse_after_app_change(&state, "app_delete").await;
            let deleted_notifications = {
                let agent = state.agent.read().await;
                agent
                    .storage
                    .delete_app_notifications(&app_id, app_title.as_deref())
                    .await
                    .unwrap_or(0)
            };
            Json(serde_json::json!({
                "status": "deleted",
                "app_id": app_id,
                "deleted_notifications": deleted_notifications
            }))
            .into_response()
        }
        Err(error) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(serde_json::json!({ "error": format!("Failed to delete app files: {}", error) })),
        )
            .into_response(),
    }
}

/// Upload a file for use in chat (attachments for code execution, analysis, etc.)
async fn upload_chat_file(State(state): State<AppState>, mut multipart: Multipart) -> Response {
    let (data_dir, storage) = {
        let agent = state.agent.read().await;
        (agent.data_dir().to_path_buf(), agent.storage.clone())
    };
    let uploads_dir = data_dir.join("uploads");

    let mut uploaded_files = Vec::new();

    while let Ok(Some(field)) = multipart.next_field().await {
        let original_name: String = field.file_name().unwrap_or("unnamed").to_string();
        let content_type = field.content_type().map(|value| value.to_string());

        // Sanitize filename: keep only safe characters
        let safe_name: String = original_name
            .chars()
            .map(|c: char| {
                if c.is_alphanumeric() || c == '.' || c == '-' || c == '_' {
                    c
                } else {
                    '_'
                }
            })
            .collect();

        // Prevent path traversal
        if safe_name.contains("..") || safe_name.starts_with('.') {
            return (StatusCode::BAD_REQUEST, "Invalid filename").into_response();
        }

        match field.bytes().await {
            Ok(data) => {
                // 50MB limit per file
                if data.len() > 50 * 1024 * 1024 {
                    return (StatusCode::PAYLOAD_TOO_LARGE, "File too large (50MB max)")
                        .into_response();
                }

                if let Err(e) = tokio::fs::create_dir_all(&uploads_dir).await {
                    tracing::error!("Failed to create uploads dir: {}", e);
                    return StatusCode::INTERNAL_SERVER_ERROR.into_response();
                }

                let upload_id = uuid::Uuid::new_v4().to_string();
                let stored_name = format!("{}__{}", upload_id, safe_name);
                let file_path = uploads_dir.join(&stored_name);
                if let Err(e) = tokio::fs::write(&file_path, &data).await {
                    tracing::error!("Failed to write upload: {}", e);
                    return StatusCode::INTERNAL_SERVER_ERROR.into_response();
                }

                let manifest = crate::storage::UploadManifest {
                    id: upload_id.clone(),
                    original_name: safe_name.clone(),
                    stored_name,
                    content_type,
                    size_bytes: data.len() as u64,
                    created_at: chrono::Utc::now().to_rfc3339(),
                };
                if let Err(error) = storage.save_upload_manifest(&manifest).await {
                    let _ = tokio::fs::remove_file(&file_path).await;
                    tracing::error!("Failed to persist upload manifest: {}", error);
                    return StatusCode::INTERNAL_SERVER_ERROR.into_response();
                }
                if let Some(workspace) = state.workspace_client.as_ref() {
                    if let Err(error) = workspace
                        .put_blob(&format!("uploads/{}", manifest.stored_name), &data)
                        .await
                    {
                        tracing::warn!(
                            "Failed to mirror upload {} to workspace service: {}",
                            manifest.id,
                            error
                        );
                    }
                }

                tracing::info!("File uploaded: {} ({} bytes)", safe_name, data.len());
                uploaded_files.push(serde_json::json!({
                    "id": upload_id,
                    "name": safe_name,
                    "size": data.len(),
                    "path": format!("/api/uploads/{}", manifest.id),
                }));
            }
            Err(e) => {
                tracing::error!("Failed to read upload field: {}", e);
                return StatusCode::BAD_REQUEST.into_response();
            }
        }
    }

    if uploaded_files.is_empty() {
        return (StatusCode::BAD_REQUEST, "No files uploaded").into_response();
    }

    Json(serde_json::json!({ "files": uploaded_files })).into_response()
}

/// Serve uploaded files (for preview/download in chat)
async fn serve_upload_file(
    State(state): State<AppState>,
    Path(upload_id): Path<String>,
) -> Response {
    let normalized_id = match uuid::Uuid::parse_str(upload_id.trim()) {
        Ok(value) => value.to_string(),
        Err(_) => return StatusCode::BAD_REQUEST.into_response(),
    };

    let (data_dir, storage) = {
        let agent = state.agent.read().await;
        (agent.data_dir().to_path_buf(), agent.storage.clone())
    };
    let manifest = match storage.load_upload_manifest(&normalized_id).await {
        Ok(Some(value)) => value,
        Ok(None) => return StatusCode::NOT_FOUND.into_response(),
        Err(error) => {
            tracing::error!(
                "Failed to load upload manifest {}: {}",
                normalized_id,
                error
            );
            return StatusCode::INTERNAL_SERVER_ERROR.into_response();
        }
    };

    let uploads_dir = data_dir.join("uploads");
    let mut bytes = if let Ok(uploads_root) = tokio::fs::canonicalize(&uploads_dir).await {
        match tokio::fs::canonicalize(uploads_root.join(&manifest.stored_name)).await {
            Ok(file_path) if file_path.starts_with(&uploads_root) => {
                tokio::fs::read(&file_path).await.ok()
            }
            Ok(_) => return StatusCode::BAD_REQUEST.into_response(),
            Err(_) => None,
        }
    } else {
        None
    };
    if bytes.is_none() {
        if let Some(workspace) = state.workspace_client.as_ref() {
            bytes = workspace
                .get_blob(&format!("uploads/{}", manifest.stored_name))
                .await
                .ok();
        }
    }

    match bytes {
        Some(bytes) => {
            let content_type = manifest
                .content_type
                .clone()
                .unwrap_or_else(|| guess_content_type(&manifest.original_name));
            let safe_filename = sanitize_content_disposition_filename(&manifest.original_name);
            (
                [
                    (header::CONTENT_TYPE, content_type.as_str()),
                    (
                        header::CONTENT_DISPOSITION,
                        &format!("inline; filename=\"{}\"", safe_filename),
                    ),
                ],
                bytes,
            )
                .into_response()
        }
        None => StatusCode::NOT_FOUND.into_response(),
    }
}

/// Health check endpoint
fn heartbeat_recent_with_threshold(value: Option<&str>, max_age_secs: i64) -> bool {
    value
        .and_then(parse_utc_rfc3339)
        .map(|ts| (chrono::Utc::now() - ts).num_seconds() <= max_age_secs)
        .unwrap_or(false)
}

async fn build_runtime_health_payload(
    state: &AppState,
    readiness_mode: bool,
) -> (StatusCode, serde_json::Value) {
    let storage = { state.agent.read().await.storage.clone() };
    let storage_ok = storage.get("__health_probe").await.is_ok();
    let expected_migration_version = storage.expected_migration_version();
    let migration_version = storage.latest_migration_version().await.ok().flatten();
    let migration_tracked = migration_version.is_some();
    let table_names = storage.database_table_names().await.ok();
    let database_size_bytes = storage.database_size_bytes().await.ok().flatten();
    let lease_status = storage
        .lease_status_summary()
        .await
        .ok()
        .unwrap_or_default();
    let housekeeping = storage.housekeeping_status().await.ok().unwrap_or_default();
    let required_tables = [
        "approval_log",
        "automation_runs",
        "automation_supervisor_states",
        "conversations",
        "execution_runs",
        "kv_store",
        "messages",
        "notifications",
        "run_checkpoints",
        "tasks",
        "tool_attempts",
        "watchers",
    ];
    let missing_tables = table_names
        .as_ref()
        .map(|tables| {
            let set = tables.iter().cloned().collect::<HashSet<_>>();
            required_tables
                .iter()
                .filter(|table| !set.contains(**table))
                .map(|table| (*table).to_string())
                .collect::<Vec<_>>()
        })
        .unwrap_or_else(|| {
            required_tables
                .iter()
                .map(|table| (*table).to_string())
                .collect()
        });
    let schema_ok = missing_tables.is_empty();
    let migration_current = migration_version
        .map(|value| value == expected_migration_version)
        .unwrap_or(schema_ok);

    let scheduler_heartbeat = storage
        .get(crate::sentinel::SENTINEL_SCHEDULER_HEARTBEAT_KEY)
        .await
        .ok()
        .flatten()
        .and_then(|raw| String::from_utf8(raw).ok());
    let watcher_heartbeat = storage
        .get(crate::sentinel::SENTINEL_WATCHER_HEARTBEAT_KEY)
        .await
        .ok()
        .flatten()
        .and_then(|raw| String::from_utf8(raw).ok());
    let integration_sync_heartbeat = storage
        .get(crate::sentinel::SENTINEL_INTEGRATION_SYNC_HEARTBEAT_KEY)
        .await
        .ok()
        .flatten()
        .and_then(|raw| String::from_utf8(raw).ok());
    let consolidation_heartbeat = storage
        .get(crate::sentinel::SENTINEL_CONSOLIDATION_HEARTBEAT_KEY)
        .await
        .ok()
        .flatten()
        .and_then(|raw| String::from_utf8(raw).ok());
    let approval_expiry_heartbeat = storage
        .get(crate::sentinel::SENTINEL_APPROVAL_EXPIRY_HEARTBEAT_KEY)
        .await
        .ok()
        .flatten()
        .and_then(|raw| String::from_utf8(raw).ok());
    let arkpulse_heartbeat = storage
        .get(crate::sentinel::SENTINEL_ARKPULSE_HEARTBEAT_KEY)
        .await
        .ok()
        .flatten()
        .and_then(|raw| String::from_utf8(raw).ok());
    let auto_analysis_heartbeat = storage
        .get(crate::sentinel::SENTINEL_AUTO_ANALYSIS_HEARTBEAT_KEY)
        .await
        .ok()
        .flatten()
        .and_then(|raw| String::from_utf8(raw).ok());

    let sentinel_config = crate::sentinel::SentinelConfig::default();
    let scheduler_loop_ok = if state.server_role == HttpServerRole::ControlPlane {
        heartbeat_recent_with_threshold(
            scheduler_heartbeat.as_deref(),
            (sentinel_config.scheduler_interval as i64 * 3).max(5 * 60),
        )
    } else {
        true
    };
    let watcher_loop_ok = if state.server_role == HttpServerRole::ControlPlane {
        heartbeat_recent_with_threshold(
            watcher_heartbeat.as_deref(),
            (sentinel_config.watcher_interval as i64 * 3).max(5 * 60),
        )
    } else {
        true
    };
    let integration_sync_loop_ok = if state.server_role == HttpServerRole::ControlPlane
        && sentinel_config.integration_sync_interval > 0
    {
        heartbeat_recent_with_threshold(
            integration_sync_heartbeat.as_deref(),
            (sentinel_config.integration_sync_interval as i64 * 3).max(8 * 60),
        )
    } else {
        true
    };
    let consolidation_loop_ok = if state.server_role == HttpServerRole::ControlPlane {
        heartbeat_recent_with_threshold(
            consolidation_heartbeat.as_deref(),
            (sentinel_config.consolidation_interval as i64 * 3).max(20 * 60),
        )
    } else {
        true
    };
    let approval_expiry_loop_ok = if state.server_role == HttpServerRole::ControlPlane {
        heartbeat_recent_with_threshold(
            approval_expiry_heartbeat.as_deref(),
            (sentinel_config.approval_expiry_interval as i64 * 3).max(10 * 60),
        )
    } else {
        true
    };
    let arkpulse_loop_ok = if state.server_role == HttpServerRole::ControlPlane
        && sentinel_config.pulse_interval > 0
    {
        heartbeat_recent_with_threshold(
            arkpulse_heartbeat.as_deref(),
            (sentinel_config.pulse_interval as i64 * 3).max(60 * 60),
        )
    } else {
        true
    };
    let auto_analysis_loop_ok = if state.server_role == HttpServerRole::ControlPlane
        && sentinel_config.auto_analysis_interval > 0
    {
        heartbeat_recent_with_threshold(
            auto_analysis_heartbeat.as_deref(),
            (sentinel_config.auto_analysis_interval as i64 * 3).max(20 * 60),
        )
    } else {
        true
    };

    let (
        embedding_client,
        playwright_url,
        public_app_base_url_configured,
        startup_issues_handle,
        docker_ok,
        active_container_count,
        container_reaper_status,
    ) = {
        let agent = state.agent.read().await;
        (
            agent.embedding_client.clone(),
            agent.config.browser.bridge_url.clone(),
            agent
                .config
                .public_apps
                .base_url
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .is_some(),
            agent.startup_issues_handle(),
            if state.server_role == HttpServerRole::ControlPlane
                && crate::runtime::ActionRuntime::should_manage_local_sandbox_containers()
            {
                agent.runtime.docker_available().await
            } else {
                true
            },
            agent.runtime.active_container_count().await,
            agent.runtime.container_reaper_status().await,
        )
    };
    let startup_issues = startup_issues_handle.read().await.clone();
    let blocking_startup_issue_count = startup_issues
        .iter()
        .filter(|issue| issue.blocks_readiness())
        .count();

    let health_client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(2))
        .build()
        .ok();
    let pgvector_retrieval_ok = if state.server_role == HttpServerRole::ControlPlane {
        let pgvector_ok = storage.pgvector_health_check().await.is_ok();
        let embeddings_ok = if let Some(client) = embedding_client.as_ref() {
            client.health_check().await.is_ok()
        } else {
            true
        };
        pgvector_ok && embeddings_ok
    } else {
        true
    };
    let playwright_ok = if state.server_role == HttpServerRole::ControlPlane {
        if let Some(client) = health_client.as_ref() {
            client
                .get(format!("{}/health", playwright_url.trim_end_matches('/')))
                .send()
                .await
                .map(|resp| resp.status().is_success())
                .unwrap_or(false)
        } else {
            false
        }
    } else {
        true
    };
    let whatsapp_active = state.whatsapp_bridge.read().await.active;
    let tunnel_active = state.tunnel.read().await.active;
    let restore = state.app_registry.restore_snapshot().await;
    let restore_ready = if state.server_role == HttpServerRole::ControlPlane {
        !restore.active && restore.pending == 0 && restore.degraded == 0
    } else {
        true
    };
    let public_app_origin_ok = if state.server_role == HttpServerRole::ControlPlane
        && state.deployment_mode == DeploymentMode::InternetFacing
    {
        public_app_base_url_configured
    } else {
        true
    };

    let healthy = storage_ok
        && schema_ok
        && migration_current
        && pgvector_retrieval_ok
        && docker_ok
        && playwright_ok
        && public_app_origin_ok
        && scheduler_loop_ok
        && watcher_loop_ok;
    let ready = healthy
        && integration_sync_loop_ok
        && consolidation_loop_ok
        && approval_expiry_loop_ok
        && arkpulse_loop_ok
        && auto_analysis_loop_ok
        && restore_ready
        && blocking_startup_issue_count == 0;
    let overall_ok = if readiness_mode { ready } else { true };
    let status_text = if readiness_mode {
        if ready { "ok" } else { "not_ready" }
    } else if healthy {
        "ok"
    } else {
        "degraded"
    };

    (
        if overall_ok {
            StatusCode::OK
        } else {
            StatusCode::SERVICE_UNAVAILABLE
        },
        serde_json::json!({
            "status": status_text,
            "mode": if readiness_mode { "readiness" } else { "health" },
            "ready": ready,
            "server_role": match state.server_role {
                HttpServerRole::ControlPlane => "control_plane",
                HttpServerRole::PublicApps => "public_apps",
            },
            "deployment_mode": state.deployment_mode.as_str(),
            "database": {
                "kind": "postgres",
                "connected": storage_ok,
                "migration_version": migration_version,
                "expected_migration_version": expected_migration_version,
                "migration_tracking": if migration_tracked { "tracked" } else { "bootstrap_only" },
                "migration_current": migration_current,
                "schema_ok": schema_ok,
                "missing_tables": missing_tables,
                "table_count": table_names.as_ref().map(|tables| tables.len()).unwrap_or(0),
                "size_bytes": database_size_bytes,
                "lease_status": lease_status,
            },
            "startup": {
                "issue_count": startup_issues.len(),
                "blocking_issue_count": blocking_startup_issue_count,
                "issues": startup_issues,
            },
            "apps": {
                "restore": restore,
            },
            "runtime": {
                "active_container_count": active_container_count,
                "container_reaper": container_reaper_status,
            },
            "housekeeping": housekeeping,
            "checks": {
                "storage": storage_ok,
                "postgres_connected": storage_ok,
                "schema_ok": schema_ok,
                "migration_current": migration_current,
                "postgres_pgvector_retrieval": pgvector_retrieval_ok,
                "docker": docker_ok,
                "playwright_bridge": playwright_ok,
                "whatsapp_bridge": whatsapp_active,
                "tunnel": tunnel_active,
                "scheduler_loop": scheduler_loop_ok,
                "watcher_loop": watcher_loop_ok,
                "integration_sync_loop": integration_sync_loop_ok,
                "consolidation_loop": consolidation_loop_ok,
                "approval_expiry_loop": approval_expiry_loop_ok,
                "arkpulse_loop": arkpulse_loop_ok,
                "auto_analysis_loop": auto_analysis_loop_ok,
                "app_restore_ready": restore_ready,
                "public_app_origin_ready": public_app_origin_ok,
            },
            "heartbeats": {
                "scheduler": scheduler_heartbeat,
                "watcher": watcher_heartbeat,
                "integration_sync": integration_sync_heartbeat,
                "consolidation": consolidation_heartbeat,
                "approval_expiry": approval_expiry_heartbeat,
                "arkpulse": arkpulse_heartbeat,
                "auto_analysis": auto_analysis_heartbeat,
            }
        }),
    )
}

fn timed_out_health_payload(readiness_mode: bool) -> (StatusCode, serde_json::Value) {
    (
        if readiness_mode {
            StatusCode::SERVICE_UNAVAILABLE
        } else {
            StatusCode::OK
        },
        serde_json::json!({
            "status": if readiness_mode { "not_ready" } else { "degraded" },
            "mode": if readiness_mode { "readiness" } else { "health" },
            "ready": false,
            "checks": {
                "health_probe_timeout": true,
            },
            "error": "Health probe timed out before dependency checks completed.",
        }),
    )
}

async fn health(State(state): State<AppState>) -> Response {
    let (status, payload) = match tokio::time::timeout(
        HEALTH_PROBE_TIMEOUT,
        build_runtime_health_payload(&state, false),
    )
    .await
    {
        Ok(result) => result,
        Err(_) => timed_out_health_payload(false),
    };
    (status, Json(payload)).into_response()
}

async fn readiness(State(state): State<AppState>) -> Response {
    let (status, payload) = match tokio::time::timeout(
        HEALTH_PROBE_TIMEOUT,
        build_runtime_health_payload(&state, true),
    )
    .await
    {
        Ok(result) => result,
        Err(_) => timed_out_health_payload(true),
    };
    (status, Json(payload)).into_response()
}

async fn metrics(State(state): State<AppState>) -> Response {
    let (queue_depth, active_tasks) = {
        let tasks = state.tasks.read().await;
        let all = tasks.all();
        let active = all
            .iter()
            .filter(|task| {
                matches!(
                    task.status,
                    TaskStatus::Pending
                        | TaskStatus::AwaitingApproval
                        | TaskStatus::ExpiredNeedsReapproval
                        | TaskStatus::Paused
                        | TaskStatus::InProgress
                )
            })
            .count();
        (all.len(), active)
    };
    let (active_container_count, reaper_status) = {
        let agent = state.agent.read().await;
        (
            agent.runtime.active_container_count().await,
            agent.runtime.container_reaper_status().await,
        )
    };
    let mut extra_metrics = Vec::new();
    extra_metrics.push("# HELP agentark_task_queue_depth Total tasks currently stored in the in-memory scheduler queue.".to_string());
    extra_metrics.push("# TYPE agentark_task_queue_depth gauge".to_string());
    extra_metrics.push(format!("agentark_task_queue_depth {}", queue_depth));
    extra_metrics.push("# HELP agentark_active_tasks Tasks currently pending or otherwise active in the scheduler queue.".to_string());
    extra_metrics.push("# TYPE agentark_active_tasks gauge".to_string());
    extra_metrics.push(format!("agentark_active_tasks {}", active_tasks));
    extra_metrics.push("# HELP agentark_runtime_active_containers Active sandbox containers reported by the runtime.".to_string());
    extra_metrics.push("# TYPE agentark_runtime_active_containers gauge".to_string());
    extra_metrics.push(format!(
        "agentark_runtime_active_containers {}",
        active_container_count
    ));
    extra_metrics.push("# HELP agentark_container_reaper_last_removed_count Containers removed by the most recent orphan-container sweep.".to_string());
    extra_metrics.push("# TYPE agentark_container_reaper_last_removed_count gauge".to_string());
    extra_metrics.push(format!(
        "agentark_container_reaper_last_removed_count {}",
        reaper_status.last_removed_count
    ));
    extra_metrics.push("# HELP agentark_container_reaper_total_removed_count Cumulative orphan sandbox containers removed by the runtime reaper.".to_string());
    extra_metrics.push("# TYPE agentark_container_reaper_total_removed_count counter".to_string());
    extra_metrics.push(format!(
        "agentark_container_reaper_total_removed_count {}",
        reaper_status.total_removed_count
    ));
    let body = crate::metrics::render_prometheus(&extra_metrics);
    (
        StatusCode::OK,
        [(
            header::CONTENT_TYPE,
            "text/plain; version=0.0.4; charset=utf-8",
        )],
        body,
    )
        .into_response()
}

async fn get_run(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Response {
    let storage = { state.agent.read().await.storage.clone() };
    match storage.load_execution_run(&id).await {
        Ok(Some(run)) => (
            StatusCode::OK,
            Json(serde_json::json!({
                "run": run,
            })),
        )
            .into_response(),
        Ok(None) => (
            StatusCode::NOT_FOUND,
            Json(serde_json::json!({
                "error": "Run not found",
                "run_id": id,
            })),
        )
            .into_response(),
        Err(error) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(serde_json::json!({
                "error": format!("Failed to load run: {}", error),
                "run_id": id,
            })),
        )
            .into_response(),
    }
}

async fn stream_run_events(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
    axum::extract::Query(params): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let since_seq = params
        .get("since_seq")
        .and_then(|value| value.parse::<u64>().ok());
    let agent = state.agent.read().await;
    let Some((replay, rx)) = agent.subscribe_live_run(&id, since_seq).await else {
        return (
            StatusCode::NOT_FOUND,
            Json(serde_json::json!({
                "error": "Run stream not found",
                "run_id": id,
            })),
        )
            .into_response();
    };
    drop(agent);

    let replay_stream = futures::stream::iter(
        replay
            .into_iter()
            .map(|event| Ok::<Event, std::convert::Infallible>(run_event_to_sse_event(event))),
    );
    let live_stream = futures::stream::unfold(rx, |mut rx| async move {
        loop {
            match rx.recv().await {
                Ok(event) => {
                    return Some((
                        Ok::<Event, std::convert::Infallible>(run_event_to_sse_event(event)),
                        rx,
                    ));
                }
                Err(tokio::sync::broadcast::error::RecvError::Lagged(_)) => {
                    continue;
                }
                Err(tokio::sync::broadcast::error::RecvError::Closed) => {
                    return None;
                }
            }
        }
    });
    let stream = replay_stream.chain(live_stream);

    Sse::new(stream)
        .keep_alive(KeepAlive::new().interval(std::time::Duration::from_secs(10)))
        .into_response()
}

async fn cancel_run(
    State(_state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Response {
    (
        StatusCode::CONFLICT,
        Json(serde_json::json!({
            "error": "Run cancellation is temporarily disabled until active executor enforcement is implemented",
            "run_id": id,
            "cancellation_requested": false,
        })),
    )
        .into_response()
}

async fn get_conversation_latest_run(
    State(state): State<AppState>,
    Path(id): Path<String>,
) -> Response {
    let agent = state.agent.read().await;
    let runs = match agent
        .storage
        .list_execution_runs_for_conversation(&id, 1)
        .await
    {
        Ok(runs) => runs,
        Err(error) => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(serde_json::json!({
                    "error": format!("Failed to load conversation runs: {}", error),
                    "conversation_id": id,
                })),
            )
                .into_response();
        }
    };
    let Some(run) = runs.into_iter().next() else {
        return (
            StatusCode::OK,
            Json(serde_json::json!({
                "run": serde_json::Value::Null,
                "events": [],
            })),
        )
            .into_response();
    };

    let events = agent.load_persisted_run_events(&run.id).await;

    (
        StatusCode::OK,
        Json(serde_json::json!({
            "run": run,
            "events": events,
        })),
    )
        .into_response()
}

async fn resume_run(
    State(state): State<AppState>,
    maybe_caller: Option<Extension<crate::actions::ActionCallerPrincipal>>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Response {
    let result = {
        let agent = state.agent.read().await;
        agent
            .resume_execution_run(&id, maybe_caller.as_ref().map(|caller| &caller.0))
            .await
    };

    match result {
        Ok(processed) => (
            StatusCode::OK,
            Json(ChatResponse {
                response: processed.response,
                proof_id: None,
                conversation_id: processed.conversation_id,
                conversation_title: processed.conversation_title,
                run_id: processed.run_id,
                run_status: processed.run_status,
                trace_id: processed.trace_id,
                degradation: processed.degradation,
                attempted_models: processed.attempted_models,
                user_outcome: processed.user_outcome,
            }),
        )
            .into_response(),
        Err(error) if error.to_string() == "Run not found" => (
            StatusCode::NOT_FOUND,
            Json(serde_json::json!({
                "error": "Run not found",
                "run_id": id,
            })),
        )
            .into_response(),
        Err(error) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(serde_json::json!({
                "error": format!("Failed to resume run: {}", error),
                "run_id": id,
            })),
        )
            .into_response(),
    }
}

// - WhatsApp Webhook -

/// GET /webhook/whatsapp - Meta verification handshake
async fn whatsapp_webhook_verify(
    State(state): State<AppState>,
    axum::extract::Query(params): axum::extract::Query<HashMap<String, String>>,
) -> Response {
    let verify_token = {
        let agent = state.agent.read().await;
        agent
            .config
            .whatsapp
            .as_ref()
            .map(|w| w.verify_token.clone())
    };

    let Some(token) = verify_token else {
        return (StatusCode::FORBIDDEN, "WhatsApp not configured").into_response();
    };

    match crate::channels::whatsapp::verify_webhook(&params, &token).await {
        Ok(challenge) => challenge.into_response(),
        Err(e) => {
            tracing::warn!("WhatsApp webhook verify failed: {}", e);
            (StatusCode::FORBIDDEN, format!("Verification failed: {}", e)).into_response()
        }
    }
}

/// POST /webhook/whatsapp - Inbound messages from Meta
async fn whatsapp_webhook_handler(
    State(state): State<AppState>,
    request: Request<axum::body::Body>,
) -> Response {
    let (parts, body) = request.into_parts();
    let signature = parts
        .headers
        .get("x-hub-signature-256")
        .and_then(|value| value.to_str().ok())
        .map(|value| value.to_string());
    let body_bytes = match axum::body::to_bytes(body, 1024 * 1024).await {
        Ok(bytes) => bytes,
        Err(_) => {
            return (
                StatusCode::PAYLOAD_TOO_LARGE,
                Json(serde_json::json!({ "error": "request body too large" })),
            )
                .into_response()
        }
    };
    let body = match serde_json::from_slice::<serde_json::Value>(&body_bytes) {
        Ok(body) => body,
        Err(error) => {
            return (
                StatusCode::BAD_REQUEST,
                Json(serde_json::json!({
                    "error": format!("Failed to parse WhatsApp webhook payload: {}", error)
                })),
            )
                .into_response()
        }
    };
    let config = {
        let guard = state.agent.read().await;
        guard.config.whatsapp.clone()
    };
    let Some(config) = config else {
        return (StatusCode::FORBIDDEN, "WhatsApp not configured").into_response();
    };
    let is_baileys = body.get("_source").and_then(|value| value.as_str()) == Some("baileys");

    if is_baileys {
        if config.mode != crate::channels::whatsapp::WhatsAppMode::Baileys {
            return (
                StatusCode::FORBIDDEN,
                "WhatsApp bridge payload rejected because Cloud API mode is configured",
            )
                .into_response();
        }
        let expected_api_key = state
            .api_key
            .read()
            .await
            .clone()
            .filter(|value| !value.trim().is_empty());
        let Some(expected_api_key) = expected_api_key else {
            return (
                StatusCode::SERVICE_UNAVAILABLE,
                "HTTP API key is required before bridge webhooks can be accepted",
            )
                .into_response();
        };
        if !auth::has_valid_bearer_api_key(&parts.headers, Some(expected_api_key.as_str())) {
            return (
                StatusCode::UNAUTHORIZED,
                "WhatsApp bridge authorization failed",
            )
                .into_response();
        }
    } else {
        if config.mode != crate::channels::whatsapp::WhatsAppMode::CloudApi {
            return (
                StatusCode::FORBIDDEN,
                "WhatsApp Cloud API payload rejected because Baileys mode is configured",
            )
                .into_response();
        }
        if let Err(error) = crate::channels::whatsapp::verify_cloud_api_request_signature(
            &config,
            &body_bytes,
            signature.as_deref(),
        ) {
            tracing::warn!("WhatsApp webhook request rejected: {}", error);
            return channel_webhook_error_response(error);
        }
    }

    let agent = state.agent.clone();
    tokio::spawn(async move {
        if let Err(e) = crate::channels::whatsapp::handle_webhook(agent, &body).await {
            tracing::error!("WhatsApp webhook processing error: {}", e);
        }
    });
    StatusCode::OK.into_response()
}

/// POST /webhook/slack - Slack Events API ingress
async fn slack_webhook_handler(
    State(state): State<AppState>,
    request: Request<axum::body::Body>,
) -> Response {
    let (parts, body) = request.into_parts();
    let timestamp = parts
        .headers
        .get("x-slack-request-timestamp")
        .and_then(|value| value.to_str().ok())
        .map(|value| value.to_string());
    let signature = parts
        .headers
        .get("x-slack-signature")
        .and_then(|value| value.to_str().ok())
        .map(|value| value.to_string());
    let body_bytes = match axum::body::to_bytes(body, 1024 * 1024).await {
        Ok(bytes) => bytes,
        Err(_) => {
            return (
                StatusCode::PAYLOAD_TOO_LARGE,
                Json(serde_json::json!({ "error": "request body too large" })),
            )
                .into_response()
        }
    };

    let agent = state.agent.clone();
    if let Err(error) = crate::channels::slack::verify_webhook_request(
        agent.clone(),
        &body_bytes,
        timestamp.as_deref(),
        signature.as_deref(),
    )
    .await
    {
        tracing::warn!("Slack webhook request rejected: {}", error);
        return (StatusCode::BAD_REQUEST, error.to_string()).into_response();
    }

    let is_url_verification = serde_json::from_slice::<serde_json::Value>(&body_bytes)
        .ok()
        .and_then(|payload| {
            payload
                .get("type")
                .and_then(|value| value.as_str())
                .map(str::to_string)
        })
        .is_some_and(|event_type| event_type == "url_verification");

    if is_url_verification {
        return match crate::channels::slack::handle_webhook(
            agent,
            &body_bytes,
            timestamp.as_deref(),
            signature.as_deref(),
        )
        .await
        {
            Ok(response) => (StatusCode::OK, response).into_response(),
            Err(error) => {
                tracing::warn!("Slack webhook processing failed: {}", error);
                (StatusCode::BAD_REQUEST, error.to_string()).into_response()
            }
        };
    }

    let timestamp_owned = timestamp.clone();
    let signature_owned = signature.clone();
    let body_owned = body_bytes.to_vec();
    tokio::spawn(async move {
        if let Err(error) = crate::channels::slack::handle_webhook(
            agent,
            &body_owned,
            timestamp_owned.as_deref(),
            signature_owned.as_deref(),
        )
        .await
        {
            tracing::warn!("Slack webhook processing failed: {}", error);
        }
    });

    (StatusCode::OK, "ok").into_response()
}

/// POST /webhook/teams - Teams/Bot Framework ingress
async fn teams_webhook_handler(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(activity): Json<crate::channels::teams::TeamsActivity>,
) -> Response {
    let agent = state.agent.clone();
    let config = {
        let guard = state.agent.read().await;
        guard
            .config
            .teams
            .clone()
            .or(
                crate::channels::teams::load_config_from_storage(&guard.storage)
                    .await
                    .ok()
                    .flatten(),
            )
    };

    let Some(config) = config else {
        return (StatusCode::FORBIDDEN, "Teams not configured").into_response();
    };

    let authorization = headers
        .get(header::AUTHORIZATION)
        .and_then(|value| value.to_str().ok())
        .map(|value| value.to_string());
    let verified = match crate::channels::teams::verify_inbound_activity_request(
        &config,
        authorization.as_deref(),
        &activity,
    )
    .await
    {
        Ok(verified) => verified,
        Err(error) => {
            tracing::warn!("Teams webhook authorization failed: {}", error);
            return (StatusCode::FORBIDDEN, error.to_string()).into_response();
        }
    };

    tokio::spawn(async move {
        if let Err(error) =
            crate::channels::teams::handle_activity(&agent, &config, activity, verified).await
        {
            tracing::warn!("Teams webhook processing failed: {}", error);
        }
    });

    (
        StatusCode::OK,
        Json(serde_json::json!({ "status": "accepted" })),
    )
        .into_response()
}

