fn channel_webhook_error_response(error: anyhow::Error) -> Response {
    let message = error.to_string();
    let lowered = message.to_ascii_lowercase();
    let status = if lowered.contains("signature")
        || lowered.contains("verification token")
        || lowered.contains("bridge token mismatch")
        || lowered.contains("token mismatch")
    {
        StatusCode::UNAUTHORIZED
    } else if lowered.contains("did not include")
        || lowered.contains("is required")
        || lowered.contains("missing")
        || lowered.contains("invalid")
        || lowered.contains("failed to parse")
    {
        StatusCode::BAD_REQUEST
    } else {
        StatusCode::INTERNAL_SERVER_ERROR
    };
    (
        status,
        Json(serde_json::json!({
            "status": "error",
            "error": message
        })),
    )
        .into_response()
}

// - WhatsApp Bridge Proxy -

fn embedded_whatsapp_bridge_unavailable_reason() -> Option<String> {
    if !std::path::Path::new("/app/bridges/whatsapp-bridge/index.js").exists() {
        return Some(
            "Bundled WhatsApp bridge is not installed in this image. Use the full image or switch to an external bridge."
                .to_string(),
        );
    }
    if !std::path::Path::new("/app/bridges/whatsapp-bridge/node_modules").exists() {
        return Some(
            "Bundled WhatsApp bridge dependencies are missing. Rebuild the full image or switch to an external bridge."
                .to_string(),
        );
    }
    None
}

async fn should_manage_embedded_whatsapp_bridge(state: &AppState) -> bool {
    let config = { state.agent.read().await.config.whatsapp.clone() };
    config
        .as_ref()
        .is_some_and(crate::channels::whatsapp::WhatsAppChannelConfig::uses_embedded_bridge)
}

fn whatsapp_bridge_managed_by(
    config: &crate::channels::whatsapp::WhatsAppChannelConfig,
) -> &'static str {
    match config.bridge_runtime() {
        crate::channels::whatsapp::WhatsAppBridgeRuntime::Embedded => "embedded",
        crate::channels::whatsapp::WhatsAppBridgeRuntime::External => "external",
    }
}

fn legacy_whatsapp_bridge_warning(
    config: &crate::channels::whatsapp::WhatsAppChannelConfig,
) -> Option<String> {
    if config.uses_external_bridge() && config.bridge_token.trim().is_empty() {
        Some(
            "This external bridge uses a legacy configuration without a bridge token. Add one to harden bridge requests."
                .to_string(),
        )
    } else {
        None
    }
}

fn generate_whatsapp_bridge_token() -> String {
    format!("wa_bridge_{}", uuid::Uuid::new_v4().simple())
}

fn whatsapp_bridge_status_payload(
    status: &str,
    managed_by: &str,
    detail: Option<String>,
    error: Option<String>,
    warning: Option<String>,
    installed: Option<bool>,
) -> serde_json::Value {
    let mut payload = serde_json::json!({
        "status": status,
        "managed_by": managed_by,
    });
    if let Some(object) = payload.as_object_mut() {
        if let Some(detail) = detail.filter(|value| !value.trim().is_empty()) {
            object.insert("detail".to_string(), serde_json::json!(detail));
        }
        if let Some(error) = error.filter(|value| !value.trim().is_empty()) {
            object.insert("error".to_string(), serde_json::json!(error));
        }
        if let Some(warning) = warning.filter(|value| !value.trim().is_empty()) {
            object.insert("warning".to_string(), serde_json::json!(warning));
        }
        if let Some(installed) = installed {
            object.insert("installed".to_string(), serde_json::json!(installed));
        }
    }
    payload
}

/// GET /api/whatsapp-bridge/status - resolve WhatsApp bridge ownership and status
async fn whatsapp_bridge_status(State(state): State<AppState>) -> Response {
    let config = {
        let agent = state.agent.read().await;
        agent.config.whatsapp.clone()
    };
    let Some(config) = config else {
        return (
            StatusCode::OK,
            Json(whatsapp_bridge_status_payload(
                "disabled",
                "none",
                Some("WhatsApp is disabled.".to_string()),
                None,
                None,
                None,
            )),
        )
            .into_response();
    };
    if config.mode != crate::channels::whatsapp::WhatsAppMode::Baileys {
        return (
            StatusCode::OK,
            Json(whatsapp_bridge_status_payload(
                "disabled",
                "none",
                Some("Cloud API mode does not use the WhatsApp bridge.".to_string()),
                None,
                None,
                None,
            )),
        )
            .into_response();
    }

    let managed_by = whatsapp_bridge_managed_by(&config);
    let warning = legacy_whatsapp_bridge_warning(&config);
    let installed = if config.uses_embedded_bridge() {
        Some(embedded_whatsapp_bridge_unavailable_reason().is_none())
    } else {
        None
    };
    if let Some(error) = config
        .uses_embedded_bridge()
        .then(embedded_whatsapp_bridge_unavailable_reason)
        .flatten()
    {
        return (
            StatusCode::OK,
            Json(whatsapp_bridge_status_payload(
                "unavailable",
                managed_by,
                Some("Bundled bridge unavailable.".to_string()),
                Some(error),
                warning,
                installed,
            )),
        )
            .into_response();
    }

    let bridge_url = match config.effective_bridge_url() {
        Ok(url) => url,
        Err(error) => {
            return (
                StatusCode::OK,
                Json(whatsapp_bridge_status_payload(
                    "unavailable",
                    managed_by,
                    Some("Bridge configuration is incomplete.".to_string()),
                    Some(error.to_string()),
                    warning,
                    installed,
                )),
            )
                .into_response()
        }
    };

    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(5))
        .build()
        .unwrap_or_default();

    let mut request = client.get(format!("{}/status", bridge_url.trim_end_matches('/')));
    if !config.bridge_token.trim().is_empty() {
        request = request.header("x-agentark-bridge-token", config.bridge_token.trim());
    }

    match request.send().await {
        Ok(resp) => {
            if !resp.status().is_success() {
                let status_code = resp.status();
                let body = resp.text().await.unwrap_or_default();
                let detail = if body.trim().is_empty() {
                    format!("Bridge returned {}", status_code)
                } else {
                    format!("Bridge returned {}: {}", status_code, body)
                };
                return (
                    StatusCode::OK,
                    Json(whatsapp_bridge_status_payload(
                        "unavailable",
                        managed_by,
                        Some("Bridge is unreachable right now.".to_string()),
                        Some(detail),
                        warning,
                        installed,
                    )),
                )
                    .into_response();
            }

            let mut payload = match resp.json::<serde_json::Value>().await {
                Ok(value) if value.is_object() => value,
                Ok(_) | Err(_) => {
                    return (
                        StatusCode::OK,
                        Json(whatsapp_bridge_status_payload(
                            "unavailable",
                            managed_by,
                            Some("Bridge returned invalid status data.".to_string()),
                            Some("Bridge returned invalid JSON.".to_string()),
                            warning,
                            installed,
                        )),
                    )
                        .into_response()
                }
            };
            if let Some(object) = payload.as_object_mut() {
                object.insert("managed_by".to_string(), serde_json::json!(managed_by));
                if let Some(warning) = warning.clone() {
                    object.insert("warning".to_string(), serde_json::json!(warning));
                }
                if let Some(installed) = installed {
                    object.insert("installed".to_string(), serde_json::json!(installed));
                }
            }
            (StatusCode::OK, Json(payload)).into_response()
        }
        Err(e) => (
            StatusCode::OK,
            Json(whatsapp_bridge_status_payload(
                "unavailable",
                managed_by,
                Some("Bridge is unreachable right now.".to_string()),
                Some(format!("Bridge unreachable: {}", e)),
                warning,
                installed,
            )),
        )
            .into_response(),
    }
}

/// POST /api/whatsapp-bridge/logout - proxy logout to Baileys bridge
async fn whatsapp_bridge_logout(State(state): State<AppState>) -> Response {
    let config = {
        let agent = state.agent.read().await;
        agent.config.whatsapp.clone()
    };
    let Some(config) = config else {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({ "error": "WhatsApp is disabled." })),
        )
            .into_response();
    };
    if config.mode != crate::channels::whatsapp::WhatsAppMode::Baileys {
        return (
            StatusCode::BAD_REQUEST,
            Json(
                serde_json::json!({ "error": "Cloud API mode does not use the WhatsApp bridge." }),
            ),
        )
            .into_response();
    }
    if let Some(error) = config
        .uses_embedded_bridge()
        .then(embedded_whatsapp_bridge_unavailable_reason)
        .flatten()
    {
        return (
            StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({ "error": error })),
        )
            .into_response();
    }
    let bridge_url = match config.effective_bridge_url() {
        Ok(url) => url,
        Err(error) => {
            return (
                StatusCode::BAD_REQUEST,
                Json(serde_json::json!({ "error": error.to_string() })),
            )
                .into_response()
        }
    };

    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(5))
        .build()
        .unwrap_or_default();

    let mut request = client.post(format!("{}/logout", bridge_url.trim_end_matches('/')));
    if !config.bridge_token.trim().is_empty() {
        request = request.header("x-agentark-bridge-token", config.bridge_token.trim());
    }

    match request.send().await {
        Ok(resp) => {
            let status = resp.status().as_u16();
            let body = resp.text().await.unwrap_or_default();
            (
                StatusCode::from_u16(status).unwrap_or(StatusCode::BAD_GATEWAY),
                [(header::CONTENT_TYPE, "application/json")],
                body,
            )
                .into_response()
        }
        Err(e) => (
            StatusCode::BAD_GATEWAY,
            Json(serde_json::json!({ "error": format!("Bridge unreachable: {}", e) })),
        )
            .into_response(),
    }
}

/// GET /api/telegram/status - connectivity check for configured Telegram bot.
async fn telegram_channel_status(State(state): State<AppState>) -> Response {
    let (enabled, bot_token) = {
        let agent = state.agent.read().await;
        if let Some(cfg) = &agent.config.telegram {
            (true, cfg.bot_token.clone())
        } else {
            (false, String::new())
        }
    };

    if !enabled {
        return (
            StatusCode::OK,
            Json(serde_json::json!({
                "status": "disabled",
                "detail": "Telegram is disabled.",
                "enabled": false,
                "configured": false,
                "probe_status": "disabled"
            })),
        )
            .into_response();
    }

    if bot_token.trim().is_empty() {
        return (
            StatusCode::OK,
            Json(serde_json::json!({
                "status": "missing_token",
                "detail": "Telegram bot token is not configured.",
                "enabled": true,
                "configured": false,
                "probe_status": "missing_token"
            })),
        )
            .into_response();
    }

    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(6))
        .build()
        .unwrap_or_default();

    let url = format!("https://api.telegram.org/bot{}/getMe", bot_token.trim());

    match client.get(url).send().await {
        Ok(resp) => {
            let status = resp.status();
            let payload = resp
                .json::<serde_json::Value>()
                .await
                .unwrap_or(serde_json::json!({}));
            if status.is_success() && payload.get("ok").and_then(|v| v.as_bool()) == Some(true) {
                let result = payload
                    .get("result")
                    .and_then(|v| v.as_object())
                    .cloned()
                    .unwrap_or_default();
                let username = result
                    .get("username")
                    .and_then(|v| v.as_str())
                    .unwrap_or("-");
                let bot_id = result
                    .get("id")
                    .and_then(|v| v.as_i64())
                    .unwrap_or_default();
                (
                    StatusCode::OK,
                    Json(serde_json::json!({
                        "status": "connected",
                        "detail": format!("Connected as @{} ({})", username, bot_id),
                        "enabled": true,
                        "configured": true,
                        "probe_status": "connected",
                        "username": username,
                        "bot_id": bot_id
                    })),
                )
                    .into_response()
            } else {
                let desc = payload
                    .get("description")
                    .and_then(|v| v.as_str())
                    .unwrap_or("Telegram API returned an error.");
                let detail = desc.trim();
                let detail_lower = detail.to_ascii_lowercase();
                let invalid_token =
                    status == StatusCode::UNAUTHORIZED
                        || detail_lower.contains("unauthorized")
                        || detail_lower.contains("invalid")
                        || detail_lower.contains("not found")
                        || detail_lower.contains("bot token");
                (
                    StatusCode::OK,
                    Json(serde_json::json!({
                        "status": if invalid_token { "error" } else { "configured" },
                        "detail": if invalid_token {
                            detail.to_string()
                        } else {
                            format!("Bot token is saved. Last live check failed: {}", detail)
                        },
                        "enabled": true,
                        "configured": true,
                        "probe_status": if invalid_token { "invalid_token" } else { "api_error" }
                    })),
                )
                    .into_response()
            }
        }
        Err(e) => (
            StatusCode::OK,
            Json(serde_json::json!({
                "status": "configured",
                "detail": format!("Bot token is saved. Last live check failed: Telegram API unreachable: {}", e),
                "enabled": true,
                "configured": true,
                "probe_status": "unreachable"
            })),
        )
            .into_response(),
    }
}

/// Get approval audit log (persisted in database)
async fn get_approval_log(
    State(state): State<AppState>,
    axum::extract::Query(params): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let limit = params
        .get("limit")
        .and_then(|s| s.parse().ok())
        .unwrap_or(20u64);
    let offset = params
        .get("offset")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0u64);
    let agent = state.agent.read().await;
    match agent
        .encrypted_storage
        .get_approval_log_decrypted(limit, offset)
        .await
    {
        Ok(log) => Json(serde_json::json!({ "approvals": log, "limit": limit, "offset": offset }))
            .into_response(),
        Err(e) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(ErrorResponse {
                error: format!("Failed to get approval log: {}", e),
            }),
        )
            .into_response(),
    }
}

/// Get security event log (persisted in database), with pagination and optional event type filter.
async fn get_security_logs(
    State(state): State<AppState>,
    axum::extract::Query(params): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Response {
    let limit = params
        .get("limit")
        .and_then(|s| s.parse().ok())
        .unwrap_or(20u64)
        .clamp(1, 100);
    let offset = params
        .get("offset")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0u64);
    let event_type = params
        .get("event_type")
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty());

    let agent = state.agent.read().await;
    let total = match agent
        .storage
        .count_security_logs(event_type.as_deref())
        .await
    {
        Ok(v) => v,
        Err(e) => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(ErrorResponse {
                    error: format!("Failed to count security logs: {}", e),
                }),
            )
                .into_response();
        }
    };

    match agent
        .storage
        .list_security_logs_paginated(limit, offset, event_type.as_deref())
        .await
    {
        Ok(logs) => Json(serde_json::json!({
            "logs": logs,
            "total": total,
            "limit": limit,
            "offset": offset,
            "event_type": event_type,
        }))
        .into_response(),
        Err(e) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(ErrorResponse {
                error: format!("Failed to get security logs: {}", e),
            }),
        )
            .into_response(),
    }
}

/// Spawn the WhatsApp bridge Node.js process (if not already running)
async fn spawn_whatsapp_bridge(state: AppState) -> Result<(), String> {
    let bridge_arc = state.whatsapp_bridge.clone();
    {
        let bridge = bridge_arc.read().await;
        if bridge.active {
            return Ok(());
        }
    }
    let wa_config = {
        let agent = state.agent.read().await;
        agent.config.whatsapp.clone()
    }
    .ok_or_else(|| "WhatsApp is not configured".to_string())?;
    if !wa_config.uses_embedded_bridge() {
        return Err("WhatsApp is not configured to use the bundled embedded bridge".to_string());
    }

    let api_key = state
        .api_key
        .read()
        .await
        .clone()
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| {
            "HTTP API key is required before the WhatsApp bridge can be started".to_string()
        })?;

    if let Some(error) = embedded_whatsapp_bridge_unavailable_reason() {
        let mut bridge = bridge_arc.write().await;
        bridge.active = false;
        bridge.error = Some(error.clone());
        return Err(error);
    }

    let mut command = tokio::process::Command::new("node");
    command
        .arg("/app/bridges/whatsapp-bridge/index.js")
        .env("BRIDGE_PORT", "8999")
        .env("BRIDGE_HOST", "127.0.0.1")
        .env("AGENTARK_URL", "http://127.0.0.1:8990")
        .env("AGENTARK_API_KEY", api_key)
        .env("AUTH_DIR", "/app/data/whatsapp-auth");
    if !wa_config.bridge_token.trim().is_empty() {
        command.env("BRIDGE_TOKEN", wa_config.bridge_token.trim());
    }
    command
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .kill_on_drop(true);

    match command.spawn() {
        Ok(child) => {
            let pid = child.id();
            let mut bridge = bridge_arc.write().await;
            bridge.process = Some(child);
            bridge.active = true;
            bridge.error = None;
            tracing::info!("WhatsApp bridge started (PID: {:?})", pid);
            Ok(())
        }
        Err(e) => {
            let mut bridge = bridge_arc.write().await;
            bridge.active = false;
            bridge.error = Some(format!("Failed to spawn bridge: {}", e));
            Err(format!("Failed to start WhatsApp bridge: {}", e))
        }
    }
}

/// Stop the WhatsApp bridge process
async fn stop_whatsapp_bridge(bridge_arc: Arc<RwLock<WhatsAppBridgeState>>) {
    let mut bridge = bridge_arc.write().await;
    if let Some(ref mut child) = bridge.process {
        let _ = child.kill().await;
        tracing::info!("WhatsApp bridge stopped");
    }
    bridge.process = None;
    bridge.active = false;
    bridge.error = None;
}

/// List active watchers
fn watcher_history_error_is_notification_summary_failure(error: Option<&str>) -> bool {
    let Some(error) = error else {
        return false;
    };
    let lower = error.to_ascii_lowercase();
    lower.contains("watcher notification")
        || lower.contains("notification summary")
        || lower.contains("follow-up summary")
}

async fn get_watchers(State(state): State<AppState>) -> Json<serde_json::Value> {
    let (watchers, supervisor_states) = {
        let agent = state.agent.read().await;
        (
            agent.watcher_manager.list().await,
            crate::core::list_automation_supervisor_states(&agent.storage)
                .await
                .unwrap_or_default(),
        )
    };
    let live_ids: HashSet<String> = watchers.iter().map(|w| w.id.to_string()).collect();
    let mut watcher_list: Vec<serde_json::Value> = watchers
        .iter()
        .map(|w| {
            let status_error = match &w.status {
                crate::core::watcher::WatcherStatus::Failed { error } => Some(error.clone()),
                _ => None,
            };
            serde_json::json!({
                "id": w.id.to_string(),
                "description": w.description,
                "poll_action": w.poll_action,
                "poll_arguments": w.poll_arguments,
                "condition": w.condition,
                "status": automation_watcher_status_label(&w.status),
                "status_error": status_error,
                "interval_secs": w.interval_secs,
                "timeout_secs": w.timeout_secs,
                "poll_count": w.poll_count,
                "created_at": w.created_at.to_rfc3339(),
                "last_poll_at": w.last_poll_at.map(|t| t.to_rfc3339()),
                "notify_channel": w.notify_channel,
                "on_trigger": w.on_trigger,
                "trigger_result": w.trigger_result,
                "last_result": w.last_result,
                "last_error": w.last_error,
                "last_poll_outcome": w.last_poll_outcome,
                "notification_attempts": w.notification_attempts,
                "history_only": false,
            })
        })
        .collect();
    watcher_list.extend(
        supervisor_states
            .into_iter()
            .filter(|state| {
                state.automation_kind == "watcher" && !live_ids.contains(&state.automation_id)
            })
            .map(|state| {
                let created_at = state
                    .created_at
                    .clone()
                    .or_else(|| state.last_run_at.clone())
                    .or_else(|| state.last_success_at.clone());
                let notification_summary_failure = state.status == "failed"
                    && watcher_history_error_is_notification_summary_failure(
                        state.last_error.as_deref(),
                    );
                let status = if notification_summary_failure {
                    "triggered".to_string()
                } else {
                    state.status.clone()
                };
                let status_error = if notification_summary_failure {
                    None
                } else {
                    state.last_error.clone()
                };
                let last_poll_outcome = match status.as_str() {
                    "triggered" => Some("matched"),
                    "failed" | "timed_out" => Some("error"),
                    _ => None,
                };
                serde_json::json!({
                    "id": state.automation_id,
                    "description": state.title,
                    "poll_action": state.action,
                    "poll_arguments": serde_json::Value::Null,
                    "condition": serde_json::Value::Null,
                    "status": status,
                    "status_error": status_error,
                    "interval_secs": serde_json::Value::Null,
                    "timeout_secs": serde_json::Value::Null,
                    "poll_count": state.attempt_count,
                    "created_at": created_at,
                    "last_poll_at": state.last_run_at,
                    "notify_channel": serde_json::Value::Null,
                    "on_trigger": serde_json::Value::Null,
                    "trigger_result": serde_json::Value::Null,
                    "last_result": serde_json::Value::Null,
                    "last_error": status_error,
                    "last_poll_outcome": last_poll_outcome,
                    "notification_attempts": Vec::<serde_json::Value>::new(),
                    "history_only": true,
                })
            }),
    );
    watcher_list.sort_by(|left, right| {
        let left_created = left
            .get("created_at")
            .and_then(|value| value.as_str())
            .unwrap_or_default();
        let right_created = right
            .get("created_at")
            .and_then(|value| value.as_str())
            .unwrap_or_default();
        right_created.cmp(left_created)
    });
    Json(serde_json::json!({ "watchers": watcher_list }))
}

/// Cancel a watcher
async fn cancel_watcher(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    if let Ok(uuid) = uuid::Uuid::parse_str(&id) {
        let cancelled = agent.watcher_manager.cancel(uuid).await;
        if cancelled {
            if let Some(watcher) = agent.watcher_manager.get(uuid).await {
                agent
                    .sync_watcher_supervisor_state(&watcher, Some("cancelled"), None)
                    .await;
            }
        }
        Json(serde_json::json!({ "cancelled": cancelled }))
    } else {
        Json(serde_json::json!({ "error": "Invalid watcher ID" }))
    }
}

async fn pause_watcher(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    if let Ok(uuid) = uuid::Uuid::parse_str(&id) {
        let paused = agent.watcher_manager.pause(uuid).await;
        if paused {
            if let Some(watcher) = agent.watcher_manager.get(uuid).await {
                agent
                    .sync_watcher_supervisor_state(&watcher, Some("paused"), None)
                    .await;
            }
        }
        Json(serde_json::json!({ "paused": paused }))
    } else {
        Json(serde_json::json!({ "error": "Invalid watcher ID" }))
    }
}

async fn resume_watcher(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    if let Ok(uuid) = uuid::Uuid::parse_str(&id) {
        let resumed = agent.watcher_manager.resume(uuid).await;
        if resumed {
            if let Some(watcher) = agent.watcher_manager.get(uuid).await {
                agent
                    .sync_watcher_supervisor_state(&watcher, Some("active"), None)
                    .await;
            }
        }
        Json(serde_json::json!({ "resumed": resumed }))
    } else {
        Json(serde_json::json!({ "error": "Invalid watcher ID" }))
    }
}

async fn pause_all_watchers(State(state): State<AppState>) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    let paused = agent.watcher_manager.pause_all().await;
    Json(serde_json::json!({ "paused": paused }))
}

async fn resume_all_watchers(State(state): State<AppState>) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    let resumed = agent.watcher_manager.resume_all().await;
    Json(serde_json::json!({ "resumed": resumed }))
}

async fn run_watcher_now(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    if let Ok(uuid) = uuid::Uuid::parse_str(&id) {
        let queued = agent.watcher_manager.run_now(uuid).await;
        Json(serde_json::json!({ "queued": queued }))
    } else {
        Json(serde_json::json!({ "error": "Invalid watcher ID" }))
    }
}

#[derive(Debug, Deserialize)]
struct WatcherExtendRequest {
    #[serde(default)]
    extra_hours: Option<u64>,
    #[serde(default)]
    extra_days: Option<u64>,
    #[serde(default)]
    extra_secs: Option<u64>,
    #[serde(default)]
    until_stopped: Option<bool>,
}

async fn extend_watcher(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
    Json(request): Json<WatcherExtendRequest>,
) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    if let Ok(uuid) = uuid::Uuid::parse_str(&id) {
        let timeout_secs = if request.until_stopped.unwrap_or(false) {
            agent.watcher_manager.extend_until_stopped(uuid).await
        } else {
            let extra_secs = request.extra_secs.unwrap_or(0)
                + request.extra_hours.unwrap_or(0).saturating_mul(60 * 60)
                + request.extra_days.unwrap_or(0).saturating_mul(24 * 60 * 60);
            agent.watcher_manager.extend_timeout(uuid, extra_secs).await
        };
        Json(serde_json::json!({
            "updated": timeout_secs.is_some(),
            "timeout_secs": timeout_secs
        }))
    } else {
        Json(serde_json::json!({ "error": "Invalid watcher ID" }))
    }
}

async fn delete_watcher(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    if let Ok(uuid) = uuid::Uuid::parse_str(&id) {
        let deleted_live = agent.watcher_manager.delete(uuid).await;
        let deleted_history = agent.clear_watcher_supervisor_state(&id).await;
        let deleted = deleted_live || deleted_history;
        Json(serde_json::json!({ "deleted": deleted }))
    } else {
        Json(serde_json::json!({ "error": "Invalid watcher ID" }))
    }
}

/// List active browser automation sessions
async fn browser_list_sessions(State(state): State<AppState>) -> Json<serde_json::Value> {
    let agent = state.agent.read().await;
    let sessions: Vec<_> = agent
        .browser_sessions
        .list_sessions()
        .into_iter()
        .map(|(id, task, status)| serde_json::json!({ "id": id, "task": task, "status": status }))
        .collect();
    Json(serde_json::json!({ "sessions": sessions }))
}

/// Provide user response to a waiting browser session
async fn browser_respond(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
    Json(body): Json<serde_json::Value>,
) -> Response {
    let agent = state.agent.read().await;
    let response = body.get("response").and_then(|v| v.as_str()).unwrap_or("");
    if response.trim().is_empty() {
        return (
            StatusCode::BAD_REQUEST,
            Json(ErrorResponse {
                error: "Response text is required".to_string(),
            }),
        )
            .into_response();
    }
    let success = agent
        .browser_sessions
        .provide_user_response(&id, response)
        .await;
    if success {
        (
            StatusCode::OK,
            Json(serde_json::json!({ "status": "ok", "success": true })),
        )
            .into_response()
    } else {
        (
            StatusCode::NOT_FOUND,
            Json(ErrorResponse {
                error: "Browser session not found or not waiting for input".to_string(),
            }),
        )
            .into_response()
    }
}

/// Get browser session status
async fn browser_session_status(
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Response {
    let agent = state.agent.read().await;
    match agent.browser_sessions.get_status(&id) {
        Some(status) => {
            let status_str = match &status {
                crate::core::browser_session::SessionStatus::Active => "active".to_string(),
                crate::core::browser_session::SessionStatus::WaitingForUser {
                    question, ..
                } => {
                    format!("waiting_for_user: {}", question)
                }
                crate::core::browser_session::SessionStatus::AwaitingResume { question } => {
                    format!("awaiting_resume: {}", question)
                }
                crate::core::browser_session::SessionStatus::Interrupted { reason } => {
                    format!("interrupted: {}", reason)
                }
                crate::core::browser_session::SessionStatus::Completed { summary } => {
                    format!("completed: {}", summary)
                }
                crate::core::browser_session::SessionStatus::Failed(e) => format!("failed: {}", e),
            };
            (
                StatusCode::OK,
                Json(serde_json::json!({ "id": id, "status": status_str })),
            )
                .into_response()
        }
        None => (
            StatusCode::NOT_FOUND,
            Json(ErrorResponse {
                error: "Session not found".to_string(),
            }),
        )
            .into_response(),
    }
}

/// Get agent status
async fn status(State(state): State<AppState>) -> Json<StatusResponse> {
    let agent = state.agent.read().await;
    let status = agent.status().await;

    Json(StatusResponse {
        did: status.did,
        memory_entries: status.memory_entries,
        skills_loaded: status.actions_loaded,
        actions_loaded: Some(status.actions_loaded),
        tasks_pending: status.tasks_pending,
        version: env!("CARGO_PKG_VERSION").to_string(),
    })
}

// ==================== ArkPulse Log ====================

#[derive(Debug, Deserialize)]
struct RunArkPulseFixRequest {
    #[serde(default)]
    fix_command: String,
    #[serde(default)]
    remediation: Option<crate::sentinel::DoctorRemediationSpec>,
    #[serde(default)]
    issue_title: Option<String>,
    #[serde(default)]
    target: Option<String>,
    #[serde(default)]
    event_timestamp: Option<String>,
    #[serde(default)]
    finding_index: Option<usize>,
}

enum ArkPulseFixPlan {
    TunnelStartVerify,
    TunnelRestartVerify,
    AppRestart(String),
    ShellOperations {
        app_dir: String,
        operations: Vec<ArkPulseShellOperation>,
    },
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum ArkPulseShellOperation {
    PipCompileRequirements,
    Ripgrep {
        pattern: String,
        path: Option<String>,
    },
    CargoGenerateLockfile,
    NpmPkgDelete {
        keys: Vec<String>,
    },
    MoveEnvBackup,
}

fn arkpulse_fix_plan_from_remediation(
    remediation: &crate::sentinel::DoctorRemediationSpec,
    allow_shell_command: bool,
) -> Option<ArkPulseFixPlan> {
    match remediation {
        crate::sentinel::DoctorRemediationSpec::TunnelStartVerify => {
            Some(ArkPulseFixPlan::TunnelStartVerify)
        }
        crate::sentinel::DoctorRemediationSpec::TunnelRestartVerify => {
            Some(ArkPulseFixPlan::TunnelRestartVerify)
        }
        crate::sentinel::DoctorRemediationSpec::AppRestart { app_id } => {
            if is_valid_app_id(app_id) {
                Some(ArkPulseFixPlan::AppRestart(app_id.clone()))
            } else {
                None
            }
        }
        crate::sentinel::DoctorRemediationSpec::ShellCommand { command } if allow_shell_command => {
            parse_supported_arkpulse_shell_command(command.trim())
        }
        crate::sentinel::DoctorRemediationSpec::ShellCommand { .. } => None,
    }
}

fn parse_arkpulse_app_restart(command: &str) -> Option<String> {
    let normalized = command.trim();
    let path = normalized
        .strip_prefix("POST ")
        .or_else(|| normalized.strip_prefix("post "))?
        .trim();
    let app_id = path.strip_prefix("/api/apps/")?.strip_suffix("/restart")?;
    if is_valid_app_id(app_id) {
        Some(app_id.to_string())
    } else {
        None
    }
}

fn parse_supported_arkpulse_shell_segment(segment: &str) -> Option<ArkPulseShellOperation> {
    let trimmed = segment.trim();
    let lower = trimmed.to_ascii_lowercase();
    if lower == "pip-compile requirements.txt" {
        return Some(ArkPulseShellOperation::PipCompileRequirements);
    }
    if lower == "cargo generate-lockfile" {
        return Some(ArkPulseShellOperation::CargoGenerateLockfile);
    }
    if lower == "npm pkg delete scripts.preinstall scripts.install scripts.postinstall" {
        return Some(ArkPulseShellOperation::NpmPkgDelete {
            keys: vec![
                "scripts.preinstall".to_string(),
                "scripts.install".to_string(),
                "scripts.postinstall".to_string(),
            ],
        });
    }
    if lower == "mv .env ../.env.backup" || lower == "mv .env .env.backup" {
        return Some(ArkPulseShellOperation::MoveEnvBackup);
    }
    if let Some(rest) = trimmed.strip_prefix("rg -n ") {
        let quoted = rest.strip_prefix('"')?;
        let end = quoted.find('"')?;
        let pattern = quoted[..end].to_string();
        let remaining = quoted[end + 1..].trim();
        if remaining.contains('&')
            || remaining.contains(';')
            || remaining.contains('`')
            || remaining.contains("$(")
            || remaining.contains('|')
        {
            return None;
        }
        let path = (!remaining.is_empty()).then(|| remaining.to_string());
        return Some(ArkPulseShellOperation::Ripgrep { pattern, path });
    }
    None
}

fn parse_supported_arkpulse_shell_command(command: &str) -> Option<ArkPulseFixPlan> {
    let normalized = command.trim();
    if normalized.is_empty() {
        return None;
    }
    let lower = normalized.to_ascii_lowercase();
    if lower.contains('\n')
        || lower.contains('\r')
        || lower.contains("||")
        || lower.contains(';')
        || lower.contains('`')
        || lower.contains("$(")
    {
        return None;
    }

    let segments: Vec<&str> = normalized
        .split("&&")
        .map(str::trim)
        .filter(|segment| !segment.is_empty())
        .collect();
    if segments.len() < 2 {
        return None;
    }

    let cd_segment = segments[0];
    let cd_prefix = cd_segment
        .strip_prefix("cd ")
        .or_else(|| cd_segment.strip_prefix("cd\t"))?;
    let cd_target = cd_prefix.trim();
    if cd_target.is_empty() {
        return None;
    }

    let mut operations = Vec::new();
    for segment in segments.iter().skip(1) {
        operations.push(parse_supported_arkpulse_shell_segment(segment)?);
    }

    Some(ArkPulseFixPlan::ShellOperations {
        app_dir: cd_target.to_string(),
        operations,
    })
}

fn classify_arkpulse_fix_plan(command: &str) -> Option<ArkPulseFixPlan> {
    let normalized = command.trim();
    if normalized.is_empty() {
        return None;
    }
    let lower = normalized.to_ascii_lowercase();
    if lower.contains("start tunnel") && lower.contains("/tunnel/status") {
        return Some(ArkPulseFixPlan::TunnelStartVerify);
    }
    if lower.contains("restart") && lower.contains("tunnel") {
        return Some(ArkPulseFixPlan::TunnelRestartVerify);
    }
    if let Some(app_id) = parse_arkpulse_app_restart(normalized) {
        return Some(ArkPulseFixPlan::AppRestart(app_id));
    }
    parse_supported_arkpulse_shell_command(normalized)
}

fn truncate_for_response(input: &str, max_chars: usize) -> String {
    if input.chars().count() <= max_chars {
        return input.to_string();
    }
    input.chars().take(max_chars).collect::<String>() + "..."
}

fn describe_arkpulse_remediation(
    remediation: Option<&crate::sentinel::DoctorRemediationSpec>,
    fix_command: &str,
) -> String {
    let normalized = fix_command.trim();
    if !normalized.is_empty() {
        return normalized.to_string();
    }
    match remediation {
        Some(crate::sentinel::DoctorRemediationSpec::TunnelStartVerify) => {
            "Start tunnel and verify /tunnel/status returns active + URL".to_string()
        }
        Some(crate::sentinel::DoctorRemediationSpec::TunnelRestartVerify) => {
            "Restart tunnel and verify public reachability".to_string()
        }
        Some(crate::sentinel::DoctorRemediationSpec::AppRestart { app_id }) => {
            format!("Restart app {} and re-check health", app_id)
        }
        Some(crate::sentinel::DoctorRemediationSpec::ShellCommand { command }) => {
            command.trim().to_string()
        }
        None => String::new(),
    }
}

fn describe_arkpulse_shell_operation(operation: &ArkPulseShellOperation) -> String {
    match operation {
        ArkPulseShellOperation::PipCompileRequirements => {
            "pip-compile requirements.txt".to_string()
        }
        ArkPulseShellOperation::Ripgrep { pattern, path } => match path {
            Some(path) => format!("rg -n \"{}\" {}", pattern, path),
            None => format!("rg -n \"{}\"", pattern),
        },
        ArkPulseShellOperation::CargoGenerateLockfile => "cargo generate-lockfile".to_string(),
        ArkPulseShellOperation::NpmPkgDelete { keys } => {
            format!("npm pkg delete {}", keys.join(" "))
        }
        ArkPulseShellOperation::MoveEnvBackup => "mv .env .env.backup".to_string(),
    }
}

fn arkpulse_shell_operation_auto_run_error(
    operations: &[ArkPulseShellOperation],
) -> Option<String> {
    for operation in operations {
        if matches!(operation, ArkPulseShellOperation::Ripgrep { .. }) {
            return Some(
                "ArkPulse grep fixes are no longer auto-run because they can expose file contents. Review the finding and run the search manually if needed."
                    .to_string(),
            );
        }
    }
    None
}

fn apply_arkpulse_sanitized_env(command: &mut tokio::process::Command) {
    const SAFE_ENV_KEYS: &[&str] = &[
        "PATH",
        "PATHEXT",
        "SYSTEMROOT",
        "SystemRoot",
        "COMSPEC",
        "ComSpec",
        "TMP",
        "TEMP",
        "HOME",
        "USERPROFILE",
        "APPDATA",
        "LOCALAPPDATA",
        "PROGRAMDATA",
        "ProgramData",
        "LANG",
        "LC_ALL",
        "LC_CTYPE",
        "CARGO_HOME",
        "RUSTUP_HOME",
        "RUSTUP_TOOLCHAIN",
        "NPM_CONFIG_CACHE",
        "npm_config_cache",
        "PIP_CACHE_DIR",
    ];

    command.env_clear();
    for key in SAFE_ENV_KEYS {
        if let Ok(value) = std::env::var(key) {
            command.env(key, value);
        }
    }
}

type ArkPulseFixHttpResult = (StatusCode, serde_json::Value);

fn arkpulse_error_result(status: StatusCode, error: impl Into<String>) -> ArkPulseFixHttpResult {
    let error = error.into();
    (
        status,
        serde_json::json!({
            "status": "error",
            "error": error,
        }),
    )
}

fn validate_arkpulse_relative_path(raw: &str) -> Result<PathBuf, String> {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        return Err("ArkPulse file target cannot be empty".to_string());
    }
    let path = PathBuf::from(trimmed);
    if path.is_absolute() {
        return Err("ArkPulse file targets must stay relative to the app directory".to_string());
    }
    for component in path.components() {
        if matches!(
            component,
            std::path::Component::ParentDir
                | std::path::Component::RootDir
                | std::path::Component::Prefix(_)
        ) {
            return Err("ArkPulse file targets cannot escape the app directory".to_string());
        }
    }
    Ok(path)
}

async fn resolve_arkpulse_app_dir(state: &AppState, raw_app_dir: &str) -> Result<PathBuf, String> {
    let trimmed = raw_app_dir.trim();
    if trimmed.is_empty() {
        return Err("App directory is required for ArkPulse shell operations".to_string());
    }
    let requested = tokio::fs::canonicalize(PathBuf::from(trimmed))
        .await
        .map_err(|e| format!("App directory is not accessible: {}", e))?;
    let apps_root = {
        let agent = state.agent.read().await;
        agent.data_dir.join("apps")
    };
    let apps_root = tokio::fs::canonicalize(&apps_root)
        .await
        .map_err(|e| format!("Managed apps root is not accessible: {}", e))?;
    if !requested.starts_with(&apps_root) {
        return Err("ArkPulse fixes may only run inside the managed apps directory".to_string());
    }
    Ok(requested)
}

async fn run_arkpulse_process(
    app_dir: &FsPath,
    program: &str,
    args: &[String],
) -> Result<serde_json::Value, String> {
    let mut command = tokio::process::Command::new(program);
    apply_arkpulse_sanitized_env(&mut command);
    command
        .args(args)
        .current_dir(app_dir)
        .stdin(std::process::Stdio::null())
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .kill_on_drop(true);
    let output = tokio::time::timeout(Duration::from_secs(120), command.output())
        .await
        .map_err(|_| format!("{} timed out after 120 seconds", program))?
        .map_err(|e| format!("failed to start {}: {}", program, e))?;
    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
    if !output.status.success() {
        let detail = if !stderr.is_empty() { stderr } else { stdout };
        return Err(format!(
            "{} failed with exit code {:?}: {}",
            program,
            output.status.code(),
            detail
        ));
    }
    Ok(serde_json::json!({
        "program": program,
        "args": args,
        "stdout": truncate_for_response(&stdout, 800),
        "stderr": truncate_for_response(&stderr, 800),
    }))
}

async fn run_arkpulse_shell_operations_fix(
    state: &AppState,
    raw_app_dir: &str,
    operations: &[ArkPulseShellOperation],
) -> ArkPulseFixHttpResult {
    let app_dir = match resolve_arkpulse_app_dir(state, raw_app_dir).await {
        Ok(path) => path,
        Err(error) => return arkpulse_error_result(StatusCode::BAD_REQUEST, error),
    };

    let mut results = Vec::new();
    for operation in operations {
        let detail = match operation {
            ArkPulseShellOperation::PipCompileRequirements => {
                let args = vec!["requirements.txt".to_string()];
                run_arkpulse_process(&app_dir, "pip-compile", &args).await
            }
            ArkPulseShellOperation::Ripgrep { pattern, path } => {
                let mut args = vec!["-n".to_string(), pattern.clone()];
                if let Some(path) = path {
                    let safe_path = match validate_arkpulse_relative_path(path) {
                        Ok(value) => value,
                        Err(error) => return arkpulse_error_result(StatusCode::BAD_REQUEST, error),
                    };
                    args.push(safe_path.to_string_lossy().to_string());
                }
                run_arkpulse_process(&app_dir, "rg", &args).await
            }
            ArkPulseShellOperation::CargoGenerateLockfile => {
                let args = vec!["generate-lockfile".to_string()];
                run_arkpulse_process(&app_dir, "cargo", &args).await
            }
            ArkPulseShellOperation::NpmPkgDelete { keys } => {
                let mut args = vec!["pkg".to_string(), "delete".to_string()];
                args.extend(keys.clone());
                run_arkpulse_process(&app_dir, "npm", &args).await
            }
            ArkPulseShellOperation::MoveEnvBackup => {
                let source = app_dir.join(".env");
                if !source.exists() {
                    return arkpulse_error_result(
                        StatusCode::BAD_REQUEST,
                        "No .env file exists in this app directory",
                    );
                };
                let target = app_dir.join(".env.backup");
                match tokio::fs::rename(&source, &target).await {
                    Ok(()) => Ok(serde_json::json!({
                        "action": "rename",
                        "from": source.display().to_string(),
                        "to": target.display().to_string(),
                    })),
                    Err(error) => Err(format!("failed to move .env to backup: {}", error)),
                }
            }
        };

        match detail {
            Ok(detail) => results.push(serde_json::json!({
                "operation": describe_arkpulse_shell_operation(operation),
                "detail": detail,
            })),
            Err(error) => return arkpulse_error_result(StatusCode::INTERNAL_SERVER_ERROR, error),
        }
    }

    (
        StatusCode::OK,
        serde_json::json!({
            "status": "ok",
            "mode": "shell_operations",
            "app_dir": app_dir.display().to_string(),
            "operations": results,
        }),
    )
}

async fn run_arkpulse_app_restart_fix(state: &AppState, app_id: &str) -> ArkPulseFixHttpResult {
    let response = restart_app(State(state.clone()), Path(app_id.to_string())).await;
    let status = response.status();
    let body = response.into_body();
    let body_bytes = match axum::body::to_bytes(body, 1024 * 1024).await {
        Ok(bytes) => bytes,
        Err(error) => {
            return arkpulse_error_result(
                StatusCode::INTERNAL_SERVER_ERROR,
                format!("Failed to read app restart response: {}", error),
            )
        }
    };
    let payload = serde_json::from_slice::<serde_json::Value>(&body_bytes).unwrap_or_else(|_| {
        serde_json::json!({
            "raw": String::from_utf8_lossy(&body_bytes).to_string()
        })
    });

    if !status.is_success() {
        let error = payload
            .get("error")
            .and_then(|value| value.as_str())
            .or_else(|| payload.get("message").and_then(|value| value.as_str()))
            .unwrap_or("Failed to restart app");
        return (
            status,
            serde_json::json!({
                "status": "error",
                "mode": "app_restart",
                "app_id": app_id,
                "error": error,
                "details": payload,
            }),
        );
    }

    let title = payload
        .get("title")
        .and_then(|value| value.as_str())
        .unwrap_or(app_id);
    let url = payload
        .get("url")
        .and_then(|value| value.as_str())
        .unwrap_or_default();
    (
        StatusCode::OK,
        serde_json::json!({
            "status": "ok",
            "mode": "app_restart",
            "app_id": app_id,
            "message": format!("Restarted app {} and queued a fresh ArkPulse run.", title),
            "url": url,
            "details": payload,
        }),
    )
}

fn arkpulse_fix_plan_label(plan: &ArkPulseFixPlan) -> &'static str {
    match plan {
        ArkPulseFixPlan::TunnelStartVerify => "tunnel_start_verify",
        ArkPulseFixPlan::TunnelRestartVerify => "tunnel_restart_verify",
        ArkPulseFixPlan::AppRestart(_) => "app_restart",
        ArkPulseFixPlan::ShellOperations { .. } => "shell_operations",
    }
}

struct ArkPulseFixAuditDetails<'a> {
    plan: &'a ArkPulseFixPlan,
    issue_title: &'a str,
    target: &'a str,
    fix_summary: &'a str,
    event_timestamp: Option<&'a str>,
    finding_index: Option<usize>,
}

async fn persist_arkpulse_fix_audit(
    state: &AppState,
    audit: &ArkPulseFixAuditDetails<'_>,
    latency_ms: i64,
    status: StatusCode,
    body: &serde_json::Value,
) {
    let storage = {
        let agent = state.agent.read().await;
        agent.storage.clone()
    };
    let success = status.is_success()
        && body
            .get("status")
            .and_then(|value| value.as_str())
            .map(|value| !value.eq_ignore_ascii_case("error"))
            .unwrap_or(true);
    let mode = body
        .get("mode")
        .and_then(|value| value.as_str())
        .unwrap_or_else(|| arkpulse_fix_plan_label(audit.plan));
    let arguments = serde_json::json!({
        "issue_title": audit.issue_title,
        "target": audit.target,
        "fix_summary": truncate_for_response(audit.fix_summary, 400),
        "plan": arkpulse_fix_plan_label(audit.plan),
        "event_timestamp": audit.event_timestamp,
        "finding_index": audit.finding_index,
    });
    let payload = truncate_for_response(&body.to_string(), 4000);
    let log = crate::storage::operational_log::Model {
        id: uuid::Uuid::new_v4().to_string(),
        created_at: chrono::Utc::now().to_rfc3339(),
        trace_id: None,
        conversation_id: None,
        channel: "web".to_string(),
        event_type: "arkpulse_fix".to_string(),
        success,
        outcome: if success {
            format!("ArkPulse fix completed ({mode})")
        } else {
            format!("ArkPulse fix failed ({mode})")
        },
        tool_name: Some(mode.to_string()),
        latency_ms: Some(latency_ms),
        arguments: Some(arguments.to_string()),
        payload: Some(payload),
        strategy_version: None,
        policy_version: None,
        prompt_version: None,
        model_slot: None,
    };
    if let Err(error) = storage.insert_operational_log(&log).await {
        tracing::warn!("Failed to persist ArkPulse fix audit log: {}", error);
    }
}

struct ArkPulseFixResponseContext<'a> {
    audit: ArkPulseFixAuditDetails<'a>,
    started_at: std::time::Instant,
}

async fn respond_arkpulse_fix(
    state: &AppState,
    context: ArkPulseFixResponseContext<'_>,
    result: ArkPulseFixHttpResult,
) -> Response {
    let (status, body) = result;
    let latency_ms = context
        .started_at
        .elapsed()
        .as_millis()
        .min(i64::MAX as u128) as i64;
    persist_arkpulse_fix_audit(state, &context.audit, latency_ms, status, &body).await;
    (status, Json(body)).into_response()
}

/// Execute a supported ArkPulse remediation directly (without going through Chat).
async fn run_arkpulse_fix(
    State(state): State<AppState>,
    Json(request): Json<RunArkPulseFixRequest>,
) -> Response {
    let RunArkPulseFixRequest {
        fix_command,
        remediation,
        issue_title,
        target,
        event_timestamp,
        finding_index,
    } = request;
    let started_at = std::time::Instant::now();

    let request_fix_command = fix_command.trim().to_string();
    if request_fix_command.is_empty() && remediation.is_none() {
        return (
            StatusCode::BAD_REQUEST,
            Json(ErrorResponse {
                error: "remediation or fix_command is required".to_string(),
            }),
        )
            .into_response();
    }

    let mut effective_fix_command = request_fix_command.clone();
    let mut effective_remediation = remediation.clone();
    let request_has_event_context = event_timestamp
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty())
        || finding_index.is_some();
    let mut selected_event_timestamp: Option<String> = None;
    let mut selected_finding_index: Option<usize> = None;

    let plan = if event_timestamp.is_some() || finding_index.is_some() {
        let event_timestamp = event_timestamp
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty());
        let Some(event_timestamp) = event_timestamp else {
            return (
                StatusCode::BAD_REQUEST,
                Json(ErrorResponse {
                    error: "event_timestamp is required when finding_index is provided".to_string(),
                }),
            )
                .into_response();
        };
        let Some(finding_index) = finding_index else {
            return (
                StatusCode::BAD_REQUEST,
                Json(ErrorResponse {
                    error: "finding_index is required when event_timestamp is provided".to_string(),
                }),
            )
                .into_response();
        };

        let agent = state.agent.read().await;
        let events = crate::sentinel::get_pulse_log(&agent).await;
        let Some(event) = events
            .iter()
            .find(|event| event.timestamp == event_timestamp)
        else {
            return (
                StatusCode::NOT_FOUND,
                Json(ErrorResponse {
                    error: "ArkPulse event not found".to_string(),
                }),
            )
                .into_response();
        };
        let Some(finding) = event.details.doctor_findings.get(finding_index) else {
            return (
                StatusCode::NOT_FOUND,
                Json(ErrorResponse {
                    error: "ArkPulse finding index is out of range".to_string(),
                }),
            )
                .into_response();
        };
        if !finding.user_actionable {
            return (
                StatusCode::BAD_REQUEST,
                Json(ErrorResponse {
                    error: "This ArkPulse finding is advisory-only and must be fixed manually"
                        .to_string(),
                }),
            )
                .into_response();
        }
        if !request_fix_command.is_empty() && finding.fix_command.trim() != request_fix_command {
            return (
                StatusCode::BAD_REQUEST,
                Json(ErrorResponse {
                    error: "fix_command does not match the selected ArkPulse finding".to_string(),
                }),
            )
                .into_response();
        }
        if let (Some(requested_remediation), Some(stored_remediation)) =
            (remediation.as_ref(), finding.remediation.as_ref())
        {
            if stored_remediation != requested_remediation {
                return (
                    StatusCode::BAD_REQUEST,
                    Json(ErrorResponse {
                        error: "remediation does not match the selected ArkPulse finding"
                            .to_string(),
                    }),
                )
                    .into_response();
            }
        }
        selected_event_timestamp = Some(event_timestamp.to_string());
        selected_finding_index = Some(finding_index);
        effective_fix_command = finding.fix_command.trim().to_string();
        effective_remediation = finding.remediation.clone();
        effective_remediation
            .as_ref()
            .and_then(|value| arkpulse_fix_plan_from_remediation(value, true))
            .or_else(|| classify_arkpulse_fix_plan(&effective_fix_command))
    } else {
        effective_remediation
            .as_ref()
            .and_then(|value| arkpulse_fix_plan_from_remediation(value, false))
            .or_else(|| classify_arkpulse_fix_plan(&request_fix_command))
    };

    let Some(plan) = plan else {
        return (
            StatusCode::BAD_REQUEST,
            Json(ErrorResponse {
                error:
                    "This fix cannot be auto-run directly. Copy the remediation and run it manually."
                        .to_string(),
            }),
        )
            .into_response();
    };

    if let ArkPulseFixPlan::ShellOperations { operations, .. } = &plan {
        if !request_has_event_context {
            return (
                StatusCode::BAD_REQUEST,
                Json(ErrorResponse {
                    error: "Shell-style ArkPulse fixes must come from a stored ArkPulse finding. Open the finding in ArkPulse and run it from there."
                        .to_string(),
                }),
            )
                .into_response();
        }
        if let Some(error) = arkpulse_shell_operation_auto_run_error(operations) {
            return (StatusCode::BAD_REQUEST, Json(ErrorResponse { error })).into_response();
        }
    }

    let issue_title = issue_title.unwrap_or_default();
    let target = target.unwrap_or_default();
    let fix_summary =
        describe_arkpulse_remediation(effective_remediation.as_ref(), &effective_fix_command);
    tracing::info!(
        "ArkPulse fix requested: issue='{}' target='{}' command='{}'",
        issue_title,
        target,
        truncate_for_response(&fix_summary, 220)
    );

    let result = match &plan {
        ArkPulseFixPlan::TunnelStartVerify => {
            let tunnel_arc = state.tunnel.clone();
            if let Err(error) = tunnel::spawn_tunnel(&state, None).await {
                arkpulse_error_result(StatusCode::INTERNAL_SERVER_ERROR, error)
            } else {
                let discovered_url = tunnel::wait_for_tunnel_url(tunnel_arc.clone(), 12).await;
                if let Some(url) = discovered_url.as_ref() {
                    tunnel::persist_public_tunnel_state(&state, Some(url), None).await;
                }

                let tunnel = tunnel_arc.read().await;
                let active = tunnel.active;
                let url = tunnel.url.clone();
                let message =
                    if active && url.as_ref().is_some_and(|value| !value.trim().is_empty()) {
                        format!(
                            "Remote access is active at {}.",
                            url.clone().unwrap_or_default()
                        )
                    } else {
                        "Tunnel start requested. URL is pending; re-check /tunnel/status shortly."
                            .to_string()
                    };
                (
                    StatusCode::OK,
                    serde_json::json!({
                        "status": "ok",
                        "mode": "tunnel_start_verify",
                        "message": message,
                        "active": active,
                        "url": url
                    }),
                )
            }
        }
        ArkPulseFixPlan::TunnelRestartVerify => {
            tunnel::stop_tunnel_internal(&state).await;
            let tunnel_arc = state.tunnel.clone();
            if let Err(error) = tunnel::spawn_tunnel(&state, None).await {
                arkpulse_error_result(StatusCode::INTERNAL_SERVER_ERROR, error)
            } else {
                let discovered_url = tunnel::wait_for_tunnel_url(tunnel_arc.clone(), 12).await;
                if let Some(url) = discovered_url.as_ref() {
                    tunnel::persist_public_tunnel_state(&state, Some(url), None).await;
                }

                let tunnel = tunnel_arc.read().await;
                let active = tunnel.active;
                let url = tunnel.url.clone();
                let message =
                    if active && url.as_ref().is_some_and(|value| !value.trim().is_empty()) {
                        format!(
                            "Remote access restarted successfully at {}.",
                            url.clone().unwrap_or_default()
                        )
                    } else {
                        "Tunnel restart requested. URL is pending; re-check /tunnel/status shortly."
                            .to_string()
                    };
                (
                    StatusCode::OK,
                    serde_json::json!({
                        "status": "ok",
                        "mode": "tunnel_restart_verify",
                        "message": message,
                        "active": active,
                        "url": url
                    }),
                )
            }
        }
        ArkPulseFixPlan::AppRestart(app_id) => run_arkpulse_app_restart_fix(&state, app_id).await,
        ArkPulseFixPlan::ShellOperations {
            app_dir,
            operations,
        } => run_arkpulse_shell_operations_fix(&state, app_dir, operations).await,
    };

    respond_arkpulse_fix(
        &state,
        ArkPulseFixResponseContext {
            audit: ArkPulseFixAuditDetails {
                plan: &plan,
                issue_title: &issue_title,
                target: &target,
                fix_summary: &fix_summary,
                event_timestamp: selected_event_timestamp.as_deref(),
                finding_index: selected_finding_index,
            },
            started_at,
        },
        result,
    )
    .await
}

/// Return the ArkPulse event log (last 100 events)
async fn get_pulse_log(
    State(state): State<AppState>,
    axum::extract::Query(params): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Json<serde_json::Value> {
    let limit = params
        .get("limit")
        .and_then(|s| s.parse().ok())
        .unwrap_or(20usize);
    let offset = params
        .get("offset")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0usize);
    let agent = state.agent.read().await;
    let mut all_events = crate::sentinel::get_pulse_log(&agent).await;
    let has_persisted_payload = agent
        .storage
        .get(crate::sentinel::PULSE_LOG_KEY)
        .await
        .ok()
        .flatten()
        .is_some();
    all_events.sort_by(|a, b| {
        let a_ts = chrono::DateTime::parse_from_rfc3339(&a.timestamp)
            .map(|ts| ts.timestamp_millis())
            .unwrap_or(0);
        let b_ts = chrono::DateTime::parse_from_rfc3339(&b.timestamp)
            .map(|ts| ts.timestamp_millis())
            .unwrap_or(0);
        b_ts.cmp(&a_ts)
    });
    let total = all_events.len();
    let events: Vec<_> = all_events.into_iter().skip(offset).take(limit).collect();
    Json(serde_json::json!({
        "events": events,
        "total": total,
        "limit": limit,
        "offset": offset,
        "running": crate::sentinel::is_pulse_running(),
        "history_unavailable": total == 0 && has_persisted_payload,
        "history_unavailable_reason": if total == 0 && has_persisted_payload {
            Some("A persisted ArkPulse history payload exists but could not be read. New runs will appear normally.")
        } else {
            None::<&str>
        }
    }))
}

async fn trigger_arkpulse_after_app_change(state: &AppState, reason: &'static str) {
    if crate::sentinel::is_pulse_running() {
        return;
    }
    {
        let agent_guard = state.agent.read().await;
        let autonomy = load_autonomy_settings(&agent_guard).await;
        if autonomy_background_disabled(&autonomy) {
            return;
        }
    }
    let agent = state.agent.clone();
    tokio::spawn(async move {
        tracing::info!("ArkPulse auto-triggered after {}", reason);
        crate::sentinel::run_pulse(&agent).await;
    });
}

/// Trigger an ArkPulse check immediately
async fn trigger_pulse(State(state): State<AppState>) -> Json<serde_json::Value> {
    if crate::sentinel::is_pulse_running() {
        return Json(serde_json::json!({
            "status": "running",
            "message": "ArkPulse is already running"
        }));
    }
    {
        let agent_guard = state.agent.read().await;
        let autonomy = load_autonomy_settings(&agent_guard).await;
        if autonomy_background_disabled(&autonomy) {
            return Json(serde_json::json!({
                "status": "paused",
                "message": "Autonomy is disabled. Re-enable autonomy to run ArkPulse."
            }));
        }
    }
    let agent = state.agent.clone();
    tokio::spawn(async move {
        crate::sentinel::run_pulse(&agent).await;
    });
    Json(serde_json::json!({ "status": "triggered", "message": "ArkPulse check started" }))
}

/// Get user profile (for checking onboarding status)
async fn get_profile(State(state): State<AppState>) -> Json<ProfileResponse> {
    let profile = state.user_profile.read().await;
    Json(ProfileResponse {
        name: profile.name.clone(),
        location: profile.location.clone(),
        timezone: profile.timezone.clone(),
        language: profile.language.clone(),
        tone: profile.tone.clone(),
        email_format: profile.email_format.clone(),
        preferences: profile.preferences.clone(),
        onboarding_complete: profile.onboarding_complete,
    })
}

fn conversation_not_found_response() -> Response {
    (
        StatusCode::NOT_FOUND,
        Json(ErrorResponse {
            error: "Conversation not found".to_string(),
        }),
    )
        .into_response()
}

fn build_request_execution_hints(
    deep_research: bool,
    chat_task_id: Option<String>,
    caller: Option<&crate::actions::ActionCallerPrincipal>,
    surface: crate::actions::ActionExecutionSurface,
    direct_user_intent: bool,
    attachments_present: bool,
    plan_confirmation_mode: crate::core::RequestPlanConfirmationMode,
    plan_override: Option<crate::core::ExecutionPlan>,
) -> crate::core::RequestExecutionHints {
    crate::core::RequestExecutionHints {
        deep_research,
        chat_task_id,
        caller_principal: caller.cloned(),
        execution_surface: surface,
        direct_user_intent,
        attachments_present,
        plan_confirmation_mode,
        plan_override,
        allow_sensitive_model_context_once: false,
    }
}

fn normalized_chat_plan_confirmation_mode(
    mode: Option<&str>,
) -> crate::core::RequestPlanConfirmationMode {
    match mode.unwrap_or("").trim().to_ascii_lowercase().as_str() {
        "before_execution" | "plan" | "confirm" => {
            crate::core::RequestPlanConfirmationMode::BeforeExecution
        }
        _ => crate::core::RequestPlanConfirmationMode::None,
    }
}

pub(super) fn build_direct_action_auth_context(
    caller: Option<&crate::actions::ActionCallerPrincipal>,
    surface: crate::actions::ActionExecutionSurface,
    direct_user_intent: bool,
) -> crate::actions::ActionAuthorizationContext {
    crate::actions::ActionAuthorizationContext {
        principal: caller.cloned(),
        surface,
        direct_user_intent,
        current_turn_is_explicit_approval: false,
        agent_name: None,
        agent_access_scope: None,
    }
}

/// Chat with the agent
async fn chat(
    State(state): State<AppState>,
    maybe_caller: Option<Extension<crate::actions::ActionCallerPrincipal>>,
    ConnectInfo(_addr): ConnectInfo<SocketAddr>,
    Json(request): Json<ChatRequest>,
) -> Response {
    if let Some(response) = validate_chat_message_size(&request.message) {
        return response;
    }

    tracing::info!(
        "HTTP /chat request: channel={}, msg={}chars, conv_id={:?}, project={:?}",
        request.channel,
        request.message.len(),
        request.conversation_id.as_deref().unwrap_or("-"),
        request.project_id.as_deref().unwrap_or("-"),
    );

    if let Some(conversation_id) = request
        .conversation_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        let agent = state.agent.read().await;
        match agent.storage.get_conversation(conversation_id).await {
            Ok(Some(_)) => {}
            Ok(None) => return conversation_not_found_response(),
            Err(error) => {
                return (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    Json(ErrorResponse {
                        error: format!("Failed to load conversation: {}", error),
                    }),
                )
                    .into_response();
            }
        }
    }

    // Two-tier secrets UX: allow "/setsecret KEY=VALUE" without engaging the LLM.
    // This bypasses conversation history + traces, and stores the value encrypted in secrets.enc.
    if let Some((key, value)) = parse_set_secret_command(&request.message) {
        let cid = request.conversation_id.clone();
        let (config_dir, data_dir) = {
            let agent = state.agent.read().await;
            (agent.config_dir.clone(), agent.data_dir.clone())
        };
        if let Err(e) =
            crate::core::secrets::store_user_secret(&config_dir, Some(&data_dir), &key, &value)
        {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(ErrorResponse {
                    error: format!("Failed to store secret: {}", e),
                }),
            )
                .into_response();
        }

        let followup = if let Some(ref cid_str) = cid {
            let agent = state.agent.read().await;
            agent.on_secret_saved_followup(cid_str).await
        } else {
            None
        };

        let mut response = format!(
            "Saved secret '{}' (stored encrypted). This value was not sent to the LLM.",
            key
        );
        if let Some(f) = followup {
            response.push_str("\n\n");
            response.push_str(&f);
        }

        return (
            StatusCode::OK,
            Json(ChatResponse {
                response,
                proof_id: None,
                conversation_id: cid,
                conversation_title: None,
                run_id: None,
                run_status: None,
                trace_id: None,
                degradation: Vec::new(),
                attempted_models: Vec::new(),
                user_outcome: None,
            }),
        )
            .into_response();
    }

    // Human-in-the-loop shortcut: reuse currently configured model key without sending to the LLM.
    if let Some(key) = crate::core::secrets::parse_use_current_llm_key_command(&request.message) {
        let cid = request.conversation_id.clone();
        let (config_dir, data_dir, llm_env) = {
            let agent = state.agent.read().await;
            (
                agent.config_dir.clone(),
                agent.data_dir.clone(),
                agent.app_model_env_vars(),
            )
        };
        let Some(value) = llm_env.get(&key).cloned().filter(|v| !v.trim().is_empty()) else {
            let mut available: Vec<String> = llm_env
                .iter()
                .filter_map(|(k, v)| {
                    if v.trim().is_empty() {
                        None
                    } else if k.ends_with("_API_KEY")
                        || k.ends_with("_BASE_URL")
                        || k == "LLM_MODEL"
                        || k == "LLM_PROVIDER"
                    {
                        Some(k.clone())
                    } else {
                        None
                    }
                })
                .collect();
            available.sort();
            let available_text = if available.is_empty() {
                "none".to_string()
            } else {
                available.join(", ")
            };
            return (
                StatusCode::BAD_REQUEST,
                Json(ErrorResponse {
                    error: format!(
                        "Can't map '{}' from current model settings. Available model-backed keys: {}",
                        key, available_text
                    ),
                }),
            )
                .into_response();
        };

        if let Err(e) =
            crate::core::secrets::store_user_secret(&config_dir, Some(&data_dir), &key, &value)
        {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(ErrorResponse {
                    error: format!("Failed to store secret: {}", e),
                }),
            )
                .into_response();
        }

        let followup = if let Some(ref cid_str) = cid {
            let agent = state.agent.read().await;
            agent.on_secret_saved_followup(cid_str).await
        } else {
            None
        };

        let mut response = format!(
            "Linked '{}' to the currently configured model credential (stored encrypted). This was not sent to the LLM.",
            key
        );
        if let Some(f) = followup {
            response.push_str("\n\n");
            response.push_str(&f);
        }

        return (
            StatusCode::OK,
            Json(ChatResponse {
                response,
                proof_id: None,
                conversation_id: cid,
                conversation_title: None,
                run_id: None,
                run_status: None,
                trace_id: None,
                degradation: Vec::new(),
                attempted_models: Vec::new(),
                user_outcome: None,
            }),
        )
            .into_response();
    }

    // Fast command path: push-notification controls without LLM roundtrip.
    if let Some(cmd) = parse_notification_control_command(&request.message) {
        match handle_notification_control_command(&state, cmd).await {
            Ok(response) => {
                return (
                    StatusCode::OK,
                    Json(ChatResponse {
                        response,
                        proof_id: None,
                        conversation_id: request.conversation_id.clone(),
                        conversation_title: None,
                        run_id: None,
                        run_status: None,
                        trace_id: None,
                        degradation: Vec::new(),
                        attempted_models: Vec::new(),
                        user_outcome: None,
                    }),
                )
                    .into_response();
            }
            Err(error) => {
                return (StatusCode::BAD_REQUEST, Json(ErrorResponse { error })).into_response();
            }
        }
    }

    // Fast command path: tunnel control without LLM roundtrip.
    if let Some(cmd) = tunnel::parse_tunnel_command(&request.message) {
        match tunnel::handle_tunnel_control_command(&state, cmd).await {
            Ok(response) => {
                return (
                    StatusCode::OK,
                    Json(ChatResponse {
                        response,
                        proof_id: None,
                        conversation_id: request.conversation_id.clone(),
                        conversation_title: None,
                        run_id: None,
                        run_status: None,
                        trace_id: None,
                        degradation: Vec::new(),
                        attempted_models: Vec::new(),
                        user_outcome: None,
                    }),
                )
                    .into_response();
            }
            Err(error) => {
                return (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    Json(ErrorResponse { error }),
                )
                    .into_response();
            }
        }
    }

    // Fast command path: explicit autonomy helpers without LLM roundtrip.
    if let Some(cmd) = parse_autonomy_quick_command(&request.message) {
        match handle_autonomy_quick_command(&state, cmd).await {
            Ok(response) => {
                return (
                    StatusCode::OK,
                    Json(ChatResponse {
                        response,
                        proof_id: None,
                        conversation_id: request.conversation_id.clone(),
                        conversation_title: None,
                        run_id: None,
                        run_status: None,
                        trace_id: None,
                        degradation: Vec::new(),
                        attempted_models: Vec::new(),
                        user_outcome: None,
                    }),
                )
                    .into_response();
            }
            Err(error) => {
                return (StatusCode::BAD_REQUEST, Json(ErrorResponse { error })).into_response();
            }
        }
    }

    let original_conversation_id = request.conversation_id.clone();
    let message = request.message.clone();
    let channel = request.channel.clone();
    let conversation_id = request.conversation_id.clone();
    let project_id = request.project_id.clone();
    let deep_research = request.deep_research;
    let attachments_present = request.attachments_present;
    let plan_confirmation_mode =
        normalized_chat_plan_confirmation_mode(request.plan_confirmation_mode.as_deref());
    let caller_principal = maybe_caller.as_ref().map(|Extension(value)| value.clone());
    let agent_for_chat = state.agent.clone();

    let result = {
        let worker = tokio::spawn(async move {
            let agent_guard = agent_for_chat.read().await;
            agent_guard
                .process_message_with_meta_and_hints(
                    &message,
                    &channel,
                    conversation_id.as_deref(),
                    project_id.as_deref(),
                    build_request_execution_hints(
                        deep_research,
                        None,
                        caller_principal.as_ref(),
                        crate::actions::ActionExecutionSurface::Chat,
                        true,
                        attachments_present,
                        plan_confirmation_mode,
                        None,
                    ),
                )
                .await
        });
        match worker.await {
            Ok(result) => result,
            Err(error) => Err(anyhow::anyhow!("Chat worker failed: {}", error)),
        }
    };

    match result {
        Ok(processed) => {
            spawn_autonomy_analysis_tick(state.agent.clone(), "chat_event");
            (
                StatusCode::OK,
                Json(ChatResponse {
                    response: processed.response,
                    proof_id: None,
                    conversation_id: processed.conversation_id.or(original_conversation_id),
                    conversation_title: processed.conversation_title,
                    run_id: processed.run_id,
                    run_status: processed.run_status,
                    trace_id: processed.trace_id,
                    degradation: processed.degradation,
                    attempted_models: processed.attempted_models,
                    user_outcome: processed.user_outcome,
                }),
            )
                .into_response()
        }
        Err(e) => {
            if e.to_string() == "Conversation not found" {
                return conversation_not_found_response();
            }
            tracing::error!("Framework-level web chat failure: {}", e);
            let response = "I hit a framework-level problem before supervised execution could finish. Please retry. If it keeps happening, restart the runtime or check the server logs.".to_string();
            let degradation = vec![crate::core::DegradationNote {
                kind: "platform".to_string(),
                summary: "framework error".to_string(),
                detail: Some(
                    "The request left the supervised execution path before completion.".to_string(),
                ),
            }];
            let user_outcome = crate::core::ExecutionSupervisor::default()
                .build_service_outage_outcome(&response, "framework_error", &degradation, &[]);
            (
                StatusCode::OK,
                Json(ChatResponse {
                    response,
                    proof_id: None,
                    conversation_id: original_conversation_id,
                    conversation_title: None,
                    run_id: None,
                    run_status: Some("platform_failed".to_string()),
                    trace_id: None,
                    degradation,
                    attempted_models: Vec::new(),
                    user_outcome: Some(user_outcome),
                }),
            )
                .into_response()
        }
    }
}

/// Chat with the agent via SSE - streams thinking steps in real-time
fn stream_detail_looks_like_html_payload(text: &str) -> bool {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return false;
    }
    let lower = trimmed.to_ascii_lowercase();
    lower.starts_with("<!doctype html")
        || lower.starts_with("<html")
        || (lower.contains("<html") && (lower.contains("</html>") || lower.contains("</body>")))
}

fn stream_detail_looks_like_source_payload(text: &str) -> bool {
    let sample = text.trim().lines().take(12).collect::<Vec<_>>().join("\n");
    if sample.is_empty() {
        return false;
    }
    let lower = sample.to_ascii_lowercase();
    lower.contains("from fastapi import")
        || lower.contains("import asyncio")
        || lower.contains("import httpx")
        || lower.contains("function ")
        || lower.contains("const ")
        || lower.contains("let ")
        || lower.contains("class ")
        || lower.contains("def ")
        || lower.contains("async def ")
        || lower.contains("#include ")
}

fn summarize_stream_tool_activity_content(content: &str) -> String {
    let trimmed = content.trim();
    if trimmed.is_empty() {
        return String::new();
    }

    if stream_detail_looks_like_html_payload(trimmed) {
        if let Some(start) = trimmed.to_ascii_lowercase().find("<title>") {
            let rest = &trimmed[start + "<title>".len()..];
            if let Some(end) = rest.to_ascii_lowercase().find("</title>") {
                let title = rest[..end].trim();
                if !title.is_empty() {
                    return format!("Read HTML document: {}.", title);
                }
            }
        }
        return "Read HTML document.".to_string();
    }

    let json_like = (trimmed.starts_with('{') && trimmed.ends_with('}'))
        || (trimmed.starts_with('[') && trimmed.ends_with(']'));
    if json_like {
        if let Ok(value) = serde_json::from_str::<serde_json::Value>(trimmed) {
            if let Some(obj) = value.as_object() {
                if let Some(title) = obj
                    .get("matched_app")
                    .and_then(|v| v.get("title"))
                    .and_then(|v| v.as_str())
                    .map(str::trim)
                    .filter(|v| !v.is_empty())
                {
                    return format!("Matched app and loaded metadata for {}.", title);
                }
                let keys = obj.keys().take(4).cloned().collect::<Vec<_>>().join(", ");
                if !keys.is_empty() {
                    return format!("Returned structured data: {}.", keys);
                }
            } else if let Some(items) = value.as_array() {
                return format!(
                    "Returned list with {} item{}.",
                    items.len(),
                    if items.len() == 1 { "" } else { "s" }
                );
            }
        }
    }

    if stream_detail_looks_like_source_payload(trimmed) {
        let line_count = trimmed.lines().count();
        return format!(
            "Read source file contents ({} line{}).",
            line_count,
            if line_count == 1 { "" } else { "s" }
        );
    }

    if trimmed.len() > 240
        && trimmed
            .chars()
            .any(|ch| matches!(ch, '{' | '}' | '<' | '>' | ';'))
    {
        return "Returned verbose tool output.".to_string();
    }

    trimmed.chars().take(240).collect::<String>()
}

fn truncate_stream_tool_raw_content(content: &str, max_chars: usize) -> String {
    let trimmed = content.trim();
    if trimmed.is_empty() {
        return String::new();
    }
    let mut out = String::new();
    for (idx, ch) in trimmed.chars().enumerate() {
        if idx >= max_chars {
            out.push_str("\n...[truncated]");
            break;
        }
        out.push(ch);
    }
    out
}

fn normalize_stream_heartbeat_status(status: &str) -> String {
    let trimmed = status.trim();
    if trimmed.is_empty() {
        return "Still processing. No new output yet.".to_string();
    }
    let lower = trimmed.to_ascii_lowercase();
    let memory_is_active = lower.contains("memory") && !lower.contains("available on demand");
    if memory_is_active {
        return "Memory/context setup in progress. No new output yet.".to_string();
    }
    if lower.contains("context") {
        return "Preparing conversation context. No new output yet.".to_string();
    }
    if lower.contains("execution plan") || lower.contains("research plan") {
        return "Preparing research plan. No new output yet.".to_string();
    }
    if lower.contains("tool") {
        return "Waiting on tool execution. No new output yet.".to_string();
    }
    if lower.contains("respond") || lower.contains("generating") || lower.contains("model") {
        return "Waiting on model response. No new output yet.".to_string();
    }
    "Still processing. No new output yet.".to_string()
}

fn normalize_stream_event_for_sse(
    ev: crate::core::StreamEvent,
    last_thinking_detail: &str,
) -> (Option<(&'static str, serde_json::Value)>, String) {
    match ev {
        crate::core::StreamEvent::RunStarted {
            run_id,
            flow_kind,
            origin,
            conversation_id,
            trace_id,
            resumed,
        } => (
            Some((
                "run_started",
                serde_json::json!({
                    "run_id": run_id,
                    "flow_kind": flow_kind,
                    "origin": origin,
                    "conversation_id": conversation_id,
                    "trace_id": trace_id,
                    "resumed": resumed,
                }),
            )),
            String::new(),
        ),
        crate::core::StreamEvent::ChatTaskStarted {
            task_id,
            description,
            work_type,
            conversation_id,
            project_id,
        } => (
            Some((
                "task_started",
                serde_json::json!({
                    "task_id": task_id,
                    "description": description,
                    "status": "in_progress",
                    "work_type": work_type,
                    "conversation_id": conversation_id,
                    "project_id": project_id,
                }),
            )),
            String::new(),
        ),
        crate::core::StreamEvent::Token(content) => (
            Some(("token", serde_json::json!({ "content": content }))),
            String::new(),
        ),
        crate::core::StreamEvent::Thinking(status) => {
            let detail = normalize_stream_heartbeat_status(&status);
            if detail == last_thinking_detail {
                (None, detail)
            } else {
                (
                    Some((
                        "thinking",
                        serde_json::json!({
                            "step_type": "heartbeat",
                            "title": "Still Working",
                            "detail": detail
                        }),
                    )),
                    detail,
                )
            }
        }
        crate::core::StreamEvent::ToolStart { name, payload } => {
            let payload_json = if let Some(payload) = payload {
                if let Some(obj) = payload.as_object() {
                    let mut merged = serde_json::Map::new();
                    merged.insert("name".to_string(), serde_json::json!(name));
                    for (k, v) in obj {
                        merged.insert(k.clone(), v.clone());
                    }
                    serde_json::Value::Object(merged)
                } else {
                    serde_json::json!({ "name": name, "payload": payload })
                }
            } else {
                serde_json::json!({ "name": name })
            };
            (Some(("tool_start", payload_json)), String::new())
        }
        crate::core::StreamEvent::ToolResult { name, content } => {
            let summarized = summarize_stream_tool_activity_content(&content);
            let trimmed = content.trim();
            let mut payload = serde_json::Map::new();
            payload.insert("name".to_string(), serde_json::json!(name));
            payload.insert("content".to_string(), serde_json::json!(summarized));
            if !trimmed.is_empty() {
                if let Ok(value) = serde_json::from_str::<serde_json::Value>(trimmed) {
                    if let Some(obj) = value.as_object() {
                        for (k, v) in obj {
                            if matches!(k.as_str(), "name" | "content" | "raw_content" | "result") {
                                continue;
                            }
                            payload.insert(k.clone(), v.clone());
                        }
                    } else {
                        payload.insert("result".to_string(), value);
                    }
                } else {
                    payload.insert(
                        "raw_content".to_string(),
                        serde_json::json!(truncate_stream_tool_raw_content(trimmed, 65536)),
                    );
                }
            }
            (
                Some(("tool_result", serde_json::Value::Object(payload))),
                String::new(),
            )
        }
        crate::core::StreamEvent::ToolProgress {
            name,
            content,
            payload,
        } => {
            let content = summarize_stream_tool_activity_content(&content);
            let payload_json = if let Some(payload) = payload {
                if let Some(obj) = payload.as_object() {
                    let mut merged = serde_json::Map::new();
                    merged.insert("name".to_string(), serde_json::json!(name));
                    merged.insert("content".to_string(), serde_json::json!(content));
                    for (k, v) in obj {
                        merged.insert(k.clone(), v.clone());
                    }
                    serde_json::Value::Object(merged)
                } else {
                    serde_json::json!({ "name": name, "content": content, "payload": payload })
                }
            } else {
                serde_json::json!({ "name": name, "content": content })
            };
            (Some(("tool_progress", payload_json)), String::new())
        }
        crate::core::StreamEvent::PlanGenerated { plan } => (
            Some((
                "plan_generated",
                serde_json::json!({
                    "step_type": "plan_generated",
                    "title": "Execution Plan",
                    "detail": format!("{} steps planned", plan.steps.len()),
                    "plan": plan,
                }),
            )),
            String::new(),
        ),
        crate::core::StreamEvent::PlanRevised { plan, reason } => (
            Some((
                "plan_revised",
                serde_json::json!({
                    "step_type": "plan_revised",
                    "title": "Execution Plan Revised",
                    "detail": reason.unwrap_or_else(|| format!("Plan revised to {} steps.", plan.steps.len())),
                    "plan": plan,
                }),
            )),
            String::new(),
        ),
        crate::core::StreamEvent::PlanReadyForConfirmation {
            task_id,
            plan,
            source,
        } => (
            Some((
                "plan_ready_for_confirmation",
                serde_json::json!({
                    "step_type": "plan_ready_for_confirmation",
                    "title": "Plan Ready For Confirmation",
                    "detail": "Review the plan, make edits if needed, and press Start to continue.",
                    "task_id": task_id,
                    "source": source,
                    "plan": plan,
                }),
            )),
            String::new(),
        ),
        crate::core::StreamEvent::PlanUnavailable { reason } => (
            Some((
                "plan_unavailable",
                serde_json::json!({
                    "step_type": "plan_unavailable",
                    "title": "Execution Plan Unavailable",
                    "detail": reason,
                }),
            )),
            String::new(),
        ),
        crate::core::StreamEvent::PlanStepUpdate {
            plan_id,
            revision,
            step_id,
            step_title,
            status,
            detail,
            substeps,
        } => {
            let title = match status {
                crate::core::PlanStepStatus::Pending => "Plan Step Queued",
                crate::core::PlanStepStatus::Running => "Plan Step Started",
                crate::core::PlanStepStatus::Completed => "Plan Step Completed",
                crate::core::PlanStepStatus::Failed => "Plan Step Failed",
                crate::core::PlanStepStatus::Skipped => "Plan Step Skipped",
            };
            let step_title_text = step_title
                .clone()
                .filter(|value| !value.trim().is_empty())
                .unwrap_or_else(|| format!("Step {}", step_id));
            let detail_text = detail.unwrap_or_else(|| match status {
                crate::core::PlanStepStatus::Pending => format!("Queued {}.", step_title_text),
                crate::core::PlanStepStatus::Running => format!("Started {}.", step_title_text),
                crate::core::PlanStepStatus::Completed => {
                    format!("Completed {}.", step_title_text)
                }
                crate::core::PlanStepStatus::Failed => format!("Failed {}.", step_title_text),
                crate::core::PlanStepStatus::Skipped => format!("Skipped {}.", step_title_text),
            });
            (
                Some((
                    "plan_step_update",
                    serde_json::json!({
                        "step_type": "plan_step_update",
                        "title": title,
                        "plan_id": plan_id,
                        "revision": revision,
                        "step_id": step_id,
                        "step_title": step_title,
                        "status": status,
                        "detail": detail_text,
                        "substeps": substeps,
                    }),
                )),
                String::new(),
            )
        }
    }
}

fn run_event_to_sse_event(run_event: crate::core::RunEvent) -> Event {
    let mut payload = match run_event.kind.as_str() {
        "thinking" => {
            let detail = run_event
                .payload
                .get("detail")
                .and_then(|value| value.as_str())
                .unwrap_or_default()
                .to_string();
            serde_json::json!({
                "step_type": "heartbeat",
                "title": "Still Working",
                "detail": detail,
            })
            .as_object()
            .cloned()
            .unwrap_or_default()
        }
        "tool_start" => {
            let name = run_event
                .payload
                .get("name")
                .and_then(|value| value.as_str())
                .unwrap_or_default()
                .to_string();
            if let Some(inner) = run_event
                .payload
                .get("payload")
                .and_then(|value| value.as_object())
            {
                let mut merged = serde_json::Map::new();
                merged.insert("name".to_string(), serde_json::json!(name));
                for (key, value) in inner {
                    merged.insert(key.clone(), value.clone());
                }
                merged
            } else {
                serde_json::json!({ "name": name })
                    .as_object()
                    .cloned()
                    .unwrap_or_default()
            }
        }
        "tool_progress" => {
            let name = run_event
                .payload
                .get("name")
                .and_then(|value| value.as_str())
                .unwrap_or_default()
                .to_string();
            let content = summarize_stream_tool_activity_content(
                run_event
                    .payload
                    .get("content")
                    .and_then(|value| value.as_str())
                    .unwrap_or_default(),
            );
            if let Some(inner) = run_event
                .payload
                .get("payload")
                .and_then(|value| value.as_object())
            {
                let mut merged = serde_json::Map::new();
                merged.insert("name".to_string(), serde_json::json!(name));
                merged.insert("content".to_string(), serde_json::json!(content));
                for (key, value) in inner {
                    merged.insert(key.clone(), value.clone());
                }
                merged
            } else {
                serde_json::json!({
                    "name": name,
                    "content": content,
                })
                .as_object()
                .cloned()
                .unwrap_or_default()
            }
        }
        "tool_result" => {
            let name = run_event
                .payload
                .get("name")
                .and_then(|value| value.as_str())
                .unwrap_or_default()
                .to_string();
            let raw_content = run_event
                .payload
                .get("content")
                .and_then(|value| value.as_str())
                .unwrap_or_default()
                .to_string();
            let summarized = summarize_stream_tool_activity_content(&raw_content);
            let trimmed = raw_content.trim();
            let mut merged = serde_json::Map::new();
            merged.insert("name".to_string(), serde_json::json!(name));
            merged.insert("content".to_string(), serde_json::json!(summarized));
            if !trimmed.is_empty() {
                if let Ok(value) = serde_json::from_str::<serde_json::Value>(trimmed) {
                    if let Some(obj) = value.as_object() {
                        for (key, value) in obj {
                            if matches!(key.as_str(), "name" | "content" | "raw_content" | "result")
                            {
                                continue;
                            }
                            merged.insert(key.clone(), value.clone());
                        }
                    } else {
                        merged.insert("raw_content".to_string(), serde_json::json!(raw_content));
                    }
                } else {
                    merged.insert("raw_content".to_string(), serde_json::json!(raw_content));
                }
            }
            merged
        }
        "plan_generated" => {
            let plan = run_event.payload.get("plan").cloned().unwrap_or_default();
            let step_count = plan
                .get("steps")
                .and_then(|value| value.as_array())
                .map(|steps| steps.len())
                .unwrap_or(0);
            serde_json::json!({
                "step_type": "plan_generated",
                "title": "Execution Plan",
                "detail": format!("{} steps planned", step_count),
                "plan": plan,
            })
            .as_object()
            .cloned()
            .unwrap_or_default()
        }
        "plan_revised" => {
            let plan = run_event.payload.get("plan").cloned().unwrap_or_default();
            let step_count = plan
                .get("steps")
                .and_then(|value| value.as_array())
                .map(|steps| steps.len())
                .unwrap_or(0);
            let detail = run_event
                .payload
                .get("reason")
                .and_then(|value| value.as_str())
                .map(str::to_string)
                .unwrap_or_else(|| format!("Plan revised to {} steps.", step_count));
            serde_json::json!({
                "step_type": "plan_revised",
                "title": "Execution Plan Revised",
                "detail": detail,
                "plan": plan,
            })
            .as_object()
            .cloned()
            .unwrap_or_default()
        }
        "plan_unavailable" => {
            let detail = run_event
                .payload
                .get("reason")
                .and_then(|value| value.as_str())
                .unwrap_or("Structured planning was unavailable.")
                .to_string();
            serde_json::json!({
                "step_type": "plan_unavailable",
                "title": "Execution Plan Unavailable",
                "detail": detail,
            })
            .as_object()
            .cloned()
            .unwrap_or_default()
        }
        "plan_step_update" => {
            let detail = run_event
                .payload
                .get("detail")
                .and_then(|value| value.as_str())
                .map(str::to_string)
                .unwrap_or_else(|| {
                    format!(
                        "Updated step {}",
                        run_event
                            .payload
                            .get("step_id")
                            .and_then(|value| value.as_u64())
                            .unwrap_or(0)
                    )
                });
            let mut merged = run_event.payload.as_object().cloned().unwrap_or_default();
            merged.insert(
                "step_type".to_string(),
                serde_json::json!("plan_step_update"),
            );
            merged.insert("title".to_string(), serde_json::json!("Plan Step Update"));
            merged.insert("detail".to_string(), serde_json::json!(detail));
            merged
        }
        _ => run_event.payload.as_object().cloned().unwrap_or_default(),
    };
    payload.insert("run_id".to_string(), serde_json::json!(run_event.run_id));
    payload.insert("seq".to_string(), serde_json::json!(run_event.seq));
    payload.insert("ts".to_string(), serde_json::json!(run_event.ts));
    payload.insert(
        "flow_kind".to_string(),
        serde_json::json!(run_event.flow_kind),
    );
    payload.insert("origin".to_string(), serde_json::json!(run_event.origin));
    payload.insert(
        "priority".to_string(),
        serde_json::json!(run_event.priority),
    );
    if let Some(stage) = run_event.stage {
        payload.insert("stage".to_string(), serde_json::json!(stage));
    }
    Event::default()
        .event(run_event.kind)
        .data(serde_json::to_string(&payload).unwrap_or_default())
}

fn truncate_stream_task_text(text: &str, max_chars: usize) -> String {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return String::new();
    }
    let mut out = String::new();
    for (idx, ch) in trimmed.chars().enumerate() {
        if idx >= max_chars {
            out.push_str("...");
            break;
        }
        out.push(ch);
    }
    out
}

fn chat_task_status_key(status: &crate::core::TaskStatus) -> &'static str {
    match status {
        crate::core::TaskStatus::Pending => "pending",
        crate::core::TaskStatus::AwaitingApproval => "awaiting_approval",
        crate::core::TaskStatus::ExpiredNeedsReapproval => "expired_needs_reapproval",
        crate::core::TaskStatus::Paused => "paused",
        crate::core::TaskStatus::InProgress => "in_progress",
        crate::core::TaskStatus::Completed => "completed",
        crate::core::TaskStatus::Failed { .. } => "failed",
        crate::core::TaskStatus::Cancelled => "cancelled",
    }
}

fn chat_task_terminal_status(response: &str) -> crate::core::TaskStatus {
    let lower = response.trim().to_ascii_lowercase();
    if lower.contains("waiting for your approval")
        || lower.contains("waiting for your input")
        || lower.contains("reply with approval")
        || lower.contains("needs your approval")
        || lower.contains("requires approval")
        || lower.contains("api key")
    {
        crate::core::TaskStatus::Paused
    } else {
        crate::core::TaskStatus::Completed
    }
}

#[derive(Clone)]
struct StreamedChatTask {
    task_id: String,
    description: String,
    work_type: String,
    user_message_already_recorded: bool,
}

#[allow(clippy::large_enum_variant)]
#[derive(Clone)]
enum ChatStreamTaskMode {
    CreateIfNeeded,
    Existing(Box<StreamedChatTask>),
}

#[derive(Clone)]
struct ChatStreamRunRequest {
    message: String,
    channel: String,
    conversation_id: Option<String>,
    project_id: Option<String>,
    deep_research: bool,
    attachments_present: bool,
    plan_confirmation_mode: crate::core::RequestPlanConfirmationMode,
    plan_override: Option<crate::core::ExecutionPlan>,
    caller_principal: Option<crate::actions::ActionCallerPrincipal>,
    task_mode: ChatStreamTaskMode,
}

fn spawn_chat_stream_response(state: AppState, request: ChatStreamRunRequest) -> Response {
    let (tx, rx) = tokio::sync::mpsc::channel::<Result<Event, std::convert::Infallible>>(64);
    // Per-request trace so concurrent requests cannot clobber each other.
    let trace_ref = Arc::new(RwLock::new(ExecutionTrace::default()));
    let agent_ref = state.agent.clone();
    let message = request.message.clone();
    let channel = request.channel.clone();
    let conversation_id = request.conversation_id.clone();
    let project_id = request.project_id.clone();
    let deep_research = request.deep_research;
    let attachments_present = request.attachments_present;
    let plan_confirmation_mode = request.plan_confirmation_mode;
    let plan_override = request.plan_override.clone();
    let caller_principal = request.caller_principal.clone();
    let task_mode = request.task_mode.clone();
    let app_state = state.clone();

    tokio::spawn(async move {
        let tracked_task = match task_mode {
            ChatStreamTaskMode::CreateIfNeeded => None,
            ChatStreamTaskMode::Existing(task) => {
                let payload = serde_json::json!({
                    "task_id": task.task_id.clone(),
                    "description": task.description.clone(),
                    "status": "in_progress",
                    "work_type": task.work_type.clone(),
                    "conversation_id": conversation_id.clone(),
                    "project_id": project_id.clone(),
                });
                let event = Event::default()
                    .event("task_started")
                    .data(serde_json::to_string(&payload).unwrap_or_default());
                let _ = tx.send(Ok(event)).await;
                Some(*task)
            }
        };
        let tracked_task_ref = Arc::new(RwLock::new(tracked_task));
        let (cancel_tx, mut cancel_rx) = tokio::sync::watch::channel(false);
        if let Some(task) = tracked_task_ref.read().await.as_ref() {
            bind_chat_task_cancellation_sender(&app_state, &task.task_id, cancel_tx.clone()).await;
        }

        // Stream model tokens + tool progress as dedicated SSE events.
        let (stream_tx, mut stream_rx) =
            tokio::sync::mpsc::channel::<crate::core::StreamEvent>(256);
        let stream_forwarder = {
            let tx = tx.clone();
            let tracked_task_ref = tracked_task_ref.clone();
            let app_state = app_state.clone();
            let cancel_tx = cancel_tx.clone();
            tokio::spawn(async move {
                let mut last_thinking_detail = String::new();
                while let Some(ev) = stream_rx.recv().await {
                    if let crate::core::StreamEvent::ChatTaskStarted {
                        task_id,
                        description,
                        work_type,
                        ..
                    } = &ev
                    {
                        {
                            let mut tracked = tracked_task_ref.write().await;
                            *tracked = Some(StreamedChatTask {
                                task_id: task_id.clone(),
                                description: description.clone(),
                                work_type: work_type.clone(),
                                user_message_already_recorded: false,
                            });
                        }
                        bind_chat_task_cancellation_sender(&app_state, task_id, cancel_tx.clone())
                            .await;
                    }
                    let (maybe_event, next_thinking_detail) =
                        normalize_stream_event_for_sse(ev, &last_thinking_detail);
                    last_thinking_detail = next_thinking_detail;
                    let Some((event_name, payload)) = maybe_event else {
                        continue;
                    };
                    let event = Event::default()
                        .event(event_name)
                        .data(serde_json::to_string(&payload).unwrap_or_default());
                    if tx.send(Ok(event)).await.is_err() {
                        break;
                    }
                }
            })
        };

        // Poll trace for new steps and emit as SSE events.
        let trace_poller = {
            let tx = tx.clone();
            let trace_ref = trace_ref.clone();
            tokio::spawn(async move {
                let mut last_step_count = 0;
                let start = std::time::Instant::now();
                let mut last_progress_at = std::time::Instant::now();
                let mut last_heartbeat_at = std::time::Instant::now();
                const HEARTBEAT_SECS: u64 = 3;
                loop {
                    tokio::time::sleep(std::time::Duration::from_millis(200)).await;
                    if start.elapsed().as_secs() > 1800 {
                        break;
                    }
                    let trace = trace_ref.read().await;
                    let current_count = trace.steps.len();
                    if current_count > last_step_count {
                        for step in &trace.steps[last_step_count..current_count] {
                            let event_data = serde_json::json!({
                                "icon": step.icon,
                                "title": step.title,
                                "detail": step.detail,
                                "step_type": step.step_type,
                                "data": step.data,
                                "time": step.timestamp.to_rfc3339_opts(chrono::SecondsFormat::Secs, true),
                                "duration_ms": step.duration_ms,
                            });
                            let event = Event::default()
                                .event("thinking")
                                .data(serde_json::to_string(&event_data).unwrap_or_default());
                            if tx.send(Ok(event)).await.is_err() {
                                return;
                            }
                        }
                        last_step_count = current_count;
                        last_progress_at = std::time::Instant::now();
                        last_heartbeat_at = last_progress_at;
                    }
                    if trace.completed_at.is_some() {
                        break;
                    }
                    if last_progress_at.elapsed().as_secs() >= HEARTBEAT_SECS
                        && last_heartbeat_at.elapsed().as_secs() >= HEARTBEAT_SECS
                    {
                        let idle_secs = last_progress_at.elapsed().as_secs();
                        let phase_hint = trace
                            .steps
                            .last()
                            .map(|s| {
                                let title = s.title.to_ascii_lowercase();
                                let detail = s.detail.to_ascii_lowercase();
                                let memory_is_active = (title.contains("memory")
                                    || detail.contains("memory"))
                                    && !detail.contains("available on demand");
                                if memory_is_active {
                                    if detail.contains("pending") {
                                        "Vector memory layer is starting up (first run may include embedding warmup)."
                                    } else if detail.contains("active") {
                                        "Retrieving semantic memory/context."
                                    } else if detail.contains("warmup") {
                                        "Memory layer warmup in progress."
                                    } else {
                                        "Memory/context setup in progress."
                                    }
                                } else if title.contains("context") || detail.contains("context") {
                                    "Preparing conversation context."
                                } else if title.contains("repairing deploy payload")
                                    || detail.contains("deploy payload")
                                    || detail.contains("files payload")
                                {
                                    "Regenerating deploy payload (model is building required files map)."
                                } else if title.contains("llm request") || title.contains("llm call") {
                                    "Waiting on model response."
                                } else if title.contains("tool") || detail.contains("tool") {
                                    "Waiting on tool execution."
                                } else {
                                    "Still processing."
                                }
                            })
                            .unwrap_or("Still processing.");
                        let event_data = serde_json::json!({
                            "icon": "[wait]",
                            "title": "Still Working",
                            "detail": format!("{} No new output yet ({}s idle).", phase_hint, idle_secs),
                            "step_type": "heartbeat",
                            "data": serde_json::json!({ "idle_secs": idle_secs })
                        });
                        let event = Event::default()
                            .event("thinking")
                            .data(serde_json::to_string(&event_data).unwrap_or_default());
                        if tx.send(Ok(event)).await.is_err() {
                            return;
                        }
                        last_heartbeat_at = std::time::Instant::now();
                    }
                }
            })
        };

        let initial_status = Event::default().event("thinking").data(
            serde_json::json!({
                "icon": "[recv]",
                "title": "Request received",
                "detail": "Preparing model call and tool plan...",
                "step_type": "thinking",
                "data": null
            })
            .to_string(),
        );
        let _ = tx.send(Ok(initial_status)).await;

        let tracked_task_snapshot = tracked_task_ref.read().await.clone();
        let user_message_already_recorded = tracked_task_snapshot
            .as_ref()
            .map(|task| task.user_message_already_recorded)
            .unwrap_or(false);
        let chat_task_id = tracked_task_snapshot
            .as_ref()
            .map(|task| task.task_id.clone());
        let mut process_handle = {
            let agent_ref = agent_ref.clone();
            let message = message.clone();
            let channel = channel.clone();
            let conversation_id = conversation_id.clone();
            let project_id = project_id.clone();
            let trace_ref = trace_ref.clone();
            let chat_task_id = chat_task_id.clone();
            let caller_principal = caller_principal.clone();
            let plan_override = plan_override.clone();
            tokio::spawn(async move {
                let agent_guard = agent_ref.read().await;
                if user_message_already_recorded {
                    agent_guard
                        .process_message_stream_resume_with_meta_and_hints(
                            &message,
                            &channel,
                            conversation_id.as_deref(),
                            project_id.as_deref(),
                            trace_ref,
                            stream_tx,
                            build_request_execution_hints(
                                deep_research,
                                chat_task_id.clone(),
                                caller_principal.as_ref(),
                                crate::actions::ActionExecutionSurface::Chat,
                                true,
                                attachments_present,
                                plan_confirmation_mode,
                                plan_override.clone(),
                            ),
                        )
                        .await
                } else {
                    agent_guard
                        .process_message_stream_with_meta_and_hints(
                            &message,
                            &channel,
                            conversation_id.as_deref(),
                            project_id.as_deref(),
                            trace_ref,
                            stream_tx,
                            build_request_execution_hints(
                                deep_research,
                                chat_task_id.clone(),
                                caller_principal.as_ref(),
                                crate::actions::ActionExecutionSurface::Chat,
                                true,
                                attachments_present,
                                plan_confirmation_mode,
                                plan_override.clone(),
                            ),
                        )
                        .await
                }
            })
        };

        let mut was_cancelled = false;
        let result = tokio::select! {
            worker = &mut process_handle => {
                match worker {
                    Ok(result) => result,
                    Err(error) if error.is_cancelled() => {
                        was_cancelled = true;
                        Err(anyhow::anyhow!("Chat run cancelled"))
                    }
                    Err(error) => Err(anyhow::anyhow!("Chat worker failed: {}", error)),
                }
            }
            changed = cancel_rx.changed() => {
                if changed.is_ok() && *cancel_rx.borrow() {
                    was_cancelled = true;
                    process_handle.abort();
                    let _ = process_handle.await;
                    Err(anyhow::anyhow!("Chat run cancelled"))
                } else {
                    match process_handle.await {
                        Ok(result) => result,
                        Err(error) if error.is_cancelled() => {
                            was_cancelled = true;
                            Err(anyhow::anyhow!("Chat run cancelled"))
                        }
                        Err(error) => Err(anyhow::anyhow!("Chat worker failed: {}", error)),
                    }
                }
            }
        };

        {
            let mut trace = trace_ref.write().await;
            if trace.completed_at.is_none() {
                trace.completed_at = Some(chrono::Utc::now());
            }
        }

        let _ = trace_poller.await;
        let _ = stream_forwarder.await;

        let tracked_task = tracked_task_ref.read().await.clone();

        if let Some(task) = tracked_task.as_ref() {
            unregister_chat_task_cancellation(&app_state, &task.task_id).await;
        }

        match result {
            Ok(processed) => {
                let resolved_conversation_id = processed
                    .conversation_id
                    .clone()
                    .or(conversation_id.clone());
                let updated_arguments_json = if let Some(task) = tracked_task.as_ref() {
                    let mut tasks = app_state.tasks.write().await;
                    task.task_id
                        .parse::<uuid::Uuid>()
                        .ok()
                        .and_then(|task_id| tasks.get_mut(task_id))
                        .and_then(|entry| {
                            backfill_chat_task_origin_metadata(
                                entry,
                                resolved_conversation_id.as_deref(),
                                project_id.as_deref(),
                            )
                        })
                } else {
                    None
                };
                if let (Some(task), Some(arguments_json)) =
                    (tracked_task.as_ref(), updated_arguments_json)
                {
                    let agent_guard = agent_ref.read().await;
                    if task.task_id.parse::<uuid::Uuid>().is_err() {
                        tracing::warn!(
                            "Failed to parse streamed chat task id '{}' during finalize",
                            task.task_id
                        );
                    }
                    if let Err(error) = agent_guard
                        .storage
                        .update_task(&task.task_id, None, Some(arguments_json), None, None)
                        .await
                    {
                        tracing::warn!(
                            "Failed to backfill streamed chat task '{}' conversation metadata: {}",
                            task.task_id,
                            error
                        );
                    }
                }
                if let Some(task) = tracked_task.as_ref() {
                    let terminal_status = chat_task_terminal_status(&processed.response);
                    let result_preview = truncate_stream_task_text(
                        if processed.response.trim().is_empty() {
                            "Task completed."
                        } else {
                            &processed.response
                        },
                        400,
                    );
                    {
                        let agent_guard = agent_ref.read().await;
                        match task.task_id.parse::<uuid::Uuid>() {
                            Ok(task_uuid) => {
                                if let Err(error) = agent_guard
                                    .finalize_task(
                                        task_uuid,
                                        terminal_status.clone(),
                                        Some(result_preview.clone()),
                                    )
                                    .await
                                {
                                    tracing::warn!(
                                        "Failed to finalize streamed chat task '{}': {}",
                                        task.task_id,
                                        error
                                    );
                                }
                            }
                            Err(_) => {
                                tracing::warn!(
                                    "Failed to parse streamed chat task id '{}' during success finalize",
                                    task.task_id
                                );
                            }
                        }
                    }
                    let status_event = Event::default().event("task_status").data(
                        serde_json::json!({
                            "task_id": task.task_id.clone(),
                            "description": task.description.clone(),
                            "status": chat_task_status_key(&terminal_status),
                            "work_type": task.work_type.clone(),
                            "result_preview": result_preview,
                            "conversation_id": resolved_conversation_id.clone(),
                            "project_id": project_id.clone(),
                        })
                        .to_string(),
                    );
                    let _ = tx.send(Ok(status_event)).await;
                    if deep_research
                        && matches!(terminal_status, crate::core::TaskStatus::Completed)
                    {
                        let title = "Deep research completed";
                        let body = format!(
                            "{} is ready. Open Chat to review the completed report.",
                            processed
                                .conversation_title
                                .as_deref()
                                .filter(|value| !value.trim().is_empty())
                                .unwrap_or(task.description.as_str())
                        );
                        let agent_guard = agent_ref.read().await;
                        agent_guard
                            .emit_notification(title, &body, "info", "deep_research")
                            .await;
                    }
                }

                let mut content = serde_json::json!({
                    "content": processed.response,
                    "conversation_id": resolved_conversation_id,
                    "run_id": processed.run_id,
                    "run_status": processed.run_status,
                    "trace_id": processed.trace_id,
                    "degradation": processed.degradation,
                    "attempted_models": processed.attempted_models,
                    "user_outcome": processed.user_outcome,
                });
                if let Some(title) = processed.conversation_title {
                    content["conversation_title"] = serde_json::json!(title);
                }
                let event = Event::default()
                    .event("content")
                    .data(serde_json::to_string(&content).unwrap_or_default());
                let _ = tx.send(Ok(event)).await;
                let run_status = Event::default().event("run_status").data(
                    serde_json::json!({
                        "run_id": content["run_id"],
                        "run_status": content["run_status"],
                        "trace_id": content["trace_id"],
                        "degradation": content["degradation"],
                        "attempted_models": content["attempted_models"],
                        "user_outcome": content["user_outcome"],
                    })
                    .to_string(),
                );
                let _ = tx.send(Ok(run_status)).await;
            }
            Err(error) if was_cancelled => {
                if let Some(task) = tracked_task.as_ref() {
                    let result_preview = "Cancelled by user.";
                    {
                        let agent_guard = agent_ref.read().await;
                        agent_guard
                            .swarm_activity
                            .interrupt_run(
                                &task.task_id,
                                "Cancelled by user before the delegated run completed.",
                            )
                            .await;
                        if let Err(storage_error) = agent_guard
                            .storage
                            .mark_swarm_run_interrupted(
                                &task.task_id,
                                "Cancelled by user before the delegated run completed.",
                            )
                            .await
                        {
                            tracing::warn!(
                                "Failed to persist interrupted swarm run '{}' after cancellation: {}",
                                task.task_id,
                                storage_error
                            );
                        }
                        match task.task_id.parse::<uuid::Uuid>() {
                            Ok(task_uuid) => {
                                if let Err(finalize_error) = agent_guard
                                    .finalize_task(
                                        task_uuid,
                                        crate::core::TaskStatus::Cancelled,
                                        Some(result_preview.to_string()),
                                    )
                                    .await
                                {
                                    tracing::warn!(
                                        "Failed to finalize cancelled streamed chat task '{}': {}",
                                        task.task_id,
                                        finalize_error
                                    );
                                }
                            }
                            Err(_) => {
                                tracing::warn!(
                                    "Failed to parse streamed chat task id '{}' during cancellation finalize",
                                    task.task_id
                                );
                            }
                        }
                    }
                    let status_event = Event::default().event("task_status").data(
                        serde_json::json!({
                            "task_id": task.task_id.clone(),
                            "description": task.description.clone(),
                            "status": "cancelled",
                            "work_type": task.work_type.clone(),
                            "result_preview": result_preview,
                            "conversation_id": conversation_id.clone(),
                            "project_id": project_id.clone(),
                        })
                        .to_string(),
                    );
                    let _ = tx.send(Ok(status_event)).await;
                }
                let run_status = Event::default().event("run_status").data(
                    serde_json::json!({
                        "run_id": serde_json::Value::Null,
                        "run_status": "cancelled",
                        "trace_id": serde_json::Value::Null,
                        "degradation": [{
                            "kind": "cancellation",
                            "summary": "run cancelled",
                            "detail": error.to_string(),
                        }],
                        "attempted_models": [],
                        "user_outcome": serde_json::Value::Null,
                    })
                    .to_string(),
                );
                let _ = tx.send(Ok(run_status)).await;
            }
            Err(error) => {
                if let Some(task) = tracked_task.as_ref() {
                    let error_text = error.to_string();
                    {
                        let agent_guard = agent_ref.read().await;
                        match task.task_id.parse::<uuid::Uuid>() {
                            Ok(task_uuid) => {
                                if let Err(finalize_error) = agent_guard
                                    .finalize_task(
                                        task_uuid,
                                        crate::core::TaskStatus::Failed {
                                            error: error_text.clone(),
                                        },
                                        Some(truncate_stream_task_text(&error_text, 400)),
                                    )
                                    .await
                                {
                                    tracing::warn!(
                                        "Failed to finalize failed streamed chat task '{}': {}",
                                        task.task_id,
                                        finalize_error
                                    );
                                }
                            }
                            Err(_) => {
                                tracing::warn!(
                                    "Failed to parse streamed chat task id '{}' during failure finalize",
                                    task.task_id
                                );
                            }
                        }
                    }
                    let status_event = Event::default().event("task_status").data(
                        serde_json::json!({
                            "task_id": task.task_id.clone(),
                            "description": task.description.clone(),
                            "status": "failed",
                            "work_type": task.work_type.clone(),
                            "result_preview": truncate_stream_task_text(&error_text, 400),
                            "conversation_id": conversation_id.clone(),
                            "project_id": project_id.clone(),
                        })
                        .to_string(),
                    );
                    let _ = tx.send(Ok(status_event)).await;
                }

                let error_payload = serde_json::json!({ "error": error.to_string() });
                let event = Event::default()
                    .event("error")
                    .data(serde_json::to_string(&error_payload).unwrap_or_default());
                let _ = tx.send(Ok(event)).await;
                let response =
                    "I hit a framework-level problem before supervised execution could finish. Please retry."
                        .to_string();
                let degradation = vec![crate::core::DegradationNote {
                    kind: "platform".to_string(),
                    summary: "framework error".to_string(),
                    detail: Some(error.to_string()),
                }];
                let user_outcome = crate::core::ExecutionSupervisor::default()
                    .build_service_outage_outcome(&response, "framework_error", &degradation, &[]);
                let run_status = Event::default().event("run_status").data(
                    serde_json::json!({
                        "run_id": serde_json::Value::Null,
                        "run_status": "platform_failed",
                        "trace_id": serde_json::Value::Null,
                        "degradation": degradation,
                        "attempted_models": user_outcome.attempted_models,
                        "user_outcome": user_outcome,
                    })
                    .to_string(),
                );
                let _ = tx.send(Ok(run_status)).await;
            }
        }

        let done = Event::default().event("done").data("{}");
        let _ = tx.send(Ok(done)).await;
    });

    let stream = tokio_stream::wrappers::ReceiverStream::new(rx);
    Sse::new(stream)
        .keep_alive(KeepAlive::default())
        .into_response()
}

#[derive(Clone)]
struct ResumableChatTaskRequest {
    message: String,
    channel: String,
    conversation_id: String,
    project_id: Option<String>,
    deep_research: bool,
    attachments_present: bool,
    work_type: String,
    stored_plan_override: Option<serde_json::Value>,
    paused_for_plan_confirmation: bool,
}

#[derive(Debug, Deserialize, Default)]
struct ResumeChatTaskStreamRequest {
    #[serde(default)]
    plan_override: Option<serde_json::Value>,
}

fn backfill_chat_task_origin_metadata(
    task: &mut crate::core::Task,
    conversation_id: Option<&str>,
    project_id: Option<&str>,
) -> Option<String> {
    let mut arguments = task.arguments.as_object().cloned().unwrap_or_default();
    let mut changed = false;

    if let Some(cid) = conversation_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        let current = arguments
            .get("conversation_id")
            .and_then(|value| value.as_str())
            .unwrap_or("")
            .trim();
        if current != cid {
            arguments.insert(
                "conversation_id".to_string(),
                serde_json::json!(cid.to_string()),
            );
            changed = true;
        }
    }

    if let Some(pid) = project_id.map(str::trim).filter(|value| !value.is_empty()) {
        let current = arguments
            .get("project_id")
            .and_then(|value| value.as_str())
            .unwrap_or("")
            .trim();
        if current != pid {
            arguments.insert("project_id".to_string(), serde_json::json!(pid.to_string()));
            changed = true;
        }
    }

    if !changed {
        return None;
    }

    task.arguments = serde_json::Value::Object(arguments);
    serde_json::to_string(&task.arguments).ok()
}

fn extract_resumable_web_chat_task(
    task: &crate::core::Task,
) -> std::result::Result<ResumableChatTaskRequest, String> {
    if task.action != "chat_request" {
        return Err("Only chat-request tasks can be resumed in chat.".to_string());
    }
    let arguments = task
        .arguments
        .as_object()
        .ok_or_else(|| "This chat task is missing its stored arguments.".to_string())?;

    let pause_kind = arguments
        .get("_pause_kind")
        .and_then(|value| value.as_str())
        .unwrap_or("")
        .trim()
        .to_string();
    let paused_for_plan_confirmation = pause_kind == "plan_confirmation";
    if !matches!(
        task.status,
        crate::core::TaskStatus::Cancelled
            | crate::core::TaskStatus::Failed { .. }
            | crate::core::TaskStatus::Paused
    ) {
        return Err(
            "Only cancelled, failed, or plan-confirmation-paused chat tasks can be resumed in chat."
                .to_string(),
        );
    }
    if matches!(task.status, crate::core::TaskStatus::Paused) && !paused_for_plan_confirmation {
        return Err(
            "Only cancelled, failed, or plan-confirmation-paused chat tasks can be resumed in chat."
                .to_string(),
        );
    }

    let origin = arguments
        .get("_origin")
        .and_then(|value| value.as_str())
        .unwrap_or("")
        .trim();
    if origin != "chat" {
        return Err("Only chat-origin tasks can be resumed in chat.".to_string());
    }

    let channel = arguments
        .get("channel")
        .and_then(|value| value.as_str())
        .unwrap_or("")
        .trim()
        .to_string();
    if channel != "web" {
        return Err("Only web chat tasks can be resumed in chat.".to_string());
    }

    let message = arguments
        .get("message")
        .and_then(|value| value.as_str())
        .unwrap_or("")
        .trim()
        .to_string();
    if message.is_empty() {
        return Err(
            "This chat task no longer has its stored message, so it cannot be resumed.".to_string(),
        );
    }

    let conversation_id = arguments
        .get("conversation_id")
        .and_then(|value| value.as_str())
        .unwrap_or("")
        .trim()
        .to_string();
    if conversation_id.is_empty() {
        return Err(
            "This chat task no longer has a conversation id, so it cannot be resumed.".to_string(),
        );
    }

    let project_id = arguments
        .get("project_id")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let deep_research = arguments
        .get("deep_research")
        .and_then(|value| value.as_bool())
        .unwrap_or(false);
    let attachments_present = arguments
        .get("attachments_present")
        .and_then(|value| value.as_bool())
        .unwrap_or(false);
    let work_type = arguments
        .get("_work_type")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| {
            if deep_research {
                "research".to_string()
            } else if attachments_present {
                "workspace".to_string()
            } else {
                "task".to_string()
            }
        });
    let stored_plan_override = arguments
        .get("_plan_preview")
        .and_then(|value| value.as_object())
        .and_then(|value| value.get("current_plan"))
        .cloned();

    Ok(ResumableChatTaskRequest {
        message,
        channel,
        conversation_id,
        project_id,
        deep_research,
        attachments_present,
        work_type,
        stored_plan_override,
        paused_for_plan_confirmation,
    })
}

async fn parse_execution_plan_override(
    state: &AppState,
    raw: Option<&serde_json::Value>,
) -> std::result::Result<Option<crate::core::ExecutionPlan>, String> {
    let Some(raw_plan) = raw else {
        return Ok(None);
    };
    let agent = state.agent.read().await;
    let actions = agent
        .runtime
        .list_actions()
        .await
        .map_err(|error| format!("Failed to load actions for plan validation: {}", error))?;
    let parsed = crate::core::planner::parse_plan_from_value(raw_plan, &actions, None, 1, false)
        .map(|plan| crate::core::planner::prepare_plan_for_execution(&plan))
        .ok_or_else(|| "Invalid plan override payload.".to_string())?;
    Ok(Some(parsed))
}

async fn chat_stream(
    State(state): State<AppState>,
    maybe_caller: Option<Extension<crate::actions::ActionCallerPrincipal>>,
    ConnectInfo(_addr): ConnectInfo<SocketAddr>,
    Json(request): Json<ChatRequest>,
) -> Response {
    if let Some(response) = validate_chat_message_size(&request.message) {
        return response;
    }

    tracing::info!(
        "HTTP /chat/stream request: channel={}, msg={}chars, conv_id={:?}",
        request.channel,
        request.message.len(),
        request.conversation_id.as_deref().unwrap_or("-"),
    );

    if let Some(conversation_id) = request
        .conversation_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        let agent = state.agent.read().await;
        match agent.storage.get_conversation(conversation_id).await {
            Ok(Some(_)) => {}
            Ok(None) => return conversation_not_found_response(),
            Err(error) => {
                return (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    Json(ErrorResponse {
                        error: format!("Failed to load conversation: {}", error),
                    }),
                )
                    .into_response();
            }
        }
    }

    // Two-tier secrets UX: allow "/setsecret KEY=VALUE" without engaging the LLM.
    if let Some((key, value)) = parse_set_secret_command(&request.message) {
        let cid = request.conversation_id.clone();
        let (config_dir, data_dir) = {
            let agent = state.agent.read().await;
            (agent.config_dir.clone(), agent.data_dir.clone())
        };
        let stored =
            crate::core::secrets::store_user_secret(&config_dir, Some(&data_dir), &key, &value);
        let followup = if stored.is_ok() {
            if let Some(ref cid_str) = cid {
                let agent = state.agent.read().await;
                agent.on_secret_saved_followup(cid_str).await
            } else {
                None
            }
        } else {
            None
        };
        let mut content = format!(
            "Saved secret '{}' (stored encrypted). This value was not sent to the LLM.",
            key
        );
        if let Some(f) = followup {
            content.push_str("\n\n");
            content.push_str(&f);
        }
        let payload = match stored {
            Ok(_) => serde_json::json!({
                "content": content,
                "conversation_id": cid,
            }),
            Err(e) => serde_json::json!({ "error": format!("Failed to store secret: {}", e) }),
        };

        let (tx, rx) = tokio::sync::mpsc::channel::<Result<Event, std::convert::Infallible>>(4);
        tokio::spawn(async move {
            let event_name = if payload.get("error").is_some() {
                "error"
            } else {
                "content"
            };
            let _ = tx
                .send(Ok(Event::default()
                    .event(event_name)
                    .data(payload.to_string())))
                .await;
            let _ = tx.send(Ok(Event::default().event("done").data("{}"))).await;
        });

        return Sse::new(tokio_stream::wrappers::ReceiverStream::new(rx))
            .keep_alive(KeepAlive::default())
            .into_response();
    }

    // Human-in-the-loop shortcut: reuse currently configured model key without sending to the LLM.
    if let Some(key) = crate::core::secrets::parse_use_current_llm_key_command(&request.message) {
        let cid = request.conversation_id.clone();
        let (config_dir, data_dir, llm_env) = {
            let agent = state.agent.read().await;
            (
                agent.config_dir.clone(),
                agent.data_dir.clone(),
                agent.app_model_env_vars(),
            )
        };
        let payload = if let Some(value) =
            llm_env.get(&key).cloned().filter(|v| !v.trim().is_empty())
        {
            match crate::core::secrets::store_user_secret(
                &config_dir,
                Some(&data_dir),
                &key,
                &value,
            ) {
                Ok(_) => {
                    let followup = if let Some(ref cid_str) = cid {
                        let agent = state.agent.read().await;
                        agent.on_secret_saved_followup(cid_str).await
                    } else {
                        None
                    };
                    let mut content = format!(
                        "Linked '{}' to the currently configured model credential (stored encrypted). This was not sent to the LLM.",
                        key
                    );
                    if let Some(f) = followup {
                        content.push_str("\n\n");
                        content.push_str(&f);
                    }
                    serde_json::json!({
                        "content": content,
                        "conversation_id": cid,
                    })
                }
                Err(e) => serde_json::json!({ "error": format!("Failed to store secret: {}", e) }),
            }
        } else {
            let mut available: Vec<String> = llm_env
                .iter()
                .filter_map(|(k, v)| {
                    if v.trim().is_empty() {
                        None
                    } else if k.ends_with("_API_KEY")
                        || k.ends_with("_BASE_URL")
                        || k == "LLM_MODEL"
                        || k == "LLM_PROVIDER"
                    {
                        Some(k.clone())
                    } else {
                        None
                    }
                })
                .collect();
            available.sort();
            let available_text = if available.is_empty() {
                "none".to_string()
            } else {
                available.join(", ")
            };
            serde_json::json!({
                "error": format!(
                    "Can't map '{}' from current model settings. Available model-backed keys: {}",
                    key, available_text
                )
            })
        };

        let (tx, rx) = tokio::sync::mpsc::channel::<Result<Event, std::convert::Infallible>>(4);
        tokio::spawn(async move {
            let event_name = if payload.get("error").is_some() {
                "error"
            } else {
                "content"
            };
            let _ = tx
                .send(Ok(Event::default()
                    .event(event_name)
                    .data(payload.to_string())))
                .await;
            let _ = tx.send(Ok(Event::default().event("done").data("{}"))).await;
        });

        return Sse::new(tokio_stream::wrappers::ReceiverStream::new(rx))
            .keep_alive(KeepAlive::default())
            .into_response();
    }

    // Fast command path: push-notification controls without LLM roundtrip.
    if let Some(cmd) = parse_notification_control_command(&request.message) {
        let cid = request.conversation_id.clone();
        let payload = match handle_notification_control_command(&state, cmd).await {
            Ok(content) => serde_json::json!({
                "content": content,
                "conversation_id": cid,
            }),
            Err(error) => serde_json::json!({ "error": error }),
        };

        let (tx, rx) = tokio::sync::mpsc::channel::<Result<Event, std::convert::Infallible>>(4);
        tokio::spawn(async move {
            let event_name = if payload.get("error").is_some() {
                "error"
            } else {
                "content"
            };
            let _ = tx
                .send(Ok(Event::default()
                    .event(event_name)
                    .data(payload.to_string())))
                .await;
            let _ = tx.send(Ok(Event::default().event("done").data("{}"))).await;
        });

        return Sse::new(tokio_stream::wrappers::ReceiverStream::new(rx))
            .keep_alive(KeepAlive::default())
            .into_response();
    }

    // Fast command path: tunnel control without LLM roundtrip.
    if let Some(cmd) = tunnel::parse_tunnel_command(&request.message) {
        let cid = request.conversation_id.clone();
        let payload = match tunnel::handle_tunnel_control_command(&state, cmd).await {
            Ok(content) => serde_json::json!({
                "content": content,
                "conversation_id": cid,
            }),
            Err(error) => serde_json::json!({ "error": error }),
        };

        let (tx, rx) = tokio::sync::mpsc::channel::<Result<Event, std::convert::Infallible>>(4);
        tokio::spawn(async move {
            let event_name = if payload.get("error").is_some() {
                "error"
            } else {
                "content"
            };
            let _ = tx
                .send(Ok(Event::default()
                    .event(event_name)
                    .data(payload.to_string())))
                .await;
            let _ = tx.send(Ok(Event::default().event("done").data("{}"))).await;
        });

        return Sse::new(tokio_stream::wrappers::ReceiverStream::new(rx))
            .keep_alive(KeepAlive::default())
            .into_response();
    }

    // Fast command path: explicit autonomy helpers without LLM roundtrip.
    if let Some(cmd) = parse_autonomy_quick_command(&request.message) {
        let cid = request.conversation_id.clone();
        let payload = match handle_autonomy_quick_command(&state, cmd).await {
            Ok(content) => serde_json::json!({
                "content": content,
                "conversation_id": cid,
            }),
            Err(error) => serde_json::json!({ "error": error }),
        };

        let (tx, rx) = tokio::sync::mpsc::channel::<Result<Event, std::convert::Infallible>>(4);
        tokio::spawn(async move {
            let event_name = if payload.get("error").is_some() {
                "error"
            } else {
                "content"
            };
            let _ = tx
                .send(Ok(Event::default()
                    .event(event_name)
                    .data(payload.to_string())))
                .await;
            let _ = tx.send(Ok(Event::default().event("done").data("{}"))).await;
        });

        return Sse::new(tokio_stream::wrappers::ReceiverStream::new(rx))
            .keep_alive(KeepAlive::default())
            .into_response();
    }

    spawn_chat_stream_response(
        state,
        ChatStreamRunRequest {
            message: request.message,
            channel: request.channel,
            conversation_id: request.conversation_id,
            project_id: request.project_id,
            deep_research: request.deep_research,
            attachments_present: request.attachments_present,
            plan_confirmation_mode: normalized_chat_plan_confirmation_mode(
                request.plan_confirmation_mode.as_deref(),
            ),
            plan_override: None,
            caller_principal: maybe_caller.as_ref().map(|Extension(value)| value.clone()),
            task_mode: ChatStreamTaskMode::CreateIfNeeded,
        },
    )
}

/// Clear conversation history for a channel
async fn clear_chat(
    State(state): State<AppState>,
    Json(request): Json<serde_json::Value>,
) -> Response {
    let channel = request
        .get("channel")
        .and_then(|v| v.as_str())
        .unwrap_or("web");
    let project_id = request.get("project_id").and_then(|v| v.as_str());
    let agent = state.agent.read().await;
    if let Some(pid) = project_id {
        agent
            .clear_conversation_for_project(channel, Some(pid))
            .await;
    } else {
        agent.clear_conversation_history(channel).await;
    }
    (
        StatusCode::OK,
        Json(serde_json::json!({ "status": "cleared" })),
    )
        .into_response()
}

async fn list_tasks(
    State(state): State<AppState>,
    axum::extract::Query(params): axum::extract::Query<std::collections::HashMap<String, String>>,
) -> Json<serde_json::Value> {
    let limit = params
        .get("limit")
        .and_then(|s| s.parse().ok())
        .unwrap_or(20usize);
    let offset = params
        .get("offset")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0usize);
    let tasks = state.tasks.read().await;
    let all = tasks.all();
    let total = all.len();

    let task_infos: Vec<TaskInfo> = all
        .iter()
        .skip(offset)
        .take(limit)
        .map(|t| TaskInfo {
            id: t.id.to_string(),
            description: if t.description == crate::storage::ENCRYPTED_STORAGE_UNAVAILABLE {
                "Older task details unavailable".to_string()
            } else {
                t.description.clone()
            },
            action: t.action.clone(),
            arguments: t.arguments.clone(),
            status: format!("{:?}", t.status),
            cron: t.cron.clone(),
            result: t.result.clone(),
            created_at: t.created_at.format("%Y-%m-%d %H:%M:%S").to_string(),
        })
        .collect();

    Json(
        serde_json::json!({ "tasks": task_infos, "total": total, "limit": limit, "offset": offset }),
    )
}

fn automation_task_status_label(status: &TaskStatus) -> String {
    match status {
        TaskStatus::Pending => "pending".to_string(),
        TaskStatus::AwaitingApproval => "awaiting_approval".to_string(),
        TaskStatus::ExpiredNeedsReapproval => "expired_needs_reapproval".to_string(),
        TaskStatus::Paused => "paused".to_string(),
        TaskStatus::InProgress => "in_progress".to_string(),
        TaskStatus::Completed => "completed".to_string(),
        TaskStatus::Failed { .. } => "failed".to_string(),
        TaskStatus::Cancelled => "cancelled".to_string(),
    }
}

fn automation_task_next_run_at(task: &Task, now: chrono::DateTime<chrono::Utc>) -> Option<String> {
    if let Some(scheduled_for) = task.scheduled_for {
        if task.cron.is_some() || scheduled_for >= now - chrono::Duration::seconds(5) {
            return Some(scheduled_for.to_rfc3339());
        }
    }
    let cron = task.cron.as_deref()?.trim();
    if cron.is_empty() {
        return None;
    }
    cron.parse::<cron::Schedule>()
        .ok()?
        .upcoming(chrono::Utc)
        .next()
        .map(|dt| dt.to_rfc3339())
}

fn automation_watcher_status_label(status: &crate::core::watcher::WatcherStatus) -> String {
    match status {
        crate::core::watcher::WatcherStatus::Active => "active".to_string(),
        crate::core::watcher::WatcherStatus::Paused => "paused".to_string(),
        crate::core::watcher::WatcherStatus::Triggered => "triggered".to_string(),
        crate::core::watcher::WatcherStatus::TimedOut => "timed_out".to_string(),
        crate::core::watcher::WatcherStatus::Cancelled => "cancelled".to_string(),
        crate::core::watcher::WatcherStatus::Failed { .. } => "failed".to_string(),
    }
}

fn automation_run_status_label(status: &crate::core::AutomationRunStatus) -> String {
    match status {
        crate::core::AutomationRunStatus::Running => "running".to_string(),
        crate::core::AutomationRunStatus::Succeeded => "succeeded".to_string(),
        crate::core::AutomationRunStatus::Failed => "failed".to_string(),
        crate::core::AutomationRunStatus::Retrying => "retrying".to_string(),
        crate::core::AutomationRunStatus::TimedOut => "timed_out".to_string(),
        crate::core::AutomationRunStatus::Triggered => "triggered".to_string(),
    }
}

fn automation_watcher_condition_label(condition: &crate::core::watcher::WatchCondition) -> String {
    condition.summary()
}

fn automation_watcher_next_run_at(watcher: &crate::core::watcher::Watcher) -> Option<String> {
    if !matches!(
        watcher.status,
        crate::core::watcher::WatcherStatus::Active | crate::core::watcher::WatcherStatus::Paused
    ) {
        return None;
    }
    let base = watcher.last_poll_at.unwrap_or(watcher.created_at);
    Some((base + chrono::Duration::seconds(watcher.interval_secs as i64)).to_rfc3339())
}

#[derive(Debug, Default)]
struct BackgroundSessionCounts {
    tasks_total: usize,
    tasks_queued: usize,
    tasks_running: usize,
    tasks_waiting: usize,
    tasks_paused: usize,
    tasks_done: usize,
    tasks_failed: usize,
    tasks_cancelled: usize,
    watchers_total: usize,
    watchers_active: usize,
    watchers_paused: usize,
    watchers_triggered: usize,
    watchers_stopped: usize,
}

fn parse_background_session_status(
    value: Option<&str>,
) -> Result<Option<crate::core::BackgroundSessionStatus>, String> {
    let Some(raw) = value else {
        return Ok(None);
    };
    let normalized = raw.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        return Ok(None);
    }
    let status = match normalized.as_str() {
        "draft" => crate::core::BackgroundSessionStatus::Draft,
        "active" | "working" => crate::core::BackgroundSessionStatus::Active,
        "waiting" => crate::core::BackgroundSessionStatus::Waiting,
        "needs_input" | "needs-input" | "needsinput" => {
            crate::core::BackgroundSessionStatus::NeedsInput
        }
        "paused" => crate::core::BackgroundSessionStatus::Paused,
        "completed" | "done" => crate::core::BackgroundSessionStatus::Completed,
        "failed" | "error" => crate::core::BackgroundSessionStatus::Failed,
        "cancelled" | "canceled" | "stopped" => crate::core::BackgroundSessionStatus::Cancelled,
        _ => {
            return Err(format!(
                "Unsupported background session status: {}",
                raw.trim()
            ))
        }
    };
    Ok(Some(status))
}

fn background_session_status_label(status: &crate::core::BackgroundSessionStatus) -> String {
    status.label().to_string()
}

fn task_background_session_id(task: &Task) -> Option<String> {
    crate::core::background_session_id_from_automation(&task.arguments)
}

fn watcher_background_session_id(watcher: &crate::core::watcher::Watcher) -> Option<String> {
    crate::core::background_session_id_from_automation(&watcher.poll_arguments)
}

fn collect_background_session_counts(
    session_id: &str,
    session: &crate::core::BackgroundSession,
    tasks: &[Task],
    watchers: &[crate::core::watcher::Watcher],
) -> BackgroundSessionCounts {
    let mut counts = BackgroundSessionCounts::default();

    for task in tasks {
        let task_id = task.id.to_string();
        let is_linked = session.linked_task_ids.iter().any(|id| id == &task_id)
            || task_background_session_id(task).as_deref() == Some(session_id);
        if !is_linked {
            continue;
        }
        counts.tasks_total += 1;
        match &task.status {
            TaskStatus::Pending => counts.tasks_queued += 1,
            TaskStatus::AwaitingApproval | TaskStatus::ExpiredNeedsReapproval => {
                counts.tasks_waiting += 1
            }
            TaskStatus::Paused => counts.tasks_paused += 1,
            TaskStatus::InProgress => counts.tasks_running += 1,
            TaskStatus::Completed => counts.tasks_done += 1,
            TaskStatus::Failed { .. } => counts.tasks_failed += 1,
            TaskStatus::Cancelled => counts.tasks_cancelled += 1,
        }
    }

    for watcher in watchers {
        let watcher_id = watcher.id.to_string();
        let is_linked = session
            .linked_watcher_ids
            .iter()
            .any(|id| id == &watcher_id)
            || watcher_background_session_id(watcher).as_deref() == Some(session_id);
        if !is_linked {
            continue;
        }
        counts.watchers_total += 1;
        match &watcher.status {
            crate::core::watcher::WatcherStatus::Active => counts.watchers_active += 1,
            crate::core::watcher::WatcherStatus::Paused => counts.watchers_paused += 1,
            crate::core::watcher::WatcherStatus::Triggered => counts.watchers_triggered += 1,
            crate::core::watcher::WatcherStatus::TimedOut
            | crate::core::watcher::WatcherStatus::Cancelled
            | crate::core::watcher::WatcherStatus::Failed { .. } => counts.watchers_stopped += 1,
        }
    }

    counts
}

fn background_session_live_summary(
    session: &crate::core::BackgroundSession,
    counts: &BackgroundSessionCounts,
) -> String {
    if let Some(waiting_on) = session.waiting_on.as_deref() {
        if !waiting_on.trim().is_empty() {
            return waiting_on.trim().to_string();
        }
    }
    if let Some(current_focus) = session.current_focus.as_deref() {
        if !current_focus.trim().is_empty() {
            return current_focus.trim().to_string();
        }
    }
    match session.status {
        crate::core::BackgroundSessionStatus::Draft => {
            "Ready to attach work and begin in the background.".to_string()
        }
        crate::core::BackgroundSessionStatus::Active => {
            if counts.tasks_running > 0 {
                "Working through linked tasks right now.".to_string()
            } else if counts.watchers_active > 0 {
                "Watching for changes in the background.".to_string()
            } else if counts.tasks_queued > 0 {
                "Queued work is ready to run.".to_string()
            } else {
                "Standing by for the next step.".to_string()
            }
        }
        crate::core::BackgroundSessionStatus::Waiting => {
            "Waiting for an external signal or follow-up.".to_string()
        }
        crate::core::BackgroundSessionStatus::NeedsInput => {
            "Needs an operator decision before it can continue.".to_string()
        }
        crate::core::BackgroundSessionStatus::Paused => {
            "Paused. Linked work will stay idle until resumed.".to_string()
        }
        crate::core::BackgroundSessionStatus::Completed => {
            "Completed. No further work is scheduled.".to_string()
        }
        crate::core::BackgroundSessionStatus::Failed => {
            "Blocked by a failure. Inspect the latest error before resuming.".to_string()
        }
        crate::core::BackgroundSessionStatus::Cancelled => "Stopped by the operator.".to_string(),
    }
}

