async fn create_project_endpoint(
    State(state): State<AppState>,
    Json(request): Json<serde_json::Value>,
) -> Response {
    let name = match request.get("name").and_then(|v| v.as_str()) {
        Some(n) if !n.trim().is_empty() => n.trim().to_string(),
        _ => {
            return (
                StatusCode::BAD_REQUEST,
                Json(ErrorResponse {
                    error: "Name required".to_string(),
                }),
            )
                .into_response()
        }
    };
    let now = chrono::Utc::now().to_rfc3339();
    let id = uuid::Uuid::new_v4().to_string();
    let proj = crate::storage::entities::project::Model {
        id: id.clone(),
        name,
        description: request
            .get("description")
            .and_then(|v| v.as_str())
            .unwrap_or("")
            .to_string(),
        system_prompt: request
            .get("system_prompt")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string()),
        personality: request
            .get("personality")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string()),
        tools_filter: request
            .get("tools_filter")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string()),
        active: true,
        created_at: now.clone(),
        updated_at: now,
    };
    let agent = state.agent.read().await;
    match agent.storage.create_project(&proj).await {
        Ok(_) => (
            StatusCode::OK,
            Json(serde_json::json!({"id": id, "status": "ok"})),
        )
            .into_response(),
        Err(e) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(ErrorResponse {
                error: e.to_string(),
            }),
        )
            .into_response(),
    }
}

