async fn update_project_endpoint(
    State(state): State<AppState>,
    Path(id): Path<String>,
    Json(request): Json<serde_json::Value>,
) -> Response {
    let agent = state.agent.read().await;
    let existing = match agent.storage.get_project(&id).await {
        Ok(Some(p)) => p,
        Ok(None) => {
            return (
                StatusCode::NOT_FOUND,
                Json(ErrorResponse {
                    error: "Not found".to_string(),
                }),
            )
                .into_response()
        }
        Err(e) => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(ErrorResponse {
                    error: e.to_string(),
                }),
            )
                .into_response()
        }
    };
    let updated = crate::storage::entities::project::Model {
        id: id.clone(),
        name: request
            .get("name")
            .and_then(|v| v.as_str())
            .unwrap_or(&existing.name)
            .to_string(),
        description: request
            .get("description")
            .and_then(|v| v.as_str())
            .unwrap_or(&existing.description)
            .to_string(),
        system_prompt: request
            .get("system_prompt")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string())
            .or(existing.system_prompt),
        personality: request
            .get("personality")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string())
            .or(existing.personality),
        tools_filter: request
            .get("tools_filter")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string())
            .or(existing.tools_filter),
        active: request
            .get("active")
            .and_then(|v| v.as_bool())
            .unwrap_or(existing.active),
        created_at: existing.created_at,
        updated_at: chrono::Utc::now().to_rfc3339(),
    };
    match agent.storage.update_project(&updated).await {
        Ok(_) => (StatusCode::OK, Json(serde_json::json!({"status": "ok"}))).into_response(),
        Err(e) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(ErrorResponse {
                error: e.to_string(),
            }),
        )
            .into_response(),
    }
}

